window.__ARXIV_DATA__ = {"papers":[{"id":"2607.13031v1","title":"The Seriality Gap in Video Diffusion Models","abstract":"When one ball strikes another, then another, video models should predict the consequences of each bounce. In controlled experiments on multi-ball hard-sphere dynamics, we find that the performance of standard bidirectional video diffusion degrades as the causal chain lengthens, even when provided more denoising steps. In a length-matched single-ball control, where ball-ball interactions are absent, the degradation largely disappears, isolating dependent-event structure rather than video length as the cause. Across intervention studies, methods that increase effective serial computation improve performance disproportionately, including autoregressive/blockwise generation and architectural depth. We identify this pattern as the seriality gap: a mismatch between tasks requiring growing serial computation and video diffusion models whose denoising loop does not provide scalable serial compute. We then prove that, for deterministic video prediction, denoising steps do not add serial computation beyond the backbone, indicating a structural obstacle for video diffusion on serial reasoning and simulation tasks.","authors":["Jorge Diaz Chao","Konpat Preechakul","Yuxi Liu","Yutong Bai"],"published":"2026-07-14T17:59:22Z","updated":"2026-07-14T17:59:22Z","abstract_url":"https://arxiv.org/abs/2607.13031v1","html_url":"https://arxiv.org/html/2607.13031v1","pdf_url":"https://arxiv.org/pdf/2607.13031v1.pdf","matched_keywords":["video","diffusion"],"source_used":"html","source_text_chars":79416,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, diffusion 相关；摘要显示其主要贡献为：When one ball strikes another, then another, video models should predict the consequences of each bounce. In controlled experiments on multi-ball hard-sphere dynamics, we find that the performance of standard bidirectional video diffusion degrades as the caus...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:56+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.13017v1","title":"FlowWAM: Optical Flow as a Unified Action Representation for World Action Models","abstract":"World Action Models (WAMs) are able to leverage pretrained video generators for both world modeling and action prediction. However, directly leveraging such video generators for control raises a new challenge: how to represent actions in a suitable form that aligns with pretrained video generators while carrying enough motion cues for accurate control. Existing numerical actions fail to satisfy the former, and prior visual action representations overlook the temporal motion structure across frames. We address this issue with FlowWAM, a dual-stream diffusion framework that adopts optical flow as a unified, video-native action representation. Flow videos share the same format as RGB videos and encode rich per-pixel displacement. By jointly modeling them within a shared pretrained video generator, FlowWAM can naturally implement two modes of WAMs. In policy mode, FlowWAM generates flow for action prediction, while in world-model mode, it uses target flow sequences to guide future video generation. Moreover, since flow can be easily extracted from raw videos without action labels, FlowWAM can leverage large-scale action-unlabeled video datasets for pretraining. We empirically find that our flow-based action representation delivers gains across both modes. On RoboTwin manipulation, FlowWAM raises the success rate to 92.94% on the Clean setting and 92.14% on Random, outperforming both VLA and WAM baselines. On WorldArena world modeling, it achieves the best overall EWMScore (63.71) with an 18.4% relative improvement in trajectory accuracy. More results can be found on our project website: https://flow-wam.github.io .","authors":["Yixiang Chen","Peiyan Li","Yuan Xu","Qisen Ma","Jiabing Yang","Kai Wang","Jianhua Yang","Dong An","He Guan","Gaoteng Liu","Jianlou Si","Jun Huang","Jing Liu","Nianfeng Liu","Yan Huang","Liang Wang"],"published":"2026-07-14T17:57:12Z","updated":"2026-07-14T17:57:12Z","abstract_url":"https://arxiv.org/abs/2607.13017v1","html_url":"https://arxiv.org/html/2607.13017v1","pdf_url":"https://arxiv.org/pdf/2607.13017v1.pdf","matched_keywords":["video","representation","diffusion"],"source_used":"html","source_text_chars":89900,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, representation, diffusion 相关；摘要显示其主要贡献为：World Action Models (WAMs) are able to leverage pretrained video generators for both world modeling and action prediction. However, directly leveraging such video generators for control raises a new challenge: how to represent actions in a suitable form that...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:56+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.13010v1","title":"DermDepth: Toward Monocular Metric Scale 3D Reconstruction Models for Dermatology","abstract":"Dermatological practice routinely involves measuring and tracking lesion size, morphology and texture, as critical components of wound or skin cancer screening, monitoring and diagnosis. To accomplish this task, practitioners often image the skin surface with commonly available off-the-shelf camera sensors. This has led to an overwhelming research focus on 2D methods while these objectives naturally benefit from 3D information. In this paper, we demonstrate that dense monocular 3D reconstructions, metric scale measurements and rich surface normal texture estimates are achievable for both dermoscopic and macroscopic cases without the need for additional hardware or multiple captures. We present DermDepth, the first single-view metric scale 3D model for the dermatological domain and D-Synth, the first synthetic dermoscopic dataset with pixel-perfect 3D information. Our experiments show training DermDepth on D-Synth corrects metric scale error from over 16x to under 1.1x for real dermoscopic data, while preserving geometric quality and increasing texture richness. Fine-tuning on a small amount of real clinical samples generalizes our method across three real-world benchmarks spanning the few mm to hundred cm range, diverse skin-tones, chronic wound cases and produces measurements broadly consistent with disease size reported in medical literature. All code, data and models are available at https://github.com/hectorcarrion/dermdepth.","authors":["Héctor Carrión","Narges Norouzi"],"published":"2026-07-14T17:51:37Z","updated":"2026-07-14T17:51:37Z","abstract_url":"https://arxiv.org/abs/2607.13010v1","html_url":"https://arxiv.org/html/2607.13010v1","pdf_url":"https://arxiv.org/pdf/2607.13010v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":27634,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Dermatological practice routinely involves measuring and tracking lesion size, morphology and texture, as critical components of wound or skin cancer screening, monitoring and diagnosis. To accomplish this task, practitioners often image the skin surface with...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:56+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12959v1","title":"ViCo3D: Empowering LiDAR-based Collaborative 3D Object Detection with Vision Foundation Models","abstract":"LiDAR-based collaborative 3D perception in Vehicle-to-Everything (V2X) systems typically relies on fusing bird's-eye-view (BEV) features across agents. However, current BEV representations, typically extracted by LiDAR backbones trained from scratch, are geometry-dominated and lack general semantic priors, inherently limiting the efficacy of feature-level collaboration. Meanwhile, vision foundation models (VFMs) pretrained on large-scale image data have demonstrated strong capability in learning general-purpose and informative visual representations for 2D tasks, and have the potential to enhance agent-wise LiDAR BEV representations for collaboration. Despite this potential, adapting VFMs to LiDAR-based 3D detection remains challenging due to the substantial image-point cloud modality gap. To bridge this gap, we propose ViCo3D, a collaborative 3D object detection framework powered by VFMs. Specifically, ViCo3D adapts VFMs to LiDAR-based collaborative perception from three aspects: First, ViCo3D projects point clouds onto the BEV plane as three-channel images, enabling DINOv2 to extract BEV-space visual features from LiDAR inputs. Besides, to effectively integrate these DINOv2-derived features with LiDAR geometric features, ViCo3D introduces a multi-scale BEV fusion module within the single-agent encoder. In addition, ViCo3D adopts an ego-centric cross-agent fusion strategy to aggregate complementary information from multiple agents. Experiments on DAIR-V2X and V2XSet demonstrate that ViCo3D achieves state-of-the-art 3D detection performance. Remarkably, it delivers up to 1.8x greater collaborative gains than prior methods on DAIR-V2X. The code will be made public available for future investigation.","authors":["Haojie Ren","Songrui Luo","Lingfeng Wang","Yan Xia","Yao Li","Jing Li","Lu Zhang","Jiajun Deng","Yanyong Zhang"],"published":"2026-07-14T16:56:10Z","updated":"2026-07-14T16:56:10Z","abstract_url":"https://arxiv.org/abs/2607.12959v1","html_url":"https://arxiv.org/html/2607.12959v1","pdf_url":"https://arxiv.org/pdf/2607.12959v1.pdf","matched_keywords":["3d","agent","representation"],"source_used":"html","source_text_chars":87955,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, agent, representation 相关；摘要显示其主要贡献为：LiDAR-based collaborative 3D perception in Vehicle-to-Everything (V2X) systems typically relies on fusing bird's-eye-view (BEV) features across agents. However, current BEV representations, typically extracted by LiDAR backbones trained from scratch, are geom...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12939v1","title":"Point Tracking in Surgery--The 2025 Surgical Tattoos in Infrared Challenge (STIRC2025)","abstract":"Point tracking in surgery is crucial to enable applications in downstream tasks such as segmentation, 3D reconstruction, virtual tissue landmarking, autonomous probe-based scanning, and subtask autonomy. This paper introduces the 2025 iteration of a point tracking challenge to address this, wherein participants submit their algorithms for quantification. Their algorithms are evaluated using a dataset named surgical tattoos in infrared (STIR), with the challenge named the STIR Challenge 2025 (STIRC2025). The STIR Challenge 2025 comprises two quantitative components: accuracy and efficiency. The accuracy component tests the accuracy of algorithms on in vivo and ex vivo sequences. The efficiency component tests algorithm inference latency. The challenge was conducted as a part of MICCAI EndoVis 2025, and seven teams participated in this challenge. In this paper we summarize the challenge results and participant methods. The challenge dataset is available at: https://zenodo.org/records/20191078, and the code for baseline models and metrics calculation is available here: https://github.com/athaddius/STIRMetrics","authors":["Adam Schmidt","Mert Asim Karaoglu","Zijian Wu","Jiaming Zhang","Yuxin Chen","Tim Salcudean","Ho-Gun Ha","Minkang Jang","Kyungmin Jung","Ihsan Ullah","Hyunki Lee","Suresh Guttikonda","Sarah Latus","Alexander Schlaefer","Xinkai Zhao","Yuichiro Hayashi","Masahiro Oda","Takayuki Kitasaka","Kensaku Mori","Peng Liu","Chenyang Li","Stefanie Speidel","Aoife Gardiner","Agostino Stilli","Danail Stoyanov","Francisco Vasconcelos","Anwesa Choudhuri","Meng Zheng","Zhongpai Gao","Benjamin Planche","Van Nguyen Nguyen","Terrence Chen","Ziyan Wu","Alexander Ladikos","Omid Mohareri"],"published":"2026-07-14T16:10:49Z","updated":"2026-07-14T16:10:49Z","abstract_url":"https://arxiv.org/abs/2607.12939v1","html_url":"https://arxiv.org/html/2607.12939v1","pdf_url":"https://arxiv.org/pdf/2607.12939v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":43858,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Point tracking in surgery is crucial to enable applications in downstream tasks such as segmentation, 3D reconstruction, virtual tissue landmarking, autonomous probe-based scanning, and subtask autonomy. This paper introduces the 2025 iteration of a point tra...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12937v1","title":"Exact and Calibrated Diffusion Reconstruction for Digital Breast Tomosynthesis","abstract":"Limited-angle digital breast tomosynthesis (DBT) reconstructs a volume from a few low-dose projections over a narrow arc. At a representative nine-view, $25^{\\circ}$ protocol more than 98% of image space is unmeasured, so a learned prior must supply structure in the missing wedge. Conditional diffusion priors achieve strong perceptual quality here but leave three clinical obstacles: inexact data consistency, unlocalized hallucination, and uncalibrated uncertainty. We enforce measurements exactly by replacing the per-step proximal update of a conditional diffusion sampler with exact Euclidean projection onto the data-consistent set, computed via an $m$-dimensional dual system with a one-time Gram matrix $AA^{\\top}$ factorization. This projection costs 4.5 ms per step (a $248\\times$ speedup) and drives the data residual to the double-precision floor ($2.4\\times10^{-13}$). We prove it is the $ρ\\to0$ limit of the proximal step, provide a no-harm theorem, and show that exactly consistent sample ensembles have variance supported on null($A$). Thus, the mean's entire error lies in the unmeasured subspace covered by the uncertainty map. On patient-derived breast phantoms, this improves fidelity at no depth-resolution cost. Conversely, a proximal step applied post-update degrades quality, isolating the consistency step's placement as decisive. Isotonic recalibration brings the ensemble spread to a calibrated error scale (expected calibration error $0.029\\to0.008$; standardized error $4.7\\to0.96$), ranking errors better than the pure prior. We also repair a 20.3% adjoint mismatch in a deployed projector via a materialized operator of record. This is the first data-consistent, uncertainty-calibrated learned reconstruction for limited-angle DBT. The solver naturally relaxes to discrepancy-ball and maximum-a-posteriori modes for noisy measurements.","authors":["Imade Bouftini"],"published":"2026-07-14T16:10:10Z","updated":"2026-07-14T16:10:10Z","abstract_url":"https://arxiv.org/abs/2607.12937v1","html_url":"https://arxiv.org/html/2607.12937v1","pdf_url":"https://arxiv.org/pdf/2607.12937v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":80162,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Limited-angle digital breast tomosynthesis (DBT) reconstructs a volume from a few low-dose projections over a narrow arc. At a representative nine-view, $25^{\\circ}$ protocol more than 98% of image space is unmeasured, so a learned prior must supply structure...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12934v1","title":"Domain-Incremental Remote Sensing Change Detection via Difference-Guided Adaptation and Frequency-Decoupled Distillation","abstract":"Remote sensing change detection (RSCD) models are prone to catastrophic forgetting when incrementally adapted to new domains. Existing domain-incremental learning (DIL) methods mainly preserve image-level representations but often overlook bitemporal discrepancy cues, which are critical for robust change detection under domain shifts. To address this limitation, we propose DG-FDD, a domain-incremental change detection framework that integrates Difference-Guided Adaptation and Frequency-Decoupled Distillation. Specifically, the Difference-Guided Dynamic Adapter (DGDA) models bitemporal feature discrepancies to promote change-aware feature adaptation and reduce domain-specific interference. Meanwhile, the Frequency-Decoupled Knowledge Distillation strategy with Cross-domain Synthesis (FDKD-CS) separates structural information from domain style in the frequency domain, enabling stable knowledge transfer without historical data. Extensive experiments on three public high-resolution RSCD datasets under two- and three-domain incremental protocols demonstrate that DG-FDD effectively mitigates catastrophic forgetting. Compared with independently trained single-task models, DG-FDD records mean relative changes in F1 and IoU of only -0.23% and -0.45%, respectively, across six two-domain sequences, and -0.69% and -1.31%, respectively, across the three evaluated three-domain sequences. These results indicate a favorable stability-plasticity balance between historical knowledge retention and new-domain adaptation in continual cross-domain change detection.","authors":["Daifeng Peng","Yaning Li","Haiyan Guan"],"published":"2026-07-14T16:07:21Z","updated":"2026-07-14T16:07:21Z","abstract_url":"https://arxiv.org/abs/2607.12934v1","html_url":"https://arxiv.org/html/2607.12934v1","pdf_url":"https://arxiv.org/pdf/2607.12934v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":99574,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Remote sensing change detection (RSCD) models are prone to catastrophic forgetting when incrementally adapted to new domains. Existing domain-incremental learning (DIL) methods mainly preserve image-level representations but often overlook bitemporal discrepa...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12911v1","title":"Open-KNEAD: Knowledge-grounded Nutrition Estimation via Agentic Decomposition","abstract":"Multimodal Large Language Models (MLLMs) are increasingly used for dietary assessment from meal images, where retrieval-augmented grounding was shown to sharpen nutrition estimates. However, we find this premise no longer holds for current MLLMs. A modern MLLM's direct estimate now matches or surpasses the full retrieval pipeline. This raises a question: if retrieval no longer improves the overall estimate, can it still deliver the two things clinicians value, accurate portions and a traceable, item-by-item record? We pursue this while preserving what matters for clinical adoption: minimal user burden (a single, unannotated meal image), explainability (an auditable record), and privacy (locally hosted inference). We introduce Open-KNEAD, a knowledge-grounded agentic framework for meal nutrition estimation that is training-free and locally deployable. Each decomposed food item is grounded to a Food and Nutrient Database for Dietary Studies (FNDDS) code via selective, nutrient-aware retrieval, composing an auditable per-item record. Across two open MLLM families and three cuisines, Open-KNEAD improves portion estimates over both prior grounding methods and direct estimation in most backbone-dataset settings. An agent-internal recipe-prior step further recovers the invisible cooking-added energy that biases estimates on non-US cuisine. The advantage is largest on the dietitian-verified ACETADA dataset, where the local open agent surpasses the direct portion estimates of two frontier closed models by roughly $30\\%$ and $53\\%$, all while keeping every meal image on local hardware. We release the Open-KNEAD framework and its agent-ready FNDDS knowledge base.","authors":["Bruce Coburn","Jingbo Yue","Jinge Ma","Siddeshwar Raghavan","Gautham Vinod","Fengqing Zhu"],"published":"2026-07-14T15:48:25Z","updated":"2026-07-14T15:48:25Z","abstract_url":"https://arxiv.org/abs/2607.12911v1","html_url":"https://arxiv.org/html/2607.12911v1","pdf_url":"https://arxiv.org/pdf/2607.12911v1.pdf","matched_keywords":["retrieval","agent","multimodal"],"source_used":"html","source_text_chars":65829,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval, agent, multimodal 相关；摘要显示其主要贡献为：Multimodal Large Language Models (MLLMs) are increasingly used for dietary assessment from meal images, where retrieval-augmented grounding was shown to sharpen nutrition estimates. However, we find this premise no longer holds for current MLLMs. A modern MLL...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12896v1","title":"UniMedSeg: Unified In-Context Learning for Multi-Paradigm 2D/3D Medical Image Segmentation","abstract":"Medical image segmentation foundation models are expected to generalize across diverse clinical scenarios, yet existing universal methods remain fragmented by prompt paradigms and spatial dimensions. Visual in-context learning, interactive segmentation, and language-guided segmentation are typically handled by paradigm-specific models, while 2D and 3D images are also modeled separately. Such isolation prevents heterogeneous annotations and data from being jointly absorbed by a single scalable model and limits cross-paradigm knowledge transfer. To address this bottleneck, we propose UniMedSeg, a Transformer-centric universal segmentation framework that maps visual examples, geometric interactions, language instructions, and 2D/3D images into a shared sequence space, enabling heterogeneous medical supervision to be jointly learned through a unified in-context interface without prompt- or dimension-specific branches. To overcome the long-sequence memory bottleneck caused by visual contexts, we introduce Decoupled Split Attention, which reduces attention complexity to linear while preserving hardware-friendly computation and focused context-target interaction. Extensively trained and evaluated on a large corpus curated from 27 public datasets, UniMedSeg achieves state-of-the-art performance across visual in-context, interactive, and language-guided segmentation without task-specific fine-tuning, demonstrating strong generalization on diverse held-out tasks. The code and model weights are publicly available at https://github.com/Lii1228/UniMedSeg","authors":["Yunzhou Li","Jiesi Hu","Yanwu Yang","Hanyang Peng","Chenfei Ye","Jianfeng Cao","Yixuan Yuan","Ting Ma"],"published":"2026-07-14T15:34:46Z","updated":"2026-07-14T15:34:46Z","abstract_url":"https://arxiv.org/abs/2607.12896v1","html_url":"https://arxiv.org/html/2607.12896v1","pdf_url":"https://arxiv.org/pdf/2607.12896v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":62610,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Medical image segmentation foundation models are expected to generalize across diverse clinical scenarios, yet existing universal methods remain fragmented by prompt paradigms and spatial dimensions. Visual in-context learning, interactive segmentation, and l...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12894v1","title":"Hy-Embodied-VLM-1.0: Efficient Physical-World Agents","abstract":"Building capable embodied agents requires not only multimodal perception and understanding, but also agentic capabilities for reasoning about actions, adapting to evolving situations, and interacting with the physical world. In this report, we introduce Hy-Embodied-VLM-1.0, an efficient and powerful embodied foundation model specifically designed for embodied agents operating in the physical world. To cultivate such capabilities from the pre-training stage onward, we define an action-centric capability taxonomy comprising three progressive dimensions: Action-Relevant State Understanding, Action-Transition Reasoning, and Sequential and Adaptive Reasoning. Guided by this taxonomy, we develop a systematic data pipeline and curate data mixtures spanning both pre-training and post-training. To deliver strong physical-world understanding and interaction capabilities while supporting latency-sensitive deployment, we build our model on the Hy3-A3B language backbone and the Hy-ViT2 vision encoder. Its efficient Mixture-of-Experts architecture combines strong model capacity with high inference efficiency. We evaluate Hy-Embodied-VLM-1.0 on a comprehensive suite of 38 benchmarks covering embodied perception, physical-world understanding, and embodied reasoning. The model achieves the best performance among similarly sized models on 19 of the 38 benchmarks and substantially outperforms strong competitors, including Qwen3.6-A3B and Cosmos 3. Compared with the previous-generation Hy-Embodied-0.5 MoT-2B, Hy-Embodied-VLM-1.0 improves average performance by 8.4%. Despite activating only 3B parameters, it achieves performance close to that of the previous-generation model with 32B activated parameters. Beyond static benchmark evaluation, Hy-Embodied-VLM-1.0 also demonstrates strong performance on embodied agentic tasks requiring multi-turn interaction and long-horizon reasoning.","authors":["Ziyi Wang","Xumin Yu","Yongming Rao","Yonggen Ling","Yunheng Li","Oran Wang","Mingqi Gao","Yuchen Zhou","Yves Liang","Zuyan Liu","Yani Zhang","Rui Huang","Xiaoran Xu","Bowen Yuan","Yifu Yuan","Xu Tan","He Zhang","Yufei Huang","Shenghao Zhang","Hongsheng Wu","Han Hu","Zhengyou Zhang"],"published":"2026-07-14T15:34:17Z","updated":"2026-07-14T15:34:17Z","abstract_url":"https://arxiv.org/abs/2607.12894v1","html_url":"https://arxiv.org/html/2607.12894v1","pdf_url":"https://arxiv.org/pdf/2607.12894v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"html","source_text_chars":106273,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 agent, multimodal 相关；摘要显示其主要贡献为：Building capable embodied agents requires not only multimodal perception and understanding, but also agentic capabilities for reasoning about actions, adapting to evolving situations, and interacting with the physical world. In this report, we introduce Hy-Em...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12874v1","title":"Metric-Guided Synthetic Image Data Rendering for Deep Learning compatible with Agentic AI","abstract":"Deep learning computer vision for scientific applications requires collecting and annotating large datasets in a laborious, expensive and error-prone process. Synthetic data generation through 3D modelling and rendering may simplify this process and increase the accuracy of annotations by generating them programmatically. However, minimising the domain gap between real and synthetic images visually is subjective and lacks systematic quantitative guidance. We present GraNatPy, a Python package with metrics to guide improvement of the rendered scene. We show that quantifiable increase in realism, diversity and size of rendered dataset correlates with improved visual perception of the scene and higher zero-shot performance of an object detection model. Furthermore, we demonstrated using photographs of virological plaque assays that gradient similarity affects performance on small object detection, which can be improved by mixing real and synthetic data. Finally, we turn procedural data rendering into an agentic skill (SynthClaw) to automate the procedural parameter optimisation.","authors":["Martina Radoynova","Samuel Pantze","Trina De","Ulrik Günther","Artur Yakimovich"],"published":"2026-07-14T15:22:26Z","updated":"2026-07-14T15:22:26Z","abstract_url":"https://arxiv.org/abs/2607.12874v1","html_url":"https://arxiv.org/html/2607.12874v1","pdf_url":"https://arxiv.org/pdf/2607.12874v1.pdf","matched_keywords":["3d","agent"],"source_used":"html","source_text_chars":56318,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, agent 相关；摘要显示其主要贡献为：Deep learning computer vision for scientific applications requires collecting and annotating large datasets in a laborious, expensive and error-prone process. Synthetic data generation through 3D modelling and rendering may simplify this process and increase...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12820v1","title":"AVSCap: Orchestrating Audio-Visual Synergy for Omni-modal Video Captioning","abstract":"Omni-modal video captioning is not merely combining visual captioning with audio transcription: a useful caption must describe how visual actions, speech, music, and sound effects co-evolve. Existing large multimodal models often fail at this relational step, treating audio and visual streams as loosely coupled observations, relying on automatic speech recognition, and under-specifying non-speech sounds and their links to visual events. We present AVSCap, a framework for audio-visual captioning centered on explicit cross-modal event binding. First, we construct AVSCap-130K, a tri-modal training corpus generated by a decoupled-then-fused pipeline that anchors visual and acoustic evidence before composing grounded omni-modal captions. Second, we train AVSCap-7B, a 7B captioner with a two-stage strategy: supervised fine-tuning establishes baseline capabilities, while sample-efficient reinforcement learning uses hybrid rewards to optimize acoustic completeness and audio-visual synergy. Our scaling analysis shows that reinforcement learning brings larger gains than increasing SFT data. Third, we introduce AVSCapBench, a benchmark that decomposes captions into visual, audio, and synergy events and evaluates them with fine-grained event recall. Experiments on AVSCapBench and external benchmarks show that AVSCap-7B improves non-speech audio coverage and cross-modal binding, delivering the best overall performance among evaluated open-source models.","authors":["Yanghai Wang","Jiahao Wang","Jiafu Tang","Yuanxing Zhang","Zhe Cao","Hanyan Bian","Zijie Zhang","Weiliang Luo","Zhiyu Pan","Zixuan Dong","Jiaheng Liu","Zhaoxiang Zhang"],"published":"2026-07-14T14:34:19Z","updated":"2026-07-14T14:34:19Z","abstract_url":"https://arxiv.org/abs/2607.12820v1","html_url":"https://arxiv.org/html/2607.12820v1","pdf_url":"https://arxiv.org/pdf/2607.12820v1.pdf","matched_keywords":["video","multimodal"],"source_used":"html","source_text_chars":105724,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, multimodal 相关；摘要显示其主要贡献为：Omni-modal video captioning is not merely combining visual captioning with audio transcription: a useful caption must describe how visual actions, speech, music, and sound effects co-evolve. Existing large multimodal models often fail at this relational step,...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12818v1","title":"Breaking Déjà Vu: Independent Auditing of Visual Place Recognition through Vision-Language Reasoning","abstract":"Visual place recognition (VPR) is a key enabler of accurate localization and long-term autonomous navigation in robotics applications, such as loop closure detection for simultaneous localisation and mapping (SLAM). However, real-world VPR deployment relies on selecting an image matching threshold that balances precision and recall. These thresholds are typically tuned using labeled validation data and fixed during deployment, making them unreliable under environmental changes where ground truth is unavailable. This is particularly problematic in safety-critical robotics, where accepting a false loop closure can corrupt the estimated trajectory and map. In this work, we introduce Visual Place Recognition Auditing, an independent post-retrieval verification framework that leverages Vision-Language Models (VLMs) to assess retrieved matches by reasoning jointly over query and candidate images. Unlike conventional verification methods, our approach performs instance-level verification without requiring architecture-specific confidence measures, dataset-dependent thresholds, or prior knowledge of the deployment environment. We evaluate our method on six benchmark datasets using five state-of-the-art VPR methods and four VLMs. Results show that VLM-based auditing improves recall@1 by 13.6% on average as compared to state-of-the-art methods while reducing false acceptance rates to 12%, maintaining precision above 95% and coverage above 75%.","authors":["Sania Waheed","Michael Milford","Sarvapali D. Ramchurn","Shoaib Ehsan"],"published":"2026-07-14T14:30:24Z","updated":"2026-07-14T14:30:24Z","abstract_url":"https://arxiv.org/abs/2607.12818v1","html_url":"https://arxiv.org/html/2607.12818v1","pdf_url":"https://arxiv.org/pdf/2607.12818v1.pdf","matched_keywords":["retrieval","instance"],"source_used":"html","source_text_chars":47232,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval, instance 相关；摘要显示其主要贡献为：Visual place recognition (VPR) is a key enabler of accurate localization and long-term autonomous navigation in robotics applications, such as loop closure detection for simultaneous localisation and mapping (SLAM). However, real-world VPR deployment relies o...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12800v1","title":"UniVR: Thinking in Visual Space for Unified Visual Reasoning","abstract":"Learning broad world knowledge directly from raw visual data is a fundamental capability of intelligence. We introduce UniVR, the first investigation into simultaneously learning complex reasoning, fine-grained physical dynamics, and long-term planning from pure visual demonstrations. At its core, UniVR features VR-GRPO, a reinforcement learning paradigm with complementary global and step-level rewards. This approach enforces logical coherence and physical consistency throughout the reasoning process without requiring task-specific heuristics or image-text pairs. To train and evaluate UniVR, we construct VR-X, a large-scale benchmark curated from 16 diverse sources spanning long-horizon manipulation, spatial puzzles, and physical reasoning. It is the first comprehensive suite to assess these heterogeneous capabilities under a purely visual protocol. Remarkably, UniVR achieves up to a 25% improvement on VR-X, and its superior visual reasoning also boosts performance on various multimodal understanding benchmarks. These findings underscore the vast potential of reasoning within visual spaces, with all code, data, and models are open-sourced for further research.","authors":["Zhongwei Ren","Yunchao Wei","Yao Zhao","Weibo Gong","Xiao Liu","Anran Wang","Xiangtai Li","Xiaojie Jin"],"published":"2026-07-14T14:15:13Z","updated":"2026-07-14T14:15:13Z","abstract_url":"https://arxiv.org/abs/2607.12800v1","html_url":"https://arxiv.org/html/2607.12800v1","pdf_url":"https://arxiv.org/pdf/2607.12800v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":71048,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Learning broad world knowledge directly from raw visual data is a fundamental capability of intelligence. We introduce UniVR, the first investigation into simultaneously learning complex reasoning, fine-grained physical dynamics, and long-term planning from p...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12789v1","title":"AVQ-Attention: Adaptive Vector-Quantized Attention","abstract":"The $\\mathcal{O}(N^2)$ complexity of attention over $N$ tokens remains a computational bottleneck in transformer models. Vector-Quantized (VQ) attention reduces this to $\\mathcal{O}(MN)$ by representing keys with $M$ codewords, but applies uniform codebook capacity regardless of where attention mass concentrates: high-attention regions of key space may be coarsely approximated while low-attention regions waste representational capacity. We propose Adaptive Vector-Quantized (AVQ) Attention, which adaptively allocates codebook capacity based on attention importance. Starting from a small set of codewords, our method identifies the most important codes during the forward pass and refines them with pre-learned child codewords, achieving fine-grained quantization where it matters most while maintaining coarse quantization elsewhere. We develop an implementation using custom Triton kernels that enables the full adaptive refinement process, including importance scoring, child codeword insertion, and parent contribution replacement, to be carried out within the tiled computation paradigm of Flash Attention with minimal overhead. Our approach maintains $\\mathcal{O}(MN)$ complexity while achieving improved accuracy-efficiency trade-offs compared to fixed-codebook VQ-attention.","authors":["Winfried van den dool","Patrick Forré","Amir Habibian","Yuki M. Asano","Max Welling"],"published":"2026-07-14T14:02:22Z","updated":"2026-07-14T14:02:22Z","abstract_url":"https://arxiv.org/abs/2607.12789v1","html_url":"https://arxiv.org/html/2607.12789v1","pdf_url":"https://arxiv.org/pdf/2607.12789v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":69877,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：The $\\mathcal{O}(N^2)$ complexity of attention over $N$ tokens remains a computational bottleneck in transformer models. Vector-Quantized (VQ) attention reduces this to $\\mathcal{O}(MN)$ by representing keys with $M$ codewords, but applies uniform codebook ca...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12787v1","title":"Do We Really Need Multimodal Emotion Language Models Larger Than 1B Parameters?","abstract":"Recent advances in multimodal large language models (MLLMs) have significantly improved the performance of multimodal emotion recognition (MER) and enabled interpretable description generation by jointly modeling video, audio, and language, etc. However, these performance improvements are often accompanied by an increase in model parameter size (e.g, at least 7B), which simultaneously incurs high computational costs and reduces inference efficiency, thereby hindering real-time deployment on resource-constrained platforms such as robots and mobile devices. This raises a fundamental question: do we really need the multimodal MER model larger than 1B parameters for high-quality MER? In this paper, we challenge the assumption that larger models are inherently necessary and proposes a lightweight MER framework (called Light-MER), which achieves better and faster multimodal sentiment understanding and recognition through knowledge distillation. It can transfer knowledge from a strong, large-scale teacher model to a lightweight sub-billion-parameter student model, aiming to preserve rich multimodal emotion reasoning and recognition while substantially improving deployment efficiency. Specifically, we introduce two new optimization strategies to enhance knowledge transfer: (1) a new optimal transport loss that combines Sliced Wasserstein Distance with hidden-state alignment, and (2) a new multi-reward optimization strategy based on GRPO that balances MER performance and efficiency, aimed at further enhancing the learning capabilities of student models. Extensive experiments on nine benchmark datasets demonstrate that Light-MER achieves state-of-the-art performance while significantly improving inference efficiency. This highlights the strong potential of small multimodal emotion language models for future research. Code is available at https://github.com/GAIR-Lab/Light-MER.","authors":["Kaiwen Zheng","Junchen Fu","Wenhao Deng","Hu Han","Joemon M. Jose","Xuri Ge"],"published":"2026-07-14T14:01:29Z","updated":"2026-07-14T14:01:29Z","abstract_url":"https://arxiv.org/abs/2607.12787v1","html_url":"https://arxiv.org/html/2607.12787v1","pdf_url":"https://arxiv.org/pdf/2607.12787v1.pdf","matched_keywords":["video","multimodal"],"source_used":"html","source_text_chars":64580,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, multimodal 相关；摘要显示其主要贡献为：Recent advances in multimodal large language models (MLLMs) have significantly improved the performance of multimodal emotion recognition (MER) and enabled interpretable description generation by jointly modeling video, audio, and language, etc. However, thes...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:58+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12786v1","title":"CoRe: A Comprehensive Framework for Cross-Image Comparative Reasoning in Vision-Language Models","abstract":"Cross-image comparative reasoning remains challenging for vision-language models (VLMs), especially when correct prediction requires fine-grained attribute grounding and globally consistent reasoning. We present CoRe, a unified framework for this problem. CoRe includes: (i) CoRe-20K, a large-scale triplet-based training set automatically constructed from structured visual metadata through a multi-expert collaborative pipeline, covering counting, depth, distance, and spatial relations; (ii) TriSR, a structured reward framework that jointly supervises attribute grounding, judgment alignment, and triplet consistency under GRPO optimization; and (iii) CoRe-Bench, the first benchmark dedicated to fine-grained cross-image comparative reasoning. Experiments show that CoRe substantially outperforms existing VLMs on CoRe-Bench while remaining competitive on standard multimodal benchmarks, achieving a 28.2-point gain in partial accuracy over the strongest baseline.","authors":["Lin Peng","Cong Wan","Zeyu Guo","SongLin Dong","Yihong Gong"],"published":"2026-07-14T14:01:07Z","updated":"2026-07-14T14:01:07Z","abstract_url":"https://arxiv.org/abs/2607.12786v1","html_url":"https://arxiv.org/html/2607.12786v1","pdf_url":"https://arxiv.org/pdf/2607.12786v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":56190,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Cross-image comparative reasoning remains challenging for vision-language models (VLMs), especially when correct prediction requires fine-grained attribute grounding and globally consistent reasoning. We present CoRe, a unified framework for this problem. CoR...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:58+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12785v1","title":"ExtraGS: Enhancing Endoscopic View Extrapolation via Diffusion-Guided 3D Gaussian Splatting","abstract":"Robot-assisted minimally invasive surgery (MIS) critically depends on reliable endoscopic perception for navigation and safety. However, conventional endoscopes provide only a limited field of view, leaving large portions of surrounding anatomy unobserved. Recent neural rendering approaches, such as Neural Radiance Fields and 3D Gaussian Splatting, enable novel view synthesis from endoscopic videos, but their reliance on sparse observations often leads to severe artifacts when extrapolating beyond the training trajectory.In this work, we propose ExtraGS, a framework for enhancing endoscopic view extrapolation via diffusion-guided 3D Gaussian Splatting. Starting from an initial reconstruction, we introduce an uncertainty-guided virtual camera sampling strategy to actively explore blind spots and maximize information gain. The rendered views from these sampled locations are refined using a diffusion model to recover plausible anatomical structures, producing pseudo observations that guide further optimization. To prevent the generated content from degrading reliable regions, we adopt a confidence-weighted fine-tuning strategy when incorporating these pseudo observations.Extensive experiments on multiple public endoscopic datasets demonstrate that ExtraGS significantly reduces extrapolation artifacts and achieves state-of-the-art performance in endoscopic novel view synthesis.","authors":["Cheng-Tai Hsieh","Jiwei Shan","Han Fang","Jianshu Hu","Tao Ni","Lijun Han","Yutong Ban","Shing Shin Cheng","Hesheng Wang"],"published":"2026-07-14T14:00:50Z","updated":"2026-07-14T14:00:50Z","abstract_url":"https://arxiv.org/abs/2607.12785v1","html_url":"https://arxiv.org/html/2607.12785v1","pdf_url":"https://arxiv.org/pdf/2607.12785v1.pdf","matched_keywords":["video","3d","diffusion"],"source_used":"html","source_text_chars":50605,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, diffusion 相关；摘要显示其主要贡献为：Robot-assisted minimally invasive surgery (MIS) critically depends on reliable endoscopic perception for navigation and safety. However, conventional endoscopes provide only a limited field of view, leaving large portions of surrounding anatomy unobserved. Re...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:58+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12782v1","title":"MBTI: A Multi-Branch Efficient Fine-Tuning Framework for Hyperspectral Image Classification with Foundation Models","abstract":"Hyperspectral foundation models learn transferable spectral-spatial representations from large-scale unlabeled data. They provide an effective paradigm for adapting to downstream hyperspectral image (HSI) classification tasks with limited labeled samples. However, spectral band configurations vary substantially across sensors, which makes direct model transfer difficult. Existing adaptation strategies often compress, select, or reshape the original spectra to match model-specific input requirements. These operations may discard useful spectral information and weaken local spectral continuity. To address this problem, we propose MBTI, a Multi-Branch efficient fine-tuning framework for Hyperspectral Image classification. MBTI adapts hyperspectral foundation models to downstream classification tasks while preserving full-band spectral information. First, we introduce a spectral-continuity-preserving multi-branch preprocessing strategy. The original HSI is divided into multiple continuous spectral subsets, and a band reuse mechanism is used when the remaining bands cannot form a complete branch. This avoids invalid padding and unnecessary spectral loss. Second, independent Low-Rank Adaptation (LoRA) modules are inserted into each branch. They enable different spectral intervals to learn task-specific discriminative features while keeping most pre-trained parameters frozen. Finally, a multi-branch channel attention fusion module adaptively recalibrates and integrates features from all spectral branches. Experiments on three public hyperspectral datasets show that MBTI achieves competitive and superior performance compared with representative classification methods. Under the final rank-8 configuration, only about 2.33\\%--2.36\\% of the parameters are trainable. The code will be available at https://github.com/Azhenmiddleblock/MBTI/tree/main.","authors":["Mingzhen Xu","Haonan Guo","Di Wang","Yinghua Qu","Zhiliang Zhou","Lei Zhang","Huiwen Yao","Rui Zhao","Fengxiang Wang","Gang Wan","Bo Du","Liangpei Zhang"],"published":"2026-07-14T13:58:10Z","updated":"2026-07-14T13:58:10Z","abstract_url":"https://arxiv.org/abs/2607.12782v1","html_url":"https://arxiv.org/html/2607.12782v1","pdf_url":"https://arxiv.org/pdf/2607.12782v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":70688,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Hyperspectral foundation models learn transferable spectral-spatial representations from large-scale unlabeled data. They provide an effective paradigm for adapting to downstream hyperspectral image (HSI) classification tasks with limited labeled samples. How...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:58+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12774v1","title":"HSEmotion Team at the 11th ABAW Challenge: Multi-Task Learning and Ambivalence/Hesitancy Video Recognition","abstract":"This article presents our results for the 11th Affective Behavior Analysis in-the-Wild (ABAW) competition. For multi-task learning with simultaneous prediction of valence, arousal, facial expressions, and action units on s-Aff-Wild2 dataset, we use frozen lightweight facial extractors, MT-EmotiDDAMFN and MT-EmotiEffNet-B0, with separate heads and systematic post-processing: temporal Gaussian smoothing, per-class expression bias, AffectNet blending, per-AU threshold tuning, and weighted backbone fusion. On the official validation set, our ensemble significantly exceeds the performance of the ConvNeXt baseline. For ambivalence/hesitancy video recognition on the expanded BAH dataset, we extend the audiovisual pipeline to video-level Macro F1 by late fusion of face, HuBERT audio, and RoBERTa text classifiers, temporal aggregation, and a global-text gate. Frame-level Weighted F1 on validation set rises from 0.74 in ABAW-8 to 0.79, while the best public-test video-level Macro F1 reaches 0.73. In both tasks, competitive performance is achieved without fine-tuning heavy backbones. These results indicate that systematic prediction calibration and lightweight multimodal fusion can rival substantially heavier end-to-end approaches while offering improved efficiency and deployment flexibility.","authors":["Aleksei Bakin","Andrey V. Savchenko"],"published":"2026-07-14T13:45:48Z","updated":"2026-07-14T13:45:48Z","abstract_url":"https://arxiv.org/abs/2607.12774v1","html_url":"https://arxiv.org/html/2607.12774v1","pdf_url":"https://arxiv.org/pdf/2607.12774v1.pdf","matched_keywords":["video","multimodal"],"source_used":"html","source_text_chars":41611,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, multimodal 相关；摘要显示其主要贡献为：This article presents our results for the 11th Affective Behavior Analysis in-the-Wild (ABAW) competition. For multi-task learning with simultaneous prediction of valence, arousal, facial expressions, and action units on s-Aff-Wild2 dataset, we use frozen lig...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:58+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12764v1","title":"EvoGraph-R1: Self-Evolving Multimodal Knowledge Hypergraphs for Agentic Retrieval","abstract":"Retrieval-augmented generation (RAG) has emerged as a critical paradigm for grounding Multimodal Large Language Models (MLLMs) in external knowledge. Recent GraphRAG methods introduce structured entity-relation graphs to improve retrieval and reasoning. However, they remain limited by treating knowledge graphs as static data structures built offline and queried in a single pass. This static paradigm misaligns with the interactive, iterative nature of knowledge-intensive reasoning, creating three bottlenecks: (i) text-centric fragmentation that impedes cross-modal reasoning, (ii) frozen structures unable to incorporate new evidence or correct errors, and (iii) rigid single-pass retrieval without adaptive refinement. To overcome these limitations, we introduce EvoGraph-R1, a self-evolving GraphRAG framework that reconceptualizes knowledge graphs as dynamic environments shaped through agent interactions. We formulate retrieval as a Markov Decision Process (MDP) where the agent observes the graph state and executes actions to query (GraphRetrieve), expand (WebSearch), refine (GraphEdit), or terminate (Answer) the reasoning. These actions reshape the hypergraph structure and generate feedback signals that guide subsequent evolution. Through this closed loop, the hypergraph evolves by integrating new evidence, correcting errors, and refining structure to support multi-hop reasoning. Experiments on multimodal VQA and text QA benchmarks demonstrate substantial improvements over existing RAG baselines in accuracy, coverage, and traceability, establishing self-evolving knowledge graphs as a fundamental paradigm across modalities.","authors":["Jiashi Lin","Changhong Jiang","Xiangru Lin","Ruifei Zhang","Xinyi Zhu","Jiyao Liu","Cheng Tang","Ye Du","Shujian Gao","Junzhi Ning","Lihao Liu","Ziyan Huang","Tianbin Li","Jin Ye","Junjun He"],"published":"2026-07-14T13:34:07Z","updated":"2026-07-14T13:34:07Z","abstract_url":"https://arxiv.org/abs/2607.12764v1","html_url":"https://arxiv.org/html/2607.12764v1","pdf_url":"https://arxiv.org/pdf/2607.12764v1.pdf","matched_keywords":["retrieval","agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12756v1","title":"VisCo: Leveraging Large Language Models as Intrinsic Encoders for Visual Token Compression","abstract":"Vision-language models (VLMs) process large numbers of visual tokens, resulting in substantial inference latency and memory overhead. This has motivated extensive research on visual token compression. While training-free strategies rely on heuristic metrics and suffer significant performance degradation under high compression ratios, many training-based methods introduce external compression modules that force the VLM backbone to adapt, incurring substantial retraining cost and compromising VLMs' priors. Effective visual token compression hinges on strong information encoding, a capability already present in pretrained VLMs but underutilized by existing approaches. Motivated by this, we propose VisCo, a training-efficient self-compression framework that reuses the pretrained VLM itself as an intrinsic compressor. VisCo is a parameter-sharing autoencoder that compresses visual information using a small set of memory tokens and transfers hierarchical information from encoding to decoding. Experiments show that VisCo surpasses prior methods across all evaluated compression ratios, with larger gains under more aggressive compression, and remains stable even in the extreme single-token setting. Moreover, when combined with the original visual tokens, the learned memory tokens can even improve the base model, suggesting that VisCo captures complementary representations beyond compression.","authors":["Yupeng Zheng","Kai Zou","Bin Liu","Nenghai Yu"],"published":"2026-07-14T13:21:36Z","updated":"2026-07-14T13:21:36Z","abstract_url":"https://arxiv.org/abs/2607.12756v1","html_url":"https://arxiv.org/html/2607.12756v1","pdf_url":"https://arxiv.org/pdf/2607.12756v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12753v1","title":"RFMSR: Residual Flow Matching for Image Super-Resolution","abstract":"Image super-resolution (ISR) has witnessed remarkable progress with diffusion models and flow matching. The dominant text-to-image (T2I) based approaches leverage large-scale foundation models as generative priors, achieving impressive perceptual quality but at the cost of massive model sizes and prohibitive training expenses. Recent flow-matching-based vision-only approaches have made significant strides; however, they adopt standard flow formulations that transport from a pure Gaussian prior to the data distribution, discarding the rich structural information already present in the low-quality (LQ) input. Furthermore, existing single-step acceleration techniques often forfeit the model's multi-step inference capability. In this paper, we propose Residual Flow Matching for Image Super-Resolution (RFMSR), a vision-only framework that centers the source distribution at the LQ latent, reducing transport distance and preserving structural priors throughout the flow trajectory. We further introduce a two-phase training strategy: Phase I pretrains the velocity field via conditional flow matching, while Phase II applies end-to-end supervision to the single-step prediction while retaining the velocity loss across all timesteps, achieving high-quality single-step generation without sacrificing multi-step refinement. Extensive experiments demonstrate that RFMSR achieves comparable or even superior perceptual quality compared to state-of-the-art (SOTA) methods. The source code is available at https://github.com/Faze-Hsw/RFMSR.","authors":["Shuwei Huang","Tianyao Luo","Jicheng Liu","Daizong Liu","Pan Zhou"],"published":"2026-07-14T13:19:36Z","updated":"2026-07-14T13:19:36Z","abstract_url":"https://arxiv.org/abs/2607.12753v1","html_url":"https://arxiv.org/html/2607.12753v1","pdf_url":"https://arxiv.org/pdf/2607.12753v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12752v1","title":"Hallo4D: Multi-Modal Hallucination Mitigation for Consistent Spatio-Temporal Generation","abstract":"While recent advances in 3D generation have enabled impressive visual synthesis, existing methods often rely on 2D diffusion supervision without explicit mechanisms for geometric consistency, leading to spatial hallucinations such as duplicated structures and misaligned geometry. These issues become more severe in 4D generation, where maintaining consistency across viewpoints and temporal evolution introduces additional challenges, including jitter, identity flicker, and structural drift. We present \\textbf{Hallo4D}, a unified and model-agnostic framework for mitigating spatiotemporal hallucinations in 3D and 4D content generation. Hallo4D introduces a generation-detection-correction paradigm that leverages large multimodal language models (LMMs) to identify and summarize spatial and temporal inconsistencies from multi-view and multi-frame renderings. These insights guide a consensus-driven image-space consistency optimization, where an LMM-based selector evaluates candidate corrections through multi-model voting, without requiring retraining or architectural modifications. To further improve temporal consistency and optimization efficiency, Hallo4D incorporates motion-aware keyframe sampling, LMM-guided initialization, and appearance alignment. We additionally introduce exposure-aware optimization and visibility pruning to enhance robustness under challenging viewpoints. Extensive experiments demonstrate that Hallo4D consistently outperforms strong baselines across diverse 3D and 4D generation settings, providing a scalable and generalizable solution for consistency-aware content generation.","authors":["Hongbo Wang","Huaibo Huang","Jie Cao","Jin Liu","Haoyang Tong","Ran He"],"published":"2026-07-14T13:19:06Z","updated":"2026-07-14T13:19:06Z","abstract_url":"https://arxiv.org/abs/2607.12752v1","html_url":"https://arxiv.org/html/2607.12752v1","pdf_url":"https://arxiv.org/pdf/2607.12752v1.pdf","matched_keywords":["3d","multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12748v1","title":"Weakly Supervised Spatio-Temporal Candidate Discovery of Dairy Farm Sites from Seasonal Satellite Imagery","abstract":"Farm site discovery from satellite imagery is a spatiotemporal candidate ranking problem because farm evidence is distributed across pasture, field boundaries, roads, buildings, and seasonal vegetation patterns. Direct farm labels are often incomplete, which makes fully supervised detection difficult. This paper proposes a weakly supervised pipeline for ranking dairy farm candidate clusters from seasonal Sentinel imagery and open map priors. The method uses aligned spring, summer, and autumn image tiles from County Cork, Ireland, with spectral bands, vegetation indices, built area indices, and a pasture channel. A Barlow Twins encoder learns multi-season tile embeddings without farm labels. In parallel, weak OpenStreetMap farm priors are split into a prior and a held-out set. Prior features support a rule-based tile score that combines farm proximity, seasonal pasture evidence, and summer greenness, while held-out features are reserved only for proxy evaluation. The rule score is smoothed over a spatial representation graph using geographic proximity and embedding similarity, and high-scoring tiles are grouped into ranked candidate clusters. From 26,722 valid tiles, the main run selects 535 high-confidence tiles and forms 71 candidate clusters. The top 5 clusters achieve 0.60 precision within 500 m and 0.80 precision within 1000 m of held-out OpenStreetMap farm features. The top 10 clusters achieve 0.40 precision within 500 m and 0.80 precision within 1000 m. The results show that seasonal representation learning and weak geographic priors can reduce large satellite image collections into compact candidate sets for human review.","authors":["Usman Haider","Fatima Khalid","Karl Mason"],"published":"2026-07-14T13:17:18Z","updated":"2026-07-14T13:17:18Z","abstract_url":"https://arxiv.org/abs/2607.12748v1","html_url":"https://arxiv.org/html/2607.12748v1","pdf_url":"https://arxiv.org/pdf/2607.12748v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12680v1","title":"ReflectVLN: Training Vision-Language Navigation Agents with Reflective Reasoning","abstract":"Existing vision-language navigation methods often couple a VLM with waypoint decoders to produce multi-step action plans, but they typically lack an explicit closed-loop mechanism for tracking semantic progress, diagnosing execution failures, and recovering from error accumulation in long-horizon navigation. To address this gap, we propose ReflectVLN, an agentic VLN framework that organizes decision-making through bidirectionally interactive intention and execution agents. The intention agent performs subtask decomposition and reflection, generating executable subtask descriptions as corrective plans. Conditioned on these descriptions, the execution agent grounds them into short-horizon actions under current observations while monitoring sub-goal progress and detecting off-track behavior. Crucially, ReflectVLN enables closed-loop bidirectional communication: the execution agent emits progress and deviation signals to trigger reflection and subtask updates on demand, and the intention agent returns structured guidance that reconditions subsequent actions for recovery. To encourage temporally coherent decisions with interpretable intermediate rationales, we introduce Action Chain-of-Thought (Action-CoT), a path-conditioned dual-query training scheme for action generation. Experiments on standard VLN benchmarks show that ReflectVLN improves success rates and path efficiency under a constrained data budget, with favorable training cost and fewer high-level intention calls at inference time, while providing interpretable intermediate decisions for analysis and collaboration. Code is available at: https://github.com/AIprogrammer/ReflectVLN","authors":["Jiahang Wang","Yirong Yang","Yanqing Zhu","Minghua Luo","Shichao Xie","Fei Liu","Mu Xu"],"published":"2026-07-14T12:09:33Z","updated":"2026-07-14T12:09:33Z","abstract_url":"https://arxiv.org/abs/2607.12680v1","html_url":"https://arxiv.org/html/2607.12680v1","pdf_url":"https://arxiv.org/pdf/2607.12680v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12678v1","title":"Text-Aided Multi-Modal Panoptic Symbol Spotting for CAD Floor Plan Drawings","abstract":"Computer-Aided Design (CAD) floor plan drawings contain both graphical primitives and textual annotations, which provide complementary geometric and semantic cues for intelligent design understanding. Among CAD analysis tasks, panoptic symbol spotting has become increasingly important with the growing demand for industrial digitalization and deep learning-based automation. However, most existing methods remain primarily primitive-centric and underexploit textual annotations, despite their critical semantic value. Even the few text-aware approaches often treat annotations only superficially, without properly modeling complex syntax and hierarchical semantics of CAD annotations, which leads to semantic loss and suboptimal spotting performance. To address these limitations, we propose TextCAD, a multimodal framework that jointly models graphical primitives and textual annotations for panoptic symbol spotting. Specifically, we design a Type-Attribute Correlation Encoder (TACE) to explicitly encode the compositional semantics within annotations by jointly modeling their types and attributes. We further introduce a Semantic Hierarchy Alignment framework with Multi-level Semantic Filtering (MSF) and primitive downsampling, which adaptively aligns annotation semantics with graphical primitives at different semantic levels and enables accurate cross-modal semantic injection and fusion. Experiments on real-world building-design datasets show that TextCAD effectively improves symbol spotting performance and achieves state-of-the-art results.","authors":["Yan Gong","Bohao Li","Bowen Du","Junchen Ye"],"published":"2026-07-14T12:07:44Z","updated":"2026-07-14T12:07:44Z","abstract_url":"https://arxiv.org/abs/2607.12678v1","html_url":"https://arxiv.org/html/2607.12678v1","pdf_url":"https://arxiv.org/pdf/2607.12678v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12630v1","title":"Instance-Enriched Semantic Maps for Visual Language Navigation","abstract":"Visual Language Navigation (VLN) aims to enable an embodied agent to navigate complex environments by following natural language instructions. Recent approaches build semantic spatial maps and leverage Large Language Models (LLMs) for reasoning and decision making. Despite these advances, existing systems lack instance-level object detail and robustness to diverse user queries, limiting reliable navigation in complex indoor environments. To address these limitations, we propose Instance-Enriched Semantic Maps, a unified framework with three key contributions: (1) Instance-level two-and-a-half-dimensional (2.5D) rich information mapping that constructs maps from color and depth observations via open-vocabulary panoptic segmentation, preserving vertical distinctions and capturing small objects, while storing diverse semantic attributes and natural language captions enriched with room-level context. (2) Robust query processing via LLM-based target selection, which dynamically routes queries across type-specialized experts and integrates their outputs through score-level fusion, enabling consistent goal selection across diverse query formulations. (3) Storage-efficient semantic representation that achieves approximately 96% reduction compared to three-dimensional (3D) scene-graph approaches while preserving sufficient spatial information for navigation. The proposed 2.5D representation outperforms the 3D baseline by over 27% in prediction-normalized Area Under the Curve (AUC). In navigation experiments, our method achieves over 17% improvement in object retrieval and over 23% in navigation success compared to the baseline across diverse query types. The project page is available at https://rcilab.github.io/iesm_vln.","authors":["Jiho Hong","Eunae Kang","Sanghyun Kim","Young-Sik Shin"],"published":"2026-07-14T11:09:48Z","updated":"2026-07-14T11:09:48Z","abstract_url":"https://arxiv.org/abs/2607.12630v1","html_url":"https://arxiv.org/html/2607.12630v1","pdf_url":"https://arxiv.org/pdf/2607.12630v1.pdf","matched_keywords":["retrieval","3d","agent","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12625v1","title":"KnowAct-GUIClaw: Know Deeply, Act Perfectly, Personal GUI Assistant with Self-Evolving Memory and Skill","abstract":"OpenClaw has emerged as a leading agent framework for complex task automation, yet it faces insufficient cross-platform GUI interaction support and a well-built self-evolution mechanism. These flaws limit its adaptation to diverse device ecosystems and prevent performance improvements through continuous learning from execution experience. To resolve these issues, we propose the Know Deeply, Act Perfectly paradigm for personal assistants, which holds that accumulated user interaction and task-running experience directly improve execution accuracy and efficiency, unifying cognitive comprehension and operational execution. Based on this paradigm, we introduce KnowAct-GUIClaw, a novel Know-Route-Act-Reflect framework designed to address OpenClaw's GUI manipulation deficits and break through its cross-platform and recursive self-improvement constraints. First, the host agent leverages accumulated interaction experience and task-relevant knowledge for long-horizon task decomposition and allocation (Know). Second, a pluggable GUI subagent with an experience-attributable memory system (Know) and self-evolving skill library (Act), enabling seamless cross-platform migration and fast-path integration. Especially, this framework continuously stores user profiles and feedback to improve the accuracy of task decomposition and tool calls. Extensive experiments across Android, iOS, HarmonyOS and Windows show that KnowAct-GUIClaw achieves superior efficiency, accuracy and cross-platform adaptability. Especially, the GUIClaw with open-source Kimi-2.6 models achieves the best performance (64.1%) on the long-horizon MobileWorld benchmark, beating all agentical frameworks and closed-source agentical models, e.g., Seed-2.0-Pro and GPT-5.5. Additionally, the knowledgeable memory and execution skills supported by our framework are transferable across diverse base models, improving by 8.5% with Kimi-2.6.","authors":["Yunxin Li","Jinchao Li","Shibo Su","Zhenran Xu","Chenrui Zhao","Tongshu Bian","Xiaoman Liang","Meishan Zhang","Baotian Hu","Min Zhang"],"published":"2026-07-14T11:04:01Z","updated":"2026-07-14T11:04:01Z","abstract_url":"https://arxiv.org/abs/2607.12625v1","html_url":"https://arxiv.org/html/2607.12625v1","pdf_url":"https://arxiv.org/pdf/2607.12625v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12621v1","title":"Towards Vision-Free CIR: Attribute-Augmented Scoring and LLM-Based Reranking for Zero-Shot Composed Image Retrieval","abstract":"Recent work has shown that \"Vision-Free'' approaches (representing images as text) can be effective for standard image retrieval tasks. However, it remains unclear whether this paradigm can effectively handle a more complex, multimodal task, Composed Image Retrieval (CIR), due to the inherent information loss in textual descriptions. In this paper, we introduce a Vision-Free CIR framework that addresses this challenge through two key techniques: (1) Attribute-Augmented Hybrid Scoring, which compensates for lost visual details via explicit attribute matching, and (2) LLM-Based Reranking, which verifies semantic consistency of top candidates. Experiments on the open-domain CIRR dataset show that our approach outperforms existing Zero-shot CIR methods (44.04% R@1, +8.79%). On FashionIQ, our results highlight the trade-off between semantic reasoning and fine-grained visual matching. Ablation studies reveal that both attribute-augmented scoring and LLM-Based Reranking consistently improve performance.","authors":["Ryotaro Shimada","Yu-Chieh Lin","Yuji Nozawa","Youyang Ng","Osamu Torii","Yusuke Matsui"],"published":"2026-07-14T10:58:12Z","updated":"2026-07-14T10:58:12Z","abstract_url":"https://arxiv.org/abs/2607.12621v1","html_url":"https://arxiv.org/html/2607.12621v1","pdf_url":"https://arxiv.org/pdf/2607.12621v1.pdf","matched_keywords":["retrieval","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12602v1","title":"Decouple and Reason: Anatomically Guided Two-Stage Voxel-Level Grounding of Free-Text Findings in 3D Chest CT","abstract":"Automatic voxel-level grounding of free-text findings in 3D chest Computed Tomography (CT) is critical for clinical interpretability. However, this task remains highly challenging due to the intricate spatial complexity of large 3D volumes and the heterogeneity of free-text findings. Existing end-to-end approaches often struggle to simultaneously learn the localized feature representations required for accurate 3D segmentation and the complex semantic understanding needed for text alignment, leading to suboptimal grounding performance. To overcome this fundamental limitation, we propose a novel decoupled framework that disentangles the problem into two specialized stages: (1) class-agnostic lesion segmentation and (2) text-volume reasoning. This structural separation allows the model to first extract candidate sub-volumes by localizing potential abnormalities. Subsequently, intensive cross-modal reasoning is performed to align these localized sub-volumes with free-text medical findings. To resolve the spatial ambiguities inherent in local regions, the reasoning module is augmented with explicit anatomical guidance, utilizing relative spatial coordinates and lung lobe priors. Evaluated on the ReXGroundingCT benchmark, our method achieves state-of-the-art performance in overall grounding quality on the official leaderboard. These results demonstrate that decoupling detection from reasoning is a highly effective paradigm for handling the complexity of 3D medical visual grounding. Our code is publicly available at https://github.com/khuhm/DAGG.","authors":["Kwang-Hyun Uhm","Inhwa Son","Sung-Jea Ko"],"published":"2026-07-14T10:26:14Z","updated":"2026-07-14T10:26:14Z","abstract_url":"https://arxiv.org/abs/2607.12602v1","html_url":"https://arxiv.org/html/2607.12602v1","pdf_url":"https://arxiv.org/pdf/2607.12602v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12592v1","title":"WanToFight: Real-Time Generative Game Engine for Multi-Player Combat Interaction","abstract":"We present WanToFight, a generative game engine that simulates real-time, two-player The King of Fighters '97 (KOF~'97) gameplay from keyboard input. Prior generative game engines target either single-player first-person settings or non-real-time cooperative scenarios; multi-player control, real-time inference, complex physical interaction, and adversarial gameplay have not been jointly addressed. WanToFight closes this gap with three components built on the Wan-1.3B video diffusion transformer: a streaming autoregressive generator with block-causal attention and a rolling KV cache; a visually grounded Player Association module that binds each player's keyboard signal to a character identity; and a gated, locally causal keyboard injection module trained with a single-player-to-full-gameplay curriculum. A four-step DMD-distilled student paired with a pruned VAE decoder sustains 30FPS at 512x384 on a single NVIDIA RTX 5090 over the duration of a complete match. To our knowledge, WanToFight is the first generative game engine to combine multi-player control, real-time inference, complex physical interaction, and adversarial gameplay in one system.","authors":["Li Hu","Guangyuan Wang","Peng Zhang","Bang Zhang"],"published":"2026-07-14T10:10:03Z","updated":"2026-07-14T10:10:03Z","abstract_url":"https://arxiv.org/abs/2607.12592v1","html_url":"https://arxiv.org/html/2607.12592v1","pdf_url":"https://arxiv.org/pdf/2607.12592v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12557v1","title":"Gaussian Mixture Modeling for Event-Aware Visual Allocation in Long Video Understanding","abstract":"Large Vision-Language Models (LVLMs) face significant challenges in long video understanding due to the excessive computational cost and information loss associated with uniform sampling. Existing keyframe selection methods often treat video frames as atomic entities and allocate visual budgets equally, thereby overlooking high-level semantic structures and introducing substantial redundancy. To address these limitations, we propose GMM-EVA (Gaussian Mixture Modeling for Event-Aware Visual Allocation), which leverages Gaussian Mixture Models to model event-level structure from discrete frame-wise observations. A differentiated allocation strategy is then applied to preserve one primary high-resolution keyframe per event for high-fidelity detail, while utilizing lower-resolution secondary keyframes to maintain temporal context and optimize token budgets. GMM-EVA is a training-free, plug-and-play framework that generalizes robustly across various relevance measures and downstream LVLMs. Extensive experiments on multiple long video benchmarks demonstrate that our method significantly outperforms uniform sampling. Notably, GMM-EVA achieves comparable performance to baseline selection methods while utilizing only approximately half of the visual token budget, highlighting its superior efficiency and effectiveness.","authors":["Yifan Lu","Ziqi Zhang","Chunfeng Yuan","Jun Gao","Bing Li","Weiming Hu"],"published":"2026-07-14T09:27:25Z","updated":"2026-07-14T09:27:25Z","abstract_url":"https://arxiv.org/abs/2607.12557v1","html_url":"https://arxiv.org/html/2607.12557v1","pdf_url":"https://arxiv.org/pdf/2607.12557v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12556v1","title":"CGRL: Concept-Guided Pruning and Representation Learning for Whole-Slide Image Classification","abstract":"Weakly supervised whole-slide image (WSI) classification is widely used in computational pathology because slide-level labels are easier to obtain than dense region annotations. Existing multiple instance learning (MIL) methods often aggregate large bags of patch embeddings using mainly visual cues, which can retain many non-informative patches and provide weak alignment between instance features and class-level disease semantics. We propose Concept-Guided Pruning and Representation Learning (CGRL), a simple framework that introduces class-level concept prototypes derived from disease prompts into the MIL pipeline. First, concept-relevance pruning ranks patch instances by their similarity to class concepts and retains the top-K concept-relevant patches for downstream MIL aggregation. Second, concept-guided contrastive representation learning constructs class-wise positive and negative patch sets from the same similarity matrix and optimizes target-class, symmetric auxiliary, and cross-class separation objectives, thereby regularizing the projected concept space. We evaluate CGRL on TCGA-BRCA and TCGA-NSCLC using multiple representative MIL methods. Experimental results show that CGRL improves several model-dataset combinations, with gains depending on the downstream MIL model and dataset. It achieves particularly clear improvements in accuracy and macro-F1 while reducing computational cost through concept-relevance pruning. These findings demonstrate that class-level semantic concepts provide an effective and practical prior for patch selection and representation learning in weakly supervised computational pathology.","authors":["Thuc Huynh","Tuan Le","Doanh C. Bui"],"published":"2026-07-14T09:25:52Z","updated":"2026-07-14T09:25:52Z","abstract_url":"https://arxiv.org/abs/2607.12556v1","html_url":"https://arxiv.org/html/2607.12556v1","pdf_url":"https://arxiv.org/pdf/2607.12556v1.pdf","matched_keywords":["representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12539v1","title":"DiTailed: Ensuring Visual Object Consistency in Text-Image-to-Image Flow Matching Models","abstract":"Despite remarkable progress in text-guided image editing, generative models frequently fail to preserve visual object consistency, defined as the preservation of a subject's key attributes throughout the editing process. We address this limitation through three contributions. First, we introduce ABO-Edit, a dataset specifically designed to study object consistency, comprising over 12,000 triplets of source images, editing prompts, and high-quality target images rendered from artist-designed 3D assets, with multi-view coverage and human-verified quality control. Second, we uncover an overlooked property of image-editing rectified flow models: the conditioning embedding space, not directly supervised during training, encodes a prediction of the final generated image even at high noise levels. Third, exploiting this finding, we propose FlowMirror, a parameter-free auxiliary loss that supervises this conditioning embedding space. Without architectural changes, our method improves generation quality across several metrics over baselines.","authors":["Francesco Taioli","Daniel Coelho","Iaroslav Melekhov","Roberto Alcover-Couso","Jose Miguel Grande Saiz","Virginia Fernandez Arguedas","Artur Bekasov"],"published":"2026-07-14T09:09:52Z","updated":"2026-07-14T09:09:52Z","abstract_url":"https://arxiv.org/abs/2607.12539v1","html_url":"https://arxiv.org/html/2607.12539v1","pdf_url":"https://arxiv.org/pdf/2607.12539v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12503v1","title":"DynTrace: Tracking Dynamic Object Evidence for 4D Spatio-Temporal Reasoning in MLLMs","abstract":"4D spatio-temporal reasoning, jointly modeling 3D spatial structure and temporal evolution, is essential for understanding dynamic worlds and enabling embodied interaction. While current Multimodal Large Language Models (MLLMs) show strong capabilities in static scene understanding and coarse-grained 4D tasks, they still have notable limitations in continuous dynamic scene perception, especially in tracking dynamic object evidence for coherent 4D spatio-temporal reasoning. This shortcoming stems mainly from relying on sparse frame-level observations, fragmenting continuous dynamic cues and leaving models unable to disentangle genuine object dynamics from camera-induced apparent motion. Inspired by humans tracking dynamic cues while compensating for viewpoint changes, we propose DynTrace, a training-free framework for 4D spatio-temporal reasoning with two complementary components. Dynamic Trajectory Visualization (DTV) reprojects world-coordinate trajectories onto the image plane, providing geometry-informed visual priors that disentangle genuine object dynamics from camera-induced apparent motion. Meanwhile, the Dynamic Trace Token (DT-Token), organized into a Dynamic Trace Graph (DTG), tracks object-level dynamic cues, trace evolution, and key moments, maintaining continuous dynamic object evidence for coherent 4D reasoning. Together, these two components equip MLLMs with continuously tracked dynamic object evidence, grounded in geometry-informed visual priors and structured spatio-temporal traces. DynTrace consistently improves open-source MLLMs, achieving state-of-the-art results on Dyn-Bench, VLM4D, and DSI-Bench, validating the importance of tracking dynamic object evidence for robust 4D spatio-temporal reasoning.","authors":["Rongxin Gao","Yuzhi Huang","Dongxuan Liu","Chu Li","Zhenye Wang","Jie Wu","Shuzhao Xie","Jingyan Jiang","Xinghao Ding","Xiaotong Tu","Yue Huang"],"published":"2026-07-14T08:35:07Z","updated":"2026-07-14T08:35:07Z","abstract_url":"https://arxiv.org/abs/2607.12503v1","html_url":"https://arxiv.org/html/2607.12503v1","pdf_url":"https://arxiv.org/pdf/2607.12503v1.pdf","matched_keywords":["3d","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12497v1","title":"TerraLogic: A Benchmark for Hierarchical Geospatial Reasoning in Earth Observation","abstract":"Beyond perception, reasoning is essential in remote sensing for advanced interpretation, inference, and decision-making. Recent advances in large language models (LLMs) have enabled tool-augmented agents that leverage external tools to perform complex analytical tasks. However, existing studies in remote sensing primarily focus on perception-oriented tasks, leaving cognitive geospatial reasoning largely underexplored. To address this gap, we introduce TerraLogic, a benchmark for geospatial reasoning. TerraLogic comprises 545 scenario-driven, hierarchy-aware tasks, such as hazard vulnerability assessment, urban heat island analysis, and forest fragmentation dynamics, spanning optical, Synthetic Aperture Radar (SAR), and infrared (IR) imagery. It advances evaluation beyond recognition and monitoring toward cognitive-level geospatial analysis. To facilitate evaluation on TerraLogic, we further propose HieraPlan, a tool-augmented agent that organizes toolkits into functional hierarchies and performs fault-tolerant reasoning. HieraPlan enables structured abstraction, robust recovery from tool failures, and stable long-horizon planning. Extensive experiments demonstrate that current approaches struggle with hierarchical geospatial reasoning, while HieraPlan provides a strong baseline with improved reasoning, cross-modal generalization, and error handling. The dataset and agent code are publicly available at https://github.com/Ireliya/TerraLogic.","authors":["Yuhang Yan","Linchao Mou","Bokang Yang","Qingyu Li"],"published":"2026-07-14T08:30:45Z","updated":"2026-07-14T08:30:45Z","abstract_url":"https://arxiv.org/abs/2607.12497v1","html_url":"https://arxiv.org/html/2607.12497v1","pdf_url":"https://arxiv.org/pdf/2607.12497v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12495v1","title":"RealSkin: Spatio-Spectral Partial Neural Adjoint Maps for Image-to-3D Attribute Transfer","abstract":"Creating photorealistic 3D assets requires bridging the appearance gap between real-world observations and synthetic models. A promising approach is to transfer visual attributes from real images onto synthetic 3D surfaces. Traditional methods struggle with resolution mismatch and the inherent discreteness of point correspondences. In contrast, resolution-robust functional maps enable smooth attribute propagation but rely on near-isometry assumptions and topological consistency. To address these limitations, we propose RealSkin, a self-supervised framework that performs correspondence optimization in a learned spectral domain, guided by spatial correspondences. We first introduce a spatial-guided registration algorithm to establish coarse correspondences under severe topological discrepancies. To relax strict isometric assumptions and handle partial correspondences, we further design a spectral-aware neural adjoint network that incorporates partial correspondences into a neural function space and models non-isometric residuals for correspondence refinement. Experimental results demonstrate that our method achieves state-of-the-art performance on challenging real-to-synthetic scenarios. The code will be publicly released.","authors":["Jing Li","Yawei Luo","Xiangze Meng","Ying Li","Tieru Wu","Rui Ma"],"published":"2026-07-14T08:27:28Z","updated":"2026-07-14T08:27:28Z","abstract_url":"https://arxiv.org/abs/2607.12495v1","html_url":"https://arxiv.org/html/2607.12495v1","pdf_url":"https://arxiv.org/pdf/2607.12495v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12477v1","title":"Self in Space: Benchmarking Self-Awareness and Spatial Cognition in UAV Embodied Intelligence","abstract":"Autonomous UAV systems increasingly rely on multimodal large language models (MLLMs) to operate in complex real-world environments. Such embodied scenarios require not only understanding the surrounding space but also maintaining a coherent representation of the agent itself. However, existing UAV-oriented approaches and benchmarks remain largely environment-centric, primarily focusing on spatial understanding tasks, with the agent's self-awareness remaining implicit. To address this gap, we introduce SIS-Bench, a benchmark for evaluating embodied spatial intelligence in UAV scenarios under a unified self-in-space formulation. SIS-Bench organizes evaluation along two complementary dimensions, space and self, and a three-level hierarchy of perception, memory, and reasoning. It contains 4,856 question--answer pairs across 13 tasks derived from 1,646 real-world UAV videos through a task-conditioned construction pipeline with expert verification.Extensive evaluations reveal that current MLLMs exhibit fundamental limitations in modeling dynamic and agent-centered processes. In particular, we observe a clear imbalance between spatial cognition and self-awareness, as well as a progressive performance degradation across cognitive levels.Motivated by these findings, we further explore a motion-aware representation that incorporates self-related dynamics through optical flow and visual feature fusion. Experimental results show that modeling agent motion consistently improves perception and memory performance, not only in spatial cognition but also in self-awareness, and generalizes to downstream UAV decision-making tasks.Our results highlight the importance of self-awareness for advancing embodied spatial intelligence, and provide both a new benchmark and empirical evidence for motion-aware self-in-space modeling.","authors":["Zhishan Zou","Guoyan Sun","Zhiwei Wei","Jiancheng Pan","Yujie Li","Mugen Peng","Wenjia Xu"],"published":"2026-07-14T08:04:31Z","updated":"2026-07-14T08:04:31Z","abstract_url":"https://arxiv.org/abs/2607.12477v1","html_url":"https://arxiv.org/html/2607.12477v1","pdf_url":"https://arxiv.org/pdf/2607.12477v1.pdf","matched_keywords":["video","agent","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12464v1","title":"Steering Diffusion Models via Class-Contrastive Influence for Few-Shot Medical Classification","abstract":"When labeled data are scarce, off-the-shelf diffusion models can augment training sets for few-shot medical image classification, but not all generated samples are equally useful for the downstream task. Existing approaches largely improve synthetic data by increasing realism, diversity, or domain adaptation, while overlooking a more fundamental question: how should sample usefulness for classification be measured and optimized? We address this with Class-Contrastive Influence (C2I), a criterion that quantifies a sample's usefulness through its gradient-based influence on the classifier. We find that effective samples exhibit a strong C2I gap: their loss gradients align with validation gradients from the same class and oppose those from other classes. Our analysis further suggests that such high-C2I samples are hard, boundary-proximal examples that help refine the decision boundary and improve robustness. Building on this insight, we fine-tune diffusion models with reinforcement learning using a C2I-based reward to steer generation toward class-informative samples. Across several few-shot medical imaging benchmarks, C2I-guided generation improves downstream accuracy and robustness over diffusion-based augmentation baselines, showing that synthetic augmentation is most effective when guided by task usefulness rather than image quality alone.","authors":["Jeeyung Kim","Erfan Esmaeili","Qiang Qiu"],"published":"2026-07-14T07:45:46Z","updated":"2026-07-14T07:45:46Z","abstract_url":"https://arxiv.org/abs/2607.12464v1","html_url":"https://arxiv.org/html/2607.12464v1","pdf_url":"https://arxiv.org/pdf/2607.12464v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12433v1","title":"ARDepth: Auto-regressive Monocular Depth Estimation with Progressive Visual Conditioning","abstract":"Diffusion models have recently become the dominant paradigm for monocular depth estimation (MDE). However, they implicitly assume that depth can be recovered as a globally smooth field through iterative denoising, which does not explicitly reflect the piecewise and scale-dependent organization of scene geometry. In practice, geometric structure emerges progressively across spatial scales, where coarse layout, surfaces, and boundaries are constructed in a hierarchical manner. Motivated by this observation, we introduce ARDepth, which formulates depth estimation as structured auto-regressive generation. Instead of recovering depth through global refinement, ARDepth progressively constructs depth representations as spatial resolution increases. To support this generative process, we introduce Scale-Progressive Conditioning (SPC) to inject multi-scale visual features at each generation stage, and Semantic-Aware Guidance (SAG) to provide scene-level semantic priors that enhance global structural consistency. Together, these designs enable the model to capture fine-grained local details while maintaining coherent global geometry. Empirical results demonstrate that our approach achieves strong performance and produces structurally consistent depth predictions across scales, validating auto-regressive generation as a promising alternative paradigm for geometric modeling.","authors":["Zijie Wang","Wei Zhang","Weiming Zhang","Xiao Tan","Weikai Chen","Xiaoxu Li","Guanbin Li"],"published":"2026-07-14T07:06:46Z","updated":"2026-07-14T07:06:46Z","abstract_url":"https://arxiv.org/abs/2607.12433v1","html_url":"https://arxiv.org/html/2607.12433v1","pdf_url":"https://arxiv.org/pdf/2607.12433v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12429v1","title":"More Than Where You Are: Learning Semantics, Structure, and Geometry from Cross-View Localization","abstract":"Consistent cross-view understanding under extreme viewpoint changes is essential for spatial intelligence, as it enables models to recognize the same scene across extreme viewpoint gaps. Cross-view localization naturally provides a promising pathway toward this ability, as it requires a model to align ground-view imagery with geo-referenced satellite-view imagery despite drastic appearance changes to estimate camera poses. Recent visual foundation models have made this long-standing localization problem increasingly feasible by providing rich 2D representations for cross-view matching. However, we argue that cross-view localization should not be viewed merely as 2D matching or pose estimation. In this work, we revisit cross-view localization as more than pose estimation and investigate how it can help the model develop consistent cross-view understanding under extreme viewpoint changes, including stable semantics, reliable structure, and transferable geometry. We identify three key limitations of existing methods that prevent them from achieving this. They usually lack explicit 3D grounding, rely on strict point-wise matching that can weaken semantic consistency, and learn from an absolute objective that provides limited guidance for geometric reasoning. To address these limitations, we propose CROSS, a unified cross-view localization framework built upon 3D-grounded alignment, structure-aware matching, and hypothesis ranking. This formulation makes structure learning an intrinsic requirement, encourages semantic representations to remain stable, and enables the model to acquire transferable geometry. Extensive experiments on the KITTI and VIGOR datasets show that CROSS achieves state-of-the-art performance in cross-view localization. More importantly, CROSS effectively learns stable semantics, reliable structure, and transferable geometry across extremely different viewpoints.","authors":["Mao Chen","Xiangkai Zhang","Zhiyong Liu","Chuankai Liu","Xu Yang"],"published":"2026-07-14T07:00:34Z","updated":"2026-07-14T07:00:34Z","abstract_url":"https://arxiv.org/abs/2607.12429v1","html_url":"https://arxiv.org/html/2607.12429v1","pdf_url":"https://arxiv.org/pdf/2607.12429v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12419v1","title":"DeGuNet: Depth-Guided Ultra-Compact Backbones for Efficient LiDAR-Camera 3D Detection","abstract":"In autonomous driving perception, the fusion of LiDAR and camera modalities has become the dominant paradigm for 3D object detection. However, current multi-modal frameworks heavily rely on massive visual backbones pretrained on 2D semantic tasks. This reliance introduces substantial parameter redundancy and a structural misalignment, as 2D priors are ill-equipped to handle the extreme sparsity of LiDAR projections required for Bird's-Eye-View geometry. To address this, we present DeGuNet, an ultra-compact and plug-and-play image backbone explicitly designed for depth-guided representation learning. By incorporating sparsity-aware feature extraction mechanisms, DeGuNet effectively aligns multi-view images with unstructured LiDAR depth while strictly preventing invalid-region contamination. Extensive experiments on the nuScenes dataset demonstrate DeGuNet's broad plug-and-play applicability and superior efficiency. When integrated into established baselines, it fundamentally eliminates architectural redundancy, reducing GPU memory consumption by up to 66.5% and achieving a 1.16x inference speedup. Concurrently, DeGuNet delivers up to a 6.20 absolute mAP gain, establishing a new paradigm for parameter-efficient multi-modal 3D perception.","authors":["Haifa Zhang","Yijing Wang","Peixi Peng","Zhiqiang Zuo"],"published":"2026-07-14T06:46:30Z","updated":"2026-07-14T06:46:30Z","abstract_url":"https://arxiv.org/abs/2607.12419v1","html_url":"https://arxiv.org/html/2607.12419v1","pdf_url":"https://arxiv.org/pdf/2607.12419v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12418v1","title":"MQAdapter: Multi-Modal Quantum Adapter for Coarse-to-Fine VLM Fine-tuning","abstract":"Large-scale Vision-Language Models have demonstrated impressive transfer learning capabilities across a wide range of tasks. For few-shot classification, we observe that VLMs exhibit a notable ability to filter candidate categories and thus achieve high Top-K accuracy. However, they often struggle with fine-grained discrimination among visually similar categories, resulting in unsatisfactory Top-1 performance, as shown in Figure 1. Existing studies on VLM adapters generally focus on global alignment between visual and textual representations in the feature space, but fail to exploit semantically similar categories to refine fine-grained visual representations. Based on these observations, we propose a novel coarse-to-fine VLM fine-tuning approach for few-shot learning that leverages quantum computation, termed the Multi-Modal Quantum Adapter (MQAdapter). Specifically, MQAdapter first retrieves the Top-K category candidates most similar to the input image and uses them as semantic anchors. It then employs a cross-modal quantum learning mechanism to refine visual features under the guidance of these anchors. The core of this mechanism is the encoding of visual and textual features into quantum states. By leveraging quantum entanglement and superposition in a high-dimensional Hilbert space, MQAdapter effectively models higher-order cross-modal interactions, producing more discriminative representations than traditional Euclidean adapters. MQAdapter is parameter-efficient and can be integrated with various existing fine-tuning algorithms to achieve further performance gains. Evaluations on 15 datasets demonstrate the effectiveness of MQAdapter while requiring fewer trainable parameters.","authors":["Yumiao Zhao","Bo Jiang","Min Lu","Xiao Wang","Jin Tang"],"published":"2026-07-14T06:46:24Z","updated":"2026-07-14T06:46:24Z","abstract_url":"https://arxiv.org/abs/2607.12418v1","html_url":"https://arxiv.org/html/2607.12418v1","pdf_url":"https://arxiv.org/pdf/2607.12418v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12404v1","title":"Contrastive-Augmented Flow Matching for Style-Content Disentanglement","abstract":"Learning representations that separate content and style is crucial for controllable generation and compositional generalization. However, diffusion and flow-based models trained primarily with generative objectives often produce entangled or misaligned factors. To address this gap, we introduce Contrastive Augmented Flow Matching (CAtFM), a framework that integrates contrastive regularization into an invertible flow matching formulation to promote structured content-style representations. Rather than constraining intermediate latents or velocity fields, we apply contrastive supervision to predicted endpoints during training, enforcing semantic consistency across transported distributions while allowing disentanglement to emerge implicitly, without assuming strictly pure or fully factorized content and style representations. Our main experiments operate in the CLIP embedding space, with additional validation using frozen DINO and ALIGN encoders. Across synthetic data, in-domain styles, and real-world benchmarks (ImageNet, WikiArt, DomainNet, and DTD), CAtFM improves content and style retrieval, enhances embedding cluster separation, and achieves stronger open-set robustness compared to generative and discriminative baselines. Overall, CAtFM provides a simple way to couple discriminative constraints with deterministic transport, improving disentanglement and robustness under distribution shift.","authors":["Yusong Li","Pingchuan Ma","Ming Gui","Vincent Tao Hu","Björn Ommer"],"published":"2026-07-14T06:23:52Z","updated":"2026-07-14T06:23:52Z","abstract_url":"https://arxiv.org/abs/2607.12404v1","html_url":"https://arxiv.org/html/2607.12404v1","pdf_url":"https://arxiv.org/pdf/2607.12404v1.pdf","matched_keywords":["retrieval","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12379v1","title":"SeamGen: Artist-Aligned UV Seam Generation via Graph Flow Matching","abstract":"UV seam placement is a critical yet labor-intensive step in 3D content creation, requiring artists to balance chart shape, seam concealment, and alignment with semantic and geometric features. Existing automatic methods are primarily based on per-object optimization, relying on handcrafted objectives to avoid distortion or on proxies from pretrained models to inject semantic information. However, these strategies are not always well aligned with seams used in industrial production pipelines, often resulting in layouts that deviate from artist-preferred seam patterns and practical production requirements. To address these limitations, we propose SeamGen, a generative model for UV seam generation that aligns with artist preferences and production requirements. Instead of depending on manually designed objectives and constraints, SeamGen learns the distribution of per-edge seam labels from a large corpus of existing seam layouts using a flow-matching generative model. A key challenge is that typical Transformer architectures used in flow matching models are designed for sequential representations, such as point clouds, and cannot naturally account for mesh topology. To enable mesh-native learning, we design a Mesh Transformer backbone that interleaves local graph attention over mesh edges with global self-attention across vertices, capturing both fine-grained geometric cues and long-range topological coherence. To further improve inference-time controllability and quality, we exploit the training-free inpainting capability of flow models for both localized seam refinement and constraint-guided seam generation. Extensive experiments show that by learning priors from professional seam layout data, SeamGen produces UV layouts that better align with artist-authored preferences and achieve superior perceptual quality compared with distortion-based and semantic-proxy baselines.","authors":["Hao Xu","Yuqing Zhang","Yiqian Wu","Xueqi Ma","Ding Liang","Yan-Pei Cao","Ying-Tian Liu","Xiaogang Jin"],"published":"2026-07-14T05:52:52Z","updated":"2026-07-14T05:52:52Z","abstract_url":"https://arxiv.org/abs/2607.12379v1","html_url":"https://arxiv.org/html/2607.12379v1","pdf_url":"https://arxiv.org/pdf/2607.12379v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12376v1","title":"Demonstration of the common dual-channel feature decoupling characteristic of front-door mediation causal inference methods in whole-slice image classification","abstract":"Causal inference using front door intervention and multi-instance learning (MIL) has advanced the analysis of Whole Slide Images (WSI) in digital pathology. These methods adjust feature distributions of subtle evidence sub-images to correctly associate them with WSI-level diagnoses. We propose and prove 2 hypotheses for evaluating such methods: 1) Causal inference MIL introduces an independent classification channel that effectively completes WSI classification; 2) Greater difference between features extracted by the new and baseline channels increases effectiveness in eliminating false correlations. This hypothesis describes the core of causal inference MILs: overlaying parallel, independent channels to eliminate false associations between WSI-level diagnostic and non-diagnostic evidence sub-images by increasing deep feature diversity. Based on these hypotheses, we evaluated several causal inference MILs on breast cancer and non-small cell lung cancer datasets. This hypothesis provides a new theoretical perspective for applying causal inference to WSI analysis.","authors":["Zhirui Zhang","Tianhang Nan","Yong Ding","Zhuolun Song","Dayu Hu","Xiaoyu Cui"],"published":"2026-07-14T05:49:34Z","updated":"2026-07-14T05:49:34Z","abstract_url":"https://arxiv.org/abs/2607.12376v1","html_url":"https://arxiv.org/html/2607.12376v1","pdf_url":"https://arxiv.org/pdf/2607.12376v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12375v1","title":"IQA-T1: Tool-based Visual Evidence Reasoning for Image Quality Assessment","abstract":"Image Quality Assessment (IQA) in open-world environments remains challenging due to limited generalization and interpretability. Recent approaches based on multimodal large language models (MLLMs) introduce textual reasoning for quality prediction, yet their judgments rely heavily on semantically biased internal representations, making them insensitive to low-level perceptual degradations. We propose IQA-T1, a tool-based visual evidence reasoning framework that augments MLLM reasoning with explicit perceptual observations. During inference, the model autonomously invokes specialized analysis tools to generate structured visual evidence, such as noise residual maps, gradient statistics, and frequency spectra, which are progressively integrated into the reasoning process. To support this paradigm, we construct Q-Tool, a dataset containing 11k multimodal reasoning chains grounded in tool-generated evidence. Extensive experiments on seven IQA benchmarks show that IQA-T1 achieves the best overall performance across datasets while producing interpretable and evidence-grounded quality assessments. Code and dataset are available at https://github.com/zibuyu-02/IQA-T1.","authors":["Jinjian Wu","Jiaqi Tang","Wei Wei","Yingying Yan","Jianmin Chen","Botong Geng","Lei Zhang","Qifeng Chen"],"published":"2026-07-14T05:47:32Z","updated":"2026-07-14T05:47:32Z","abstract_url":"https://arxiv.org/abs/2607.12375v1","html_url":"https://arxiv.org/html/2607.12375v1","pdf_url":"https://arxiv.org/pdf/2607.12375v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12372v1","title":"UMSS: Towards Unsupervised Multi-modal Semantic Segmentation","abstract":"Multimodal semantic segmentation (MSS) is essential for robust perception in complex environments, yet its potential remains largely untapped because of the prohibitive cost of human annotations. While unsupervised semantic segmentation (USS) has achieved strong results on a single RGB modality, its naive extension to multimodal data is often hindered by fusion degradation. This occurs because, without explicit supervision, existing frameworks struggle to reconcile the heterogeneous structural patterns captured by different sensors and therefore fail to effectively exploit their complementary information. In this paper, we make the first attempt to address the novel problem of Unsupervised Multimodal Semantic Segmentation (UMSS), aiming to effectively exploit complementary sensor information in a fully label free setting. To this end, we propose UniM2 (Unified Multimodal), a novel framework built on DINOv3 that transforms conventional fusion methods into consistent performance gains. Our key idea is to learn a unified latent space driven by Cross Modal Correspondence Synergy (CMCS) to extract intrinsic shared semantic cues, bypassing the need for label guided adaptive fusion. To mitigate inherent intermodal conflicts, we introduce a Cross Modal Harmonizer (CMH) that designates RGB as a stable reference, effectively suppressing inconsistent relational supervision while guiding the model to exploit complementary structural features. Extensive experimental results on NYU Depth v2 and MFNet show that UniM2 improves mIoU by 6.4% and 9.8%, respectively, demonstrating clear advantages over existing frameworks for UMSS.","authors":["Haitian Zhang","Thai Duy Nguyen","Xiangyuan Wang","Mohan Liu","Lin Wang"],"published":"2026-07-14T05:44:29Z","updated":"2026-07-14T05:44:29Z","abstract_url":"https://arxiv.org/abs/2607.12372v1","html_url":"https://arxiv.org/html/2607.12372v1","pdf_url":"https://arxiv.org/pdf/2607.12372v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12364v1","title":"Lost in Visual Translation: A VLM-Assisted Perceptual-Semantic Coherence Framework for EEG-to-Image Reconstruction","abstract":"EEG-to-image evaluation should distinguish visual fidelity from recoverable meaning. Yet EEG-derived reconstructions are blurry, distorted, and low-detail, causing SSIM, LPIPS, and CLIP to penalize semantically recoverable outputs or reward plausible but incorrect ones. We analyze 6,855 ground-truth/reconstruction pairs from ATM, ENIGMA, BrainVis, and DreamDiffusion using semantic probes, caption harshness and blind-spot rates, and controlled degradations. Pixel metrics show near-zero correlation with semantic consistency, while representation metrics conflate perceptual and semantic errors. We therefore introduce a BCI-aware framework in which four VLMs assess image pairs through structured questions, producing Tolerant Perceptual Alignment Scores (T-PAS) and Tolerant Semantic Alignment Scores (T-SAS). Their consensus is distilled into the BCI-Coherence Score (BCS), a compact evaluator achieving a T-PAS MAE of 0.079 (r = 0.700) and a T-SAS MAE of 0.082 (r = 0.850) on our data. Human validation shows highly reliable joint coherence judgments, with Cohen's kappa = 0.882 +/- 0.174 and Krippendorff's alpha = 0.882, supporting perceptual-semantic recoverability over generic visual similarity. Code and resources are available at https://sukt03.github.io/BCS/.","authors":["Sukriti Tiwari","BHVSP Subrahmanyam","Nidhi Goyal","Sai Amrit Patnaik"],"published":"2026-07-14T05:40:23Z","updated":"2026-07-14T05:40:23Z","abstract_url":"https://arxiv.org/abs/2607.12364v1","html_url":"https://arxiv.org/html/2607.12364v1","pdf_url":"https://arxiv.org/pdf/2607.12364v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12362v1","title":"Implicit 4D Gaussian Splatting for Fast Motion with Large Inter-Frame Displacements","abstract":"Recent 4D Gaussian Splatting (4DGS) methods often fail under fast motion with large inter-frame displacements, where Gaussian attributes are poorly learned during training, and fast-moving objects are often lost from the reconstruction. In this work, we introduce Spatiotemporal Position Implicit Network for 4DGS, coined SPIN-4DGS, which learns Gaussian attributes from explicitly collected spatiotemporal positions rather than modeling temporal displacements, thereby enabling more faithful splatting under fast motions with large inter-frame displacements. To avoid the heavy memory overhead of explicitly optimizing attributes across all spatiotemporal positions, we instead predict them with a lightweight feed-forward network trained under a rasterization-based reconstruction loss. Consequently, SPIN-4DGS learns shared representations across Gaussians, effectively capturing spatiotemporal consistency and enabling stable high-quality Gaussian splatting even under challenging motions. Across extensive experiments, SPIN-4DGS consistently achieves higher fidelity under large displacements, with clear improvements in PSNR and SSIM on challenging sports scenes from the CMU Panoptic dataset. For example, SPIN-4DGS notably outperforms the strongest baseline, D3DGS, by achieving +1.83 higher PSNR on the Basketball scene.","authors":["Seung-gyeom Kim","Areum Kim","Yongjae Yoo","Sukmin Yun"],"published":"2026-07-14T05:33:05Z","updated":"2026-07-14T05:33:05Z","abstract_url":"https://arxiv.org/abs/2607.12362v1","html_url":"https://arxiv.org/html/2607.12362v1","pdf_url":"https://arxiv.org/pdf/2607.12362v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12358v1","title":"ACID: Adaptive Caching for vIDeo generation","abstract":"Video diffusion models produce high-quality generations but remain slow at inference due to their sequential denoising procedure. Caching-based acceleration methods address this by reusing intermediate model outputs: leading dynamic approaches such as TeaCache, EasyCache, and DiCache accumulate a drift signal and skip expensive model evaluations when accumulated drift stays below a fixed threshold τ. This threshold controls an apparent tradeoff - raising it yields faster generation at the cost of visual quality, while lowering it preserves quality but sacrifices speed. We show this tradeoff is not fundamental; it is an artifact of holding τ constant throughout denoising. We identify the existence of critical steps - timesteps where the drift signal changes rapidly - and show that applying a low threshold selectively at these steps while caching aggressively elsewhere recovers most of the quality of conservative caching at substantially higher inference speeds. Building on this insight, we propose ACID, a lightweight, training-free wrapper that monitors the rate of change of each method's existing drift signal to dynamically switch between a low and a high threshold. ACID is signal-agnostic and modular: it requires no retraining and plugs directly into existing dynamic caching methods without modifying their core mechanisms. Evaluated across three caching methods (TeaCache, EasyCache, DiCache) and three open-source video diffusion models (HunyuanVideo, Wan 2.1, CogVideoX), ACID consistently expands the Pareto frontier of visual quality versus inference speed beyond what any fixed threshold achieves. In particular, on TeaCache and HunyuanVideo, ACID achieves up to 2.16x speedup over the no-caching baseline, and up to 38% additional speedup over the conservative fixed-threshold baseline with negligible (<0.3 dB PSNR, <0.01 SSIM, <0.01 LPIPS) quality degradation.","authors":["Om Agrawal","Saurabh Agarwal","Aditya Akella"],"published":"2026-07-14T05:17:24Z","updated":"2026-07-14T05:17:24Z","abstract_url":"https://arxiv.org/abs/2607.12358v1","html_url":"https://arxiv.org/html/2607.12358v1","pdf_url":"https://arxiv.org/pdf/2607.12358v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12335v1","title":"ProtoPointNet: Prototype-Based Interpretable Classification of 3D Dental Point Clouds with Verifiable Spatial Activations","abstract":"Prototype-based networks provide inherently interpretable classification by linking predictions to learned exemplars, but their use in 3D point clouds and clinical surface-pair reasoning remains limited. We introduce ProtoPointNet, a prototype-based model for dental occlusion classification from registered upper--lower intraoral arch pairs. Each point is encoded by a 14-dimensional descriptor combining local surface geometry, curvature, and explicit inter-arch displacement and clearance, exposing occlusal relationships to prototype matching. A shared multi-task point-cloud backbone learns axis-specific prototype heads for sagittal-left, sagittal-right, vertical, transverse, and midline classification. To support limited clinical data, we train prototypes from scratch using auxiliary supervision and encoder-freeze hand-off. On Bits2Bites, ProtoPointNet achieves mean test macro-F1 of 0.724 and AUROC of 0.825, with strongest performance on vertical (F1 0.828) and sagittal-left classification (F1 0.807). Projected prototype activations localise to anatomically plausible regions, including posterior molars and premolars for cross-bite evidence and anterior incisors for bite-depth evidence. These results support prototype-based reasoning as a transparent, spatially grounded alternative to black-box 3D classifiers for dental surface-pair analysis.","authors":["George V. Jose","Thao Liang Chiam","Toby Hughes","Dilan Patel","Alan Brook","Lyle J. Palmer","Nikhil Cherian Kurian"],"published":"2026-07-14T04:30:09Z","updated":"2026-07-14T04:30:09Z","abstract_url":"https://arxiv.org/abs/2607.12335v1","html_url":"https://arxiv.org/html/2607.12335v1","pdf_url":"https://arxiv.org/pdf/2607.12335v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12319v1","title":"DM-KG: A Novel Method for Boosting Spatial Cognition of Vision-Language Models in Street View Imagery","abstract":"As vision-language models (VLMs) are increasingly deployed in geospatial question answering and visual scene understanding, improving their spatial cognition capability on street view imagery for complex logical reasoning has emerged as a key research priority. However, existing VLMs frequently suffer from \"spatial semantic hallucinations\" when perceiving object locations, distances, and directions in real-world street view scenes. Furthermore, such errors are often recalcitrant to tracing and calibration, posing a critical bottleneck for their practical deployment in geospatial tasks. To address this pressing challenge, this study proposes DM-KG (Direction-Metric Knowledge Graph), a structurally grounded spatial representation framework for street view imagery. By explicitly extracting directional and metric relationships between entities from a single 2D image, this framework enhances the spatial reasoning accuracy of VLMs through a structured knowledge graph. Specifically, we integrate panoptic segmentation with metric depth estimation to robustly compute entity-level 3D spatial coordinates. Subsequently, we encode the clock azimuths and Euclidean distances of entity pairs into a JSON-formatted knowledge graph, which is injected into the VLM as an explicit geometric prior to guide spatial reasoning. Experimental results on public spatial question-answering (QA) benchmarks demonstrate that DM-KG reduces the mean absolute error (MAE) in distance estimation by 31.1% and the mean angular error in direction judgment by 65.8%, while simultaneously maintaining a high QA success rate. By establishing a complete, augmented reasoning pipeline, this research significantly improves the spatial cognitive capabilities of VLMs in street view scenarios, thereby providing a flexible, generalized, and interpretable framework for geographic visual question answering (GeoVQA) in open environments.","authors":["Xinyue Xu","Zheng Zhang","Kunyang Ma","Ge Zhu","Lianshuai Cao","Lei Wang","Zixuan Li","Yi Cheng"],"published":"2026-07-14T03:52:37Z","updated":"2026-07-14T03:52:37Z","abstract_url":"https://arxiv.org/abs/2607.12319v1","html_url":"https://arxiv.org/html/2607.12319v1","pdf_url":"https://arxiv.org/pdf/2607.12319v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12304v1","title":"What Does a Temporal Benchmark Score Measure? Decomposing Channel Use in Video VLM Evaluation","abstract":"A score on a temporal video question answering benchmark is meant to measure that a model has temporal understanding, but it conflates two questions. 1. The task question: is the question even temporal, does it need several frames and their order? and 2. The channel question, when it does, does the model recover the order from the pixels, or read it off the positional encoding (RoPE)? Most of a temporal score answers neither, a single frame and answer priors often carry it. The field's validity checks, frame-shuffle sensitivity and the accuracy gained from the full video, speak only to the task question. We contribute a label-free screen for the channel question, the reversal-drop: the accuracy lost when the visual sequence is reversed while RoPE remains forward. It can be applied to compatible temporal benchmarks without new annotations. Paired reverse labels, or tasks whose labels transform deterministically under reversal, distinguish models that follow reversed content from those merely disrupted by the conflict. Molmo2 answers the forward event reading order off positions, while Qwen3-VL answers the reversed event it actually sees, reading visual order (comparatively). We call them position-dominant and visual-sequence-dominant. The split holds across two benchmarks and several temporal tasks at two scales, and activation patching shows it is a real internal property, not an artifact of the conflict. The distinction matters, the two channels fail on opposite inputs so two models with similar score are not interchangable, i.e. an aggregate score does not reflect potential failure modes.","authors":["Farrukh Rahman"],"published":"2026-07-14T03:26:33Z","updated":"2026-07-14T03:26:33Z","abstract_url":"https://arxiv.org/abs/2607.12304v1","html_url":"https://arxiv.org/html/2607.12304v1","pdf_url":"https://arxiv.org/pdf/2607.12304v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12297v1","title":"MobileSAM2: Lightweight Segment Anything for Spatial Intelligence","abstract":"The recent large video foundation model, SAM2, enables segment anything in both images and videos, serving as a powerful base model for various applications. However, many of such use cases require to operate on resource-constrained devices like mobile phones and laptops. In this work, we aim to make SAM2 more mobile-friendly by distilling the heavyweight SAM2 into a lightweight model, facilitating segment anything in both images and videos on mobile devices. To this end, we propose Hypergraphical Knowledge Distill (HyperKD), which introduces the idea of hypergraph into knowledge distillation, aiming to effectively model and transfer SAM2's generalizable and comprehensive knowledge. HyperKD consists of Temporal HyperKD and Granularity HyperKD that construct hypergraphs to explicitly model and extract the generalizable temporal knowledge and the comprehensive multi-granularity knowledge from SAM2 respectively, which are then distilled into the lightweight student model by aligning it with the constructed hypergraphs. Besides, we present MobileSAM2, a new family of lightweight SAM2 that balances efficiency and effectiveness via searching the best model architectures with HyperKD during model size reduction. Extensive experiments validate MobileSAM2 across multiple benchmarks and show promising generalization performance on embodied AI tasks.","authors":["Kai Jiang","Jiaxing Huang","Jingyi Zhang","Weiying Xie","Yunsong Li","Yufei Wang","Aoran Xiao","Dacheng Tao"],"published":"2026-07-14T03:10:11Z","updated":"2026-07-14T03:10:11Z","abstract_url":"https://arxiv.org/abs/2607.12297v1","html_url":"https://arxiv.org/html/2607.12297v1","pdf_url":"https://arxiv.org/pdf/2607.12297v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12293v1","title":"Adaptive Cross-Modal Fusion with Sparse Attention for Pedestrian Crossing Intention Prediction","abstract":"Predicting pedestrian crossing intention is a safety-critical task for autonomous driving, yet existing approaches often rely on single-modal inputs or dense multimodal fusion strategies that inadequately capture complementary visual and kinematic information while introducing redundant inter-modal interactions. We propose ADAPT (Adaptive Domain-Aware Pedestrian Crossing Transformer), a multimodal framework that jointly models local and global visual context together with temporal motion dynamics for accurate pedestrian crossing intention prediction. ADAPT processes four spatially aligned visual modalities, including RGB images, local depth maps, global semantic maps, and global depth maps, together with ego-vehicle speed, pedestrian bounding boxes, and skeleton pose information through five specialized modules: a weight-shared Swin Transformer V2 backbone for visual feature extraction, a Cross-Modality Guided Attention module for hierarchical visual fusion, a Mamba-based Motion Feature Encoding module for efficient temporal modeling, a Sparse Cross-Modal Attention module that selectively preserves the most informative inter-modal interactions, and a Vision Transformer-based Temporal Feature Fusion module for sequence-level prediction. Extensive experiments on the JAAD and PIE benchmark datasets demonstrate that ADAPT consistently outperforms existing state-of-the-art methods while maintaining low computational complexity. On JAAD, the proposed method achieves an AUC of 0.73 on JAADbeh and 0.85 on JAADall, while on PIE it achieves an accuracy of 0.92 and an AUC of 0.90. Furthermore, ADAPT performs inference in only 17.23 ms per sample, offering an effective balance between predictive accuracy and real-time deployment efficiency for intelligent transportation and autonomous driving applications.","authors":["Md Mahfuzur Rahman","Pengzhan Zhou","A F M Abdun Noor","Md Imam Ahasan","Kah Ong Michael Goh","S. M. Hasan Mahmud","Md Mustafizur Rahman","Kaixin Gao"],"published":"2026-07-14T03:05:09Z","updated":"2026-07-14T03:05:09Z","abstract_url":"https://arxiv.org/abs/2607.12293v1","html_url":"https://arxiv.org/html/2607.12293v1","pdf_url":"https://arxiv.org/pdf/2607.12293v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12278v1","title":"Auditing Data Leakage in Whole-Slide Image Multimodal Benchmarks","abstract":"Recent vision-language models (VLMs) for computational pathology report striking zero-shot performance on whole-slide image (WSI) visual question answering (VQA) benchmarks. We audit these claims and find them fundamentally compromised by data leakage at two hierarchical levels: patient-level leakage, where slides from the same case appear in both training and test folds, and institutional-level leakage, where different cases nonetheless share staining-batch and scanner signatures through a common Tissue Source Site (TSS). By tracing canonical slide, case, and TSS identifiers across major public resources, we document case level train test overlaps of 92.3~100% on TCGA-derived benchmarks, together with near-complete TSS overlap. We further demonstrate that both leakage levels are linearly decodable from foundation-model feature space, that they induce a measurable accuracy gap between leaked and audit-clean cases on a published checkpoint, and that across multiple published WSI VLMs, peak reported accuracies concentrate on the most heavily contaminated benchmarks. Therefore, the current WSI VQA evaluation cannot distinguish genuine multimodal reasoning from nearest-neighbor retrieval over memorized institutional and patient-specific artifacts. Finally, we outline concrete recommendations for contamination-free evaluation. By addressing benchmark construction, provenance disclosure, and automated overlap auditing, we aim to guide future research toward verifiable claims of progress.","authors":["Wenhao Zhang","Zhongliang Zhou","John Kang","Sheng Li"],"published":"2026-07-14T02:28:29Z","updated":"2026-07-14T02:28:29Z","abstract_url":"https://arxiv.org/abs/2607.12278v1","html_url":"https://arxiv.org/html/2607.12278v1","pdf_url":"https://arxiv.org/pdf/2607.12278v1.pdf","matched_keywords":["retrieval","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12254v1","title":"How to Realize Recursively Self-Improving Agents and Personal Singularity: A Goal-, Scope-, Tool-, and Benchmark-Driven Multi-Agent Architecture","abstract":"Large language model (LLM) agents can increasingly plan, use tools, maintain memory, and execute long-horizon tasks. These advances motivate two linked questions: how can an agent improve the mechanisms by which it learns and acts, and how can that improvement increase the durable capabilities of its user rather than only the software itself? This paper proposes a governed multi-agent architecture for recursively self-improving agents and introduces personal singularity as a bounded human-AI co-development objective: helping a user approach an expanding, user-defined capability frontier across selected domains. Each agent is defined by a goal contract, bounded scope, validated tool registry, tool-level tests, end-to-end benchmarks, an owner-controlled autonomy policy, a routing policy, memory, and an improvement policy. Out-of-scope tasks are transferred to another accountable agent or to a newly created niche agent. A user-facing Auto-Index selects interactive, hybrid, autonomous, or scheduled operation without overriding external permissions. The architecture combines a fast planner-executor-verifier loop, a slower evidence-gated improvement loop, an external governance plane, decentralized agent lineages, an owner-directed agent foundry, and a Personal Singularity OS coordinating working, computational-imaging, process-learning, and personal-learning agents. We formalize scope, routing, improvement acceptance, bounded goal evolution, tool-first execution, and human capability transfer, and provide safety invariants, benchmark design, and an implementation roadmap. This is a position and systems-design paper, not evidence that unrestricted recursive self-improvement or personal singularity has already been achieved.","authors":["Chengshuai Yang"],"published":"2026-07-14T01:44:53Z","updated":"2026-07-14T01:44:53Z","abstract_url":"https://arxiv.org/abs/2607.12254v1","html_url":"https://arxiv.org/html/2607.12254v1","pdf_url":"https://arxiv.org/pdf/2607.12254v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12231v1","title":"The GEST-Engine: From Event Graphs to Synthetic Video. A Full Technical Report","abstract":"We present the GEST-Engine, a complete system that goes from natural-language text to fully-annotated multi-actor video. At its core is an explicit world model: rather than encoding state as a learned latent, the engine maintains a complete, inspectable representation of the world (which actors exist, where they are, what they are doing, which objects they hold, and how events relate in time and space), expressed as a formal Graph of Events in Space and Time (GEST) and realized deterministically inside the open world of a commercial game engine driven through an open-source multiplayer scripting framework. GESTs are produced either procedurally or by an agentic text-to-GEST system in which an LLM Director plans a story through tool calls validated by a programmatic state backend, so every generated specification is executable by construction. A GEST then enters a four-stage execution pipeline: graph parsing and validation, entity and action grounding, temporal orchestration (Allen-style constraints resolved by Floyd-Warshall transitive closure), and execution and capture. In a single simulation pass the engine emits frame-aligned RGB video, dense per-pixel depth, instance segmentation, per-actor skeletal pose, per-frame pairwise spatial-relation graphs, 2D bounding boxes, event-to-frame temporal mappings, and natural-language descriptions, all at zero marginal annotation cost. We further describe an in-game world editor, runtime capability extraction, a text-generation pipeline, and a production system that renders corpora at scale across parallel virtual machines. Because every frame traces back to a semantic specification, the engine guarantees object permanence, multi-actor coordination, and temporal consistency by construction, making its output valuable as training data, evaluation benchmarks, and diagnostic tools for video understanding.","authors":["Nicolae Cudlenco","Mihai Masala","Marius Leordeanu"],"published":"2026-07-14T00:25:00Z","updated":"2026-07-14T00:25:00Z","abstract_url":"https://arxiv.org/abs/2607.12231v1","html_url":"https://arxiv.org/html/2607.12231v1","pdf_url":"https://arxiv.org/pdf/2607.12231v1.pdf","matched_keywords":["video","agent","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12206v1","title":"RegHead: Non-Humanoid Head Blendshapes via Feed-Forward Registration","abstract":"We present RegHead, a framework for constructing semantic blendshape sets for animatable non-humanoid head avatars. With a fixed expression vocabulary, semantic blendshapes provide a low-dimensional and interpretable animation interface and support cross-identity retargeting. Building such blendshape sets remains expensive because (i) expression-consistent supervision is scarce, (ii) generated 4D assets typically lack correspondence, and (iii) facial motion is highly localized. We propose (1) a large-scale dataset of non-humanoid identities paired with a shared expression vocabulary, obtained by expanding a small artist-rigged library via fine-tuned image editing; (2) a dense stochastic anchor motion representation tailored to localized facial deformations; and (3) a fast feed-forward registration model that converts unregistered expression meshes into a corresponded blendshape basis by predicting anchor-based deformations from the neutral shape. Experiments show that our approach produces higher-fidelity expression meshes than baselines, while running orders of magnitude faster than optimization. We further demonstrate real-time retargeting from human face tracking signals to non-humanoid characters, capturing both head pose and localized facial motions. Our project page is available at https://snap-research.github.io/RegHead/.","authors":["Jiahao Luo","Hao Zhang","Jianqi Chen","Yijie He","Jiaxu Zou","Michael Vasilkovsky","Sergei Korolev","Sergey Tulyakov","Chaoyang Wang","Peter Wonka","James Davis","Jian Wang"],"published":"2026-07-13T23:16:29Z","updated":"2026-07-13T23:16:29Z","abstract_url":"https://arxiv.org/abs/2607.12206v1","html_url":"https://arxiv.org/html/2607.12206v1","pdf_url":"https://arxiv.org/pdf/2607.12206v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12193v1","title":"Compos3D: Interactive Part-Based Composition for Creative Control in Generative 3D Models","abstract":"While generative AI has unlocked new opportunities for 3D content creation, current workflows often rely on multiple regenerations, which provides limited control and unpredictable outcomes. We present Compos3D, a system that introduces a compositional workflow for generative 3D modeling through remixing. Instead of repeatedly regenerating models, users generate multiple candidates from text or image prompts, select parts of interest via 2D image regions or 3D mesh segments, and assemble them into a coherent design. The system synthesizes these compositions into a refined 3D model, preserving high-level intent while resolving low-level geometry. To evaluate this approach, we conducted a controlled user study comparing remixing and regeneration workflows across both 2D and 3D modalities. Results show that the remixing workflow provides participants with greater creative control, stronger alignment with their intent, and higher satisfaction. We conclude with design recommendations for future AI-assisted 3D modeling workflows.","authors":["Faraz Faruqi","Sean J. Liu","George Fitzmaurice","Justin Matejka"],"published":"2026-07-13T22:24:26Z","updated":"2026-07-13T22:24:26Z","abstract_url":"https://arxiv.org/abs/2607.12193v1","html_url":"https://arxiv.org/html/2607.12193v1","pdf_url":"https://arxiv.org/pdf/2607.12193v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12186v1","title":"Overview of Cross-Component In-loop Filters in Video Coding Standards","abstract":"In-loop filters have been comprehensively explored during the development of video coding standards due to their remarkable noise-reduction capability. In the early stage of video coding, in-loop filters, such as Deblocking Filter, Sample Adaptive Offset, and Adaptive Loop Filter, were performed separately for each component. Recently, cross-component filters were studied to improve the chroma fidelity by exploiting correlations between the luma and chroma channels. This paper summarizes the cross-component filters used in the state-of-the-art video coding standard. Specifically, it includes the Cross-Component Adaptive Loop Filter and Cross-Component Sample Adaptive Offset. Cross-component filters aim to reduce compression artifacts based on the correlation between different components and provide more accurate pixel reconstruction values. In this paper, we introduce the origin, development, and status of cross-component filters in the current video coding standards. Finally, we had some discussions on the further evolutions of cross-component filters.","authors":["Zhaoyu Li","Xuewei Meng","Jiaqi Zhang","Cheng Huang","Chuanmin Jia","Siwei Ma","Yun Jiang"],"published":"2026-07-13T22:07:16Z","updated":"2026-07-13T22:07:16Z","abstract_url":"https://arxiv.org/abs/2607.12186v1","html_url":"https://arxiv.org/html/2607.12186v1","pdf_url":"https://arxiv.org/pdf/2607.12186v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"}],"favorites":[],"latest":{"generated_at_utc":"2026-07-15T03:54:56+00:00","category":"cs.CV","keywords":["video","retrieval","3d","agent","representation","instance","multimodal","diffusion"],"fetch_window_hours":72,"daily_window_hours":30,"match_count":63,"new_or_recent_papers":[{"id":"2607.13031v1","title":"The Seriality Gap in Video Diffusion Models","abstract":"When one ball strikes another, then another, video models should predict the consequences of each bounce. In controlled experiments on multi-ball hard-sphere dynamics, we find that the performance of standard bidirectional video diffusion degrades as the causal chain lengthens, even when provided more denoising steps. In a length-matched single-ball control, where ball-ball interactions are absent, the degradation largely disappears, isolating dependent-event structure rather than video length as the cause. Across intervention studies, methods that increase effective serial computation improve performance disproportionately, including autoregressive/blockwise generation and architectural depth. We identify this pattern as the seriality gap: a mismatch between tasks requiring growing serial computation and video diffusion models whose denoising loop does not provide scalable serial compute. We then prove that, for deterministic video prediction, denoising steps do not add serial computation beyond the backbone, indicating a structural obstacle for video diffusion on serial reasoning and simulation tasks.","authors":["Jorge Diaz Chao","Konpat Preechakul","Yuxi Liu","Yutong Bai"],"published":"2026-07-14T17:59:22Z","updated":"2026-07-14T17:59:22Z","abstract_url":"https://arxiv.org/abs/2607.13031v1","html_url":"https://arxiv.org/html/2607.13031v1","pdf_url":"https://arxiv.org/pdf/2607.13031v1.pdf","matched_keywords":["video","diffusion"],"source_used":"html","source_text_chars":79416,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, diffusion 相关；摘要显示其主要贡献为：When one ball strikes another, then another, video models should predict the consequences of each bounce. In controlled experiments on multi-ball hard-sphere dynamics, we find that the performance of standard bidirectional video diffusion degrades as the caus...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:56+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.13017v1","title":"FlowWAM: Optical Flow as a Unified Action Representation for World Action Models","abstract":"World Action Models (WAMs) are able to leverage pretrained video generators for both world modeling and action prediction. However, directly leveraging such video generators for control raises a new challenge: how to represent actions in a suitable form that aligns with pretrained video generators while carrying enough motion cues for accurate control. Existing numerical actions fail to satisfy the former, and prior visual action representations overlook the temporal motion structure across frames. We address this issue with FlowWAM, a dual-stream diffusion framework that adopts optical flow as a unified, video-native action representation. Flow videos share the same format as RGB videos and encode rich per-pixel displacement. By jointly modeling them within a shared pretrained video generator, FlowWAM can naturally implement two modes of WAMs. In policy mode, FlowWAM generates flow for action prediction, while in world-model mode, it uses target flow sequences to guide future video generation. Moreover, since flow can be easily extracted from raw videos without action labels, FlowWAM can leverage large-scale action-unlabeled video datasets for pretraining. We empirically find that our flow-based action representation delivers gains across both modes. On RoboTwin manipulation, FlowWAM raises the success rate to 92.94% on the Clean setting and 92.14% on Random, outperforming both VLA and WAM baselines. On WorldArena world modeling, it achieves the best overall EWMScore (63.71) with an 18.4% relative improvement in trajectory accuracy. More results can be found on our project website: https://flow-wam.github.io .","authors":["Yixiang Chen","Peiyan Li","Yuan Xu","Qisen Ma","Jiabing Yang","Kai Wang","Jianhua Yang","Dong An","He Guan","Gaoteng Liu","Jianlou Si","Jun Huang","Jing Liu","Nianfeng Liu","Yan Huang","Liang Wang"],"published":"2026-07-14T17:57:12Z","updated":"2026-07-14T17:57:12Z","abstract_url":"https://arxiv.org/abs/2607.13017v1","html_url":"https://arxiv.org/html/2607.13017v1","pdf_url":"https://arxiv.org/pdf/2607.13017v1.pdf","matched_keywords":["video","representation","diffusion"],"source_used":"html","source_text_chars":89900,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, representation, diffusion 相关；摘要显示其主要贡献为：World Action Models (WAMs) are able to leverage pretrained video generators for both world modeling and action prediction. However, directly leveraging such video generators for control raises a new challenge: how to represent actions in a suitable form that...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:56+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.13010v1","title":"DermDepth: Toward Monocular Metric Scale 3D Reconstruction Models for Dermatology","abstract":"Dermatological practice routinely involves measuring and tracking lesion size, morphology and texture, as critical components of wound or skin cancer screening, monitoring and diagnosis. To accomplish this task, practitioners often image the skin surface with commonly available off-the-shelf camera sensors. This has led to an overwhelming research focus on 2D methods while these objectives naturally benefit from 3D information. In this paper, we demonstrate that dense monocular 3D reconstructions, metric scale measurements and rich surface normal texture estimates are achievable for both dermoscopic and macroscopic cases without the need for additional hardware or multiple captures. We present DermDepth, the first single-view metric scale 3D model for the dermatological domain and D-Synth, the first synthetic dermoscopic dataset with pixel-perfect 3D information. Our experiments show training DermDepth on D-Synth corrects metric scale error from over 16x to under 1.1x for real dermoscopic data, while preserving geometric quality and increasing texture richness. Fine-tuning on a small amount of real clinical samples generalizes our method across three real-world benchmarks spanning the few mm to hundred cm range, diverse skin-tones, chronic wound cases and produces measurements broadly consistent with disease size reported in medical literature. All code, data and models are available at https://github.com/hectorcarrion/dermdepth.","authors":["Héctor Carrión","Narges Norouzi"],"published":"2026-07-14T17:51:37Z","updated":"2026-07-14T17:51:37Z","abstract_url":"https://arxiv.org/abs/2607.13010v1","html_url":"https://arxiv.org/html/2607.13010v1","pdf_url":"https://arxiv.org/pdf/2607.13010v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":27634,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Dermatological practice routinely involves measuring and tracking lesion size, morphology and texture, as critical components of wound or skin cancer screening, monitoring and diagnosis. To accomplish this task, practitioners often image the skin surface with...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:56+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12959v1","title":"ViCo3D: Empowering LiDAR-based Collaborative 3D Object Detection with Vision Foundation Models","abstract":"LiDAR-based collaborative 3D perception in Vehicle-to-Everything (V2X) systems typically relies on fusing bird's-eye-view (BEV) features across agents. However, current BEV representations, typically extracted by LiDAR backbones trained from scratch, are geometry-dominated and lack general semantic priors, inherently limiting the efficacy of feature-level collaboration. Meanwhile, vision foundation models (VFMs) pretrained on large-scale image data have demonstrated strong capability in learning general-purpose and informative visual representations for 2D tasks, and have the potential to enhance agent-wise LiDAR BEV representations for collaboration. Despite this potential, adapting VFMs to LiDAR-based 3D detection remains challenging due to the substantial image-point cloud modality gap. To bridge this gap, we propose ViCo3D, a collaborative 3D object detection framework powered by VFMs. Specifically, ViCo3D adapts VFMs to LiDAR-based collaborative perception from three aspects: First, ViCo3D projects point clouds onto the BEV plane as three-channel images, enabling DINOv2 to extract BEV-space visual features from LiDAR inputs. Besides, to effectively integrate these DINOv2-derived features with LiDAR geometric features, ViCo3D introduces a multi-scale BEV fusion module within the single-agent encoder. In addition, ViCo3D adopts an ego-centric cross-agent fusion strategy to aggregate complementary information from multiple agents. Experiments on DAIR-V2X and V2XSet demonstrate that ViCo3D achieves state-of-the-art 3D detection performance. Remarkably, it delivers up to 1.8x greater collaborative gains than prior methods on DAIR-V2X. The code will be made public available for future investigation.","authors":["Haojie Ren","Songrui Luo","Lingfeng Wang","Yan Xia","Yao Li","Jing Li","Lu Zhang","Jiajun Deng","Yanyong Zhang"],"published":"2026-07-14T16:56:10Z","updated":"2026-07-14T16:56:10Z","abstract_url":"https://arxiv.org/abs/2607.12959v1","html_url":"https://arxiv.org/html/2607.12959v1","pdf_url":"https://arxiv.org/pdf/2607.12959v1.pdf","matched_keywords":["3d","agent","representation"],"source_used":"html","source_text_chars":87955,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, agent, representation 相关；摘要显示其主要贡献为：LiDAR-based collaborative 3D perception in Vehicle-to-Everything (V2X) systems typically relies on fusing bird's-eye-view (BEV) features across agents. However, current BEV representations, typically extracted by LiDAR backbones trained from scratch, are geom...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12939v1","title":"Point Tracking in Surgery--The 2025 Surgical Tattoos in Infrared Challenge (STIRC2025)","abstract":"Point tracking in surgery is crucial to enable applications in downstream tasks such as segmentation, 3D reconstruction, virtual tissue landmarking, autonomous probe-based scanning, and subtask autonomy. This paper introduces the 2025 iteration of a point tracking challenge to address this, wherein participants submit their algorithms for quantification. Their algorithms are evaluated using a dataset named surgical tattoos in infrared (STIR), with the challenge named the STIR Challenge 2025 (STIRC2025). The STIR Challenge 2025 comprises two quantitative components: accuracy and efficiency. The accuracy component tests the accuracy of algorithms on in vivo and ex vivo sequences. The efficiency component tests algorithm inference latency. The challenge was conducted as a part of MICCAI EndoVis 2025, and seven teams participated in this challenge. In this paper we summarize the challenge results and participant methods. The challenge dataset is available at: https://zenodo.org/records/20191078, and the code for baseline models and metrics calculation is available here: https://github.com/athaddius/STIRMetrics","authors":["Adam Schmidt","Mert Asim Karaoglu","Zijian Wu","Jiaming Zhang","Yuxin Chen","Tim Salcudean","Ho-Gun Ha","Minkang Jang","Kyungmin Jung","Ihsan Ullah","Hyunki Lee","Suresh Guttikonda","Sarah Latus","Alexander Schlaefer","Xinkai Zhao","Yuichiro Hayashi","Masahiro Oda","Takayuki Kitasaka","Kensaku Mori","Peng Liu","Chenyang Li","Stefanie Speidel","Aoife Gardiner","Agostino Stilli","Danail Stoyanov","Francisco Vasconcelos","Anwesa Choudhuri","Meng Zheng","Zhongpai Gao","Benjamin Planche","Van Nguyen Nguyen","Terrence Chen","Ziyan Wu","Alexander Ladikos","Omid Mohareri"],"published":"2026-07-14T16:10:49Z","updated":"2026-07-14T16:10:49Z","abstract_url":"https://arxiv.org/abs/2607.12939v1","html_url":"https://arxiv.org/html/2607.12939v1","pdf_url":"https://arxiv.org/pdf/2607.12939v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":43858,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Point tracking in surgery is crucial to enable applications in downstream tasks such as segmentation, 3D reconstruction, virtual tissue landmarking, autonomous probe-based scanning, and subtask autonomy. This paper introduces the 2025 iteration of a point tra...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12937v1","title":"Exact and Calibrated Diffusion Reconstruction for Digital Breast Tomosynthesis","abstract":"Limited-angle digital breast tomosynthesis (DBT) reconstructs a volume from a few low-dose projections over a narrow arc. At a representative nine-view, $25^{\\circ}$ protocol more than 98% of image space is unmeasured, so a learned prior must supply structure in the missing wedge. Conditional diffusion priors achieve strong perceptual quality here but leave three clinical obstacles: inexact data consistency, unlocalized hallucination, and uncalibrated uncertainty. We enforce measurements exactly by replacing the per-step proximal update of a conditional diffusion sampler with exact Euclidean projection onto the data-consistent set, computed via an $m$-dimensional dual system with a one-time Gram matrix $AA^{\\top}$ factorization. This projection costs 4.5 ms per step (a $248\\times$ speedup) and drives the data residual to the double-precision floor ($2.4\\times10^{-13}$). We prove it is the $ρ\\to0$ limit of the proximal step, provide a no-harm theorem, and show that exactly consistent sample ensembles have variance supported on null($A$). Thus, the mean's entire error lies in the unmeasured subspace covered by the uncertainty map. On patient-derived breast phantoms, this improves fidelity at no depth-resolution cost. Conversely, a proximal step applied post-update degrades quality, isolating the consistency step's placement as decisive. Isotonic recalibration brings the ensemble spread to a calibrated error scale (expected calibration error $0.029\\to0.008$; standardized error $4.7\\to0.96$), ranking errors better than the pure prior. We also repair a 20.3% adjoint mismatch in a deployed projector via a materialized operator of record. This is the first data-consistent, uncertainty-calibrated learned reconstruction for limited-angle DBT. The solver naturally relaxes to discrepancy-ball and maximum-a-posteriori modes for noisy measurements.","authors":["Imade Bouftini"],"published":"2026-07-14T16:10:10Z","updated":"2026-07-14T16:10:10Z","abstract_url":"https://arxiv.org/abs/2607.12937v1","html_url":"https://arxiv.org/html/2607.12937v1","pdf_url":"https://arxiv.org/pdf/2607.12937v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":80162,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Limited-angle digital breast tomosynthesis (DBT) reconstructs a volume from a few low-dose projections over a narrow arc. At a representative nine-view, $25^{\\circ}$ protocol more than 98% of image space is unmeasured, so a learned prior must supply structure...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12934v1","title":"Domain-Incremental Remote Sensing Change Detection via Difference-Guided Adaptation and Frequency-Decoupled Distillation","abstract":"Remote sensing change detection (RSCD) models are prone to catastrophic forgetting when incrementally adapted to new domains. Existing domain-incremental learning (DIL) methods mainly preserve image-level representations but often overlook bitemporal discrepancy cues, which are critical for robust change detection under domain shifts. To address this limitation, we propose DG-FDD, a domain-incremental change detection framework that integrates Difference-Guided Adaptation and Frequency-Decoupled Distillation. Specifically, the Difference-Guided Dynamic Adapter (DGDA) models bitemporal feature discrepancies to promote change-aware feature adaptation and reduce domain-specific interference. Meanwhile, the Frequency-Decoupled Knowledge Distillation strategy with Cross-domain Synthesis (FDKD-CS) separates structural information from domain style in the frequency domain, enabling stable knowledge transfer without historical data. Extensive experiments on three public high-resolution RSCD datasets under two- and three-domain incremental protocols demonstrate that DG-FDD effectively mitigates catastrophic forgetting. Compared with independently trained single-task models, DG-FDD records mean relative changes in F1 and IoU of only -0.23% and -0.45%, respectively, across six two-domain sequences, and -0.69% and -1.31%, respectively, across the three evaluated three-domain sequences. These results indicate a favorable stability-plasticity balance between historical knowledge retention and new-domain adaptation in continual cross-domain change detection.","authors":["Daifeng Peng","Yaning Li","Haiyan Guan"],"published":"2026-07-14T16:07:21Z","updated":"2026-07-14T16:07:21Z","abstract_url":"https://arxiv.org/abs/2607.12934v1","html_url":"https://arxiv.org/html/2607.12934v1","pdf_url":"https://arxiv.org/pdf/2607.12934v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":99574,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Remote sensing change detection (RSCD) models are prone to catastrophic forgetting when incrementally adapted to new domains. Existing domain-incremental learning (DIL) methods mainly preserve image-level representations but often overlook bitemporal discrepa...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12911v1","title":"Open-KNEAD: Knowledge-grounded Nutrition Estimation via Agentic Decomposition","abstract":"Multimodal Large Language Models (MLLMs) are increasingly used for dietary assessment from meal images, where retrieval-augmented grounding was shown to sharpen nutrition estimates. However, we find this premise no longer holds for current MLLMs. A modern MLLM's direct estimate now matches or surpasses the full retrieval pipeline. This raises a question: if retrieval no longer improves the overall estimate, can it still deliver the two things clinicians value, accurate portions and a traceable, item-by-item record? We pursue this while preserving what matters for clinical adoption: minimal user burden (a single, unannotated meal image), explainability (an auditable record), and privacy (locally hosted inference). We introduce Open-KNEAD, a knowledge-grounded agentic framework for meal nutrition estimation that is training-free and locally deployable. Each decomposed food item is grounded to a Food and Nutrient Database for Dietary Studies (FNDDS) code via selective, nutrient-aware retrieval, composing an auditable per-item record. Across two open MLLM families and three cuisines, Open-KNEAD improves portion estimates over both prior grounding methods and direct estimation in most backbone-dataset settings. An agent-internal recipe-prior step further recovers the invisible cooking-added energy that biases estimates on non-US cuisine. The advantage is largest on the dietitian-verified ACETADA dataset, where the local open agent surpasses the direct portion estimates of two frontier closed models by roughly $30\\%$ and $53\\%$, all while keeping every meal image on local hardware. We release the Open-KNEAD framework and its agent-ready FNDDS knowledge base.","authors":["Bruce Coburn","Jingbo Yue","Jinge Ma","Siddeshwar Raghavan","Gautham Vinod","Fengqing Zhu"],"published":"2026-07-14T15:48:25Z","updated":"2026-07-14T15:48:25Z","abstract_url":"https://arxiv.org/abs/2607.12911v1","html_url":"https://arxiv.org/html/2607.12911v1","pdf_url":"https://arxiv.org/pdf/2607.12911v1.pdf","matched_keywords":["retrieval","agent","multimodal"],"source_used":"html","source_text_chars":65829,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval, agent, multimodal 相关；摘要显示其主要贡献为：Multimodal Large Language Models (MLLMs) are increasingly used for dietary assessment from meal images, where retrieval-augmented grounding was shown to sharpen nutrition estimates. However, we find this premise no longer holds for current MLLMs. A modern MLL...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12896v1","title":"UniMedSeg: Unified In-Context Learning for Multi-Paradigm 2D/3D Medical Image Segmentation","abstract":"Medical image segmentation foundation models are expected to generalize across diverse clinical scenarios, yet existing universal methods remain fragmented by prompt paradigms and spatial dimensions. Visual in-context learning, interactive segmentation, and language-guided segmentation are typically handled by paradigm-specific models, while 2D and 3D images are also modeled separately. Such isolation prevents heterogeneous annotations and data from being jointly absorbed by a single scalable model and limits cross-paradigm knowledge transfer. To address this bottleneck, we propose UniMedSeg, a Transformer-centric universal segmentation framework that maps visual examples, geometric interactions, language instructions, and 2D/3D images into a shared sequence space, enabling heterogeneous medical supervision to be jointly learned through a unified in-context interface without prompt- or dimension-specific branches. To overcome the long-sequence memory bottleneck caused by visual contexts, we introduce Decoupled Split Attention, which reduces attention complexity to linear while preserving hardware-friendly computation and focused context-target interaction. Extensively trained and evaluated on a large corpus curated from 27 public datasets, UniMedSeg achieves state-of-the-art performance across visual in-context, interactive, and language-guided segmentation without task-specific fine-tuning, demonstrating strong generalization on diverse held-out tasks. The code and model weights are publicly available at https://github.com/Lii1228/UniMedSeg","authors":["Yunzhou Li","Jiesi Hu","Yanwu Yang","Hanyang Peng","Chenfei Ye","Jianfeng Cao","Yixuan Yuan","Ting Ma"],"published":"2026-07-14T15:34:46Z","updated":"2026-07-14T15:34:46Z","abstract_url":"https://arxiv.org/abs/2607.12896v1","html_url":"https://arxiv.org/html/2607.12896v1","pdf_url":"https://arxiv.org/pdf/2607.12896v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":62610,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Medical image segmentation foundation models are expected to generalize across diverse clinical scenarios, yet existing universal methods remain fragmented by prompt paradigms and spatial dimensions. Visual in-context learning, interactive segmentation, and l...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12894v1","title":"Hy-Embodied-VLM-1.0: Efficient Physical-World Agents","abstract":"Building capable embodied agents requires not only multimodal perception and understanding, but also agentic capabilities for reasoning about actions, adapting to evolving situations, and interacting with the physical world. In this report, we introduce Hy-Embodied-VLM-1.0, an efficient and powerful embodied foundation model specifically designed for embodied agents operating in the physical world. To cultivate such capabilities from the pre-training stage onward, we define an action-centric capability taxonomy comprising three progressive dimensions: Action-Relevant State Understanding, Action-Transition Reasoning, and Sequential and Adaptive Reasoning. Guided by this taxonomy, we develop a systematic data pipeline and curate data mixtures spanning both pre-training and post-training. To deliver strong physical-world understanding and interaction capabilities while supporting latency-sensitive deployment, we build our model on the Hy3-A3B language backbone and the Hy-ViT2 vision encoder. Its efficient Mixture-of-Experts architecture combines strong model capacity with high inference efficiency. We evaluate Hy-Embodied-VLM-1.0 on a comprehensive suite of 38 benchmarks covering embodied perception, physical-world understanding, and embodied reasoning. The model achieves the best performance among similarly sized models on 19 of the 38 benchmarks and substantially outperforms strong competitors, including Qwen3.6-A3B and Cosmos 3. Compared with the previous-generation Hy-Embodied-0.5 MoT-2B, Hy-Embodied-VLM-1.0 improves average performance by 8.4%. Despite activating only 3B parameters, it achieves performance close to that of the previous-generation model with 32B activated parameters. Beyond static benchmark evaluation, Hy-Embodied-VLM-1.0 also demonstrates strong performance on embodied agentic tasks requiring multi-turn interaction and long-horizon reasoning.","authors":["Ziyi Wang","Xumin Yu","Yongming Rao","Yonggen Ling","Yunheng Li","Oran Wang","Mingqi Gao","Yuchen Zhou","Yves Liang","Zuyan Liu","Yani Zhang","Rui Huang","Xiaoran Xu","Bowen Yuan","Yifu Yuan","Xu Tan","He Zhang","Yufei Huang","Shenghao Zhang","Hongsheng Wu","Han Hu","Zhengyou Zhang"],"published":"2026-07-14T15:34:17Z","updated":"2026-07-14T15:34:17Z","abstract_url":"https://arxiv.org/abs/2607.12894v1","html_url":"https://arxiv.org/html/2607.12894v1","pdf_url":"https://arxiv.org/pdf/2607.12894v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"html","source_text_chars":106273,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 agent, multimodal 相关；摘要显示其主要贡献为：Building capable embodied agents requires not only multimodal perception and understanding, but also agentic capabilities for reasoning about actions, adapting to evolving situations, and interacting with the physical world. In this report, we introduce Hy-Em...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12874v1","title":"Metric-Guided Synthetic Image Data Rendering for Deep Learning compatible with Agentic AI","abstract":"Deep learning computer vision for scientific applications requires collecting and annotating large datasets in a laborious, expensive and error-prone process. Synthetic data generation through 3D modelling and rendering may simplify this process and increase the accuracy of annotations by generating them programmatically. However, minimising the domain gap between real and synthetic images visually is subjective and lacks systematic quantitative guidance. We present GraNatPy, a Python package with metrics to guide improvement of the rendered scene. We show that quantifiable increase in realism, diversity and size of rendered dataset correlates with improved visual perception of the scene and higher zero-shot performance of an object detection model. Furthermore, we demonstrated using photographs of virological plaque assays that gradient similarity affects performance on small object detection, which can be improved by mixing real and synthetic data. Finally, we turn procedural data rendering into an agentic skill (SynthClaw) to automate the procedural parameter optimisation.","authors":["Martina Radoynova","Samuel Pantze","Trina De","Ulrik Günther","Artur Yakimovich"],"published":"2026-07-14T15:22:26Z","updated":"2026-07-14T15:22:26Z","abstract_url":"https://arxiv.org/abs/2607.12874v1","html_url":"https://arxiv.org/html/2607.12874v1","pdf_url":"https://arxiv.org/pdf/2607.12874v1.pdf","matched_keywords":["3d","agent"],"source_used":"html","source_text_chars":56318,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, agent 相关；摘要显示其主要贡献为：Deep learning computer vision for scientific applications requires collecting and annotating large datasets in a laborious, expensive and error-prone process. Synthetic data generation through 3D modelling and rendering may simplify this process and increase...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12820v1","title":"AVSCap: Orchestrating Audio-Visual Synergy for Omni-modal Video Captioning","abstract":"Omni-modal video captioning is not merely combining visual captioning with audio transcription: a useful caption must describe how visual actions, speech, music, and sound effects co-evolve. Existing large multimodal models often fail at this relational step, treating audio and visual streams as loosely coupled observations, relying on automatic speech recognition, and under-specifying non-speech sounds and their links to visual events. We present AVSCap, a framework for audio-visual captioning centered on explicit cross-modal event binding. First, we construct AVSCap-130K, a tri-modal training corpus generated by a decoupled-then-fused pipeline that anchors visual and acoustic evidence before composing grounded omni-modal captions. Second, we train AVSCap-7B, a 7B captioner with a two-stage strategy: supervised fine-tuning establishes baseline capabilities, while sample-efficient reinforcement learning uses hybrid rewards to optimize acoustic completeness and audio-visual synergy. Our scaling analysis shows that reinforcement learning brings larger gains than increasing SFT data. Third, we introduce AVSCapBench, a benchmark that decomposes captions into visual, audio, and synergy events and evaluates them with fine-grained event recall. Experiments on AVSCapBench and external benchmarks show that AVSCap-7B improves non-speech audio coverage and cross-modal binding, delivering the best overall performance among evaluated open-source models.","authors":["Yanghai Wang","Jiahao Wang","Jiafu Tang","Yuanxing Zhang","Zhe Cao","Hanyan Bian","Zijie Zhang","Weiliang Luo","Zhiyu Pan","Zixuan Dong","Jiaheng Liu","Zhaoxiang Zhang"],"published":"2026-07-14T14:34:19Z","updated":"2026-07-14T14:34:19Z","abstract_url":"https://arxiv.org/abs/2607.12820v1","html_url":"https://arxiv.org/html/2607.12820v1","pdf_url":"https://arxiv.org/pdf/2607.12820v1.pdf","matched_keywords":["video","multimodal"],"source_used":"html","source_text_chars":105724,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, multimodal 相关；摘要显示其主要贡献为：Omni-modal video captioning is not merely combining visual captioning with audio transcription: a useful caption must describe how visual actions, speech, music, and sound effects co-evolve. Existing large multimodal models often fail at this relational step,...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12818v1","title":"Breaking Déjà Vu: Independent Auditing of Visual Place Recognition through Vision-Language Reasoning","abstract":"Visual place recognition (VPR) is a key enabler of accurate localization and long-term autonomous navigation in robotics applications, such as loop closure detection for simultaneous localisation and mapping (SLAM). However, real-world VPR deployment relies on selecting an image matching threshold that balances precision and recall. These thresholds are typically tuned using labeled validation data and fixed during deployment, making them unreliable under environmental changes where ground truth is unavailable. This is particularly problematic in safety-critical robotics, where accepting a false loop closure can corrupt the estimated trajectory and map. In this work, we introduce Visual Place Recognition Auditing, an independent post-retrieval verification framework that leverages Vision-Language Models (VLMs) to assess retrieved matches by reasoning jointly over query and candidate images. Unlike conventional verification methods, our approach performs instance-level verification without requiring architecture-specific confidence measures, dataset-dependent thresholds, or prior knowledge of the deployment environment. We evaluate our method on six benchmark datasets using five state-of-the-art VPR methods and four VLMs. Results show that VLM-based auditing improves recall@1 by 13.6% on average as compared to state-of-the-art methods while reducing false acceptance rates to 12%, maintaining precision above 95% and coverage above 75%.","authors":["Sania Waheed","Michael Milford","Sarvapali D. Ramchurn","Shoaib Ehsan"],"published":"2026-07-14T14:30:24Z","updated":"2026-07-14T14:30:24Z","abstract_url":"https://arxiv.org/abs/2607.12818v1","html_url":"https://arxiv.org/html/2607.12818v1","pdf_url":"https://arxiv.org/pdf/2607.12818v1.pdf","matched_keywords":["retrieval","instance"],"source_used":"html","source_text_chars":47232,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval, instance 相关；摘要显示其主要贡献为：Visual place recognition (VPR) is a key enabler of accurate localization and long-term autonomous navigation in robotics applications, such as loop closure detection for simultaneous localisation and mapping (SLAM). However, real-world VPR deployment relies o...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12800v1","title":"UniVR: Thinking in Visual Space for Unified Visual Reasoning","abstract":"Learning broad world knowledge directly from raw visual data is a fundamental capability of intelligence. We introduce UniVR, the first investigation into simultaneously learning complex reasoning, fine-grained physical dynamics, and long-term planning from pure visual demonstrations. At its core, UniVR features VR-GRPO, a reinforcement learning paradigm with complementary global and step-level rewards. This approach enforces logical coherence and physical consistency throughout the reasoning process without requiring task-specific heuristics or image-text pairs. To train and evaluate UniVR, we construct VR-X, a large-scale benchmark curated from 16 diverse sources spanning long-horizon manipulation, spatial puzzles, and physical reasoning. It is the first comprehensive suite to assess these heterogeneous capabilities under a purely visual protocol. Remarkably, UniVR achieves up to a 25% improvement on VR-X, and its superior visual reasoning also boosts performance on various multimodal understanding benchmarks. These findings underscore the vast potential of reasoning within visual spaces, with all code, data, and models are open-sourced for further research.","authors":["Zhongwei Ren","Yunchao Wei","Yao Zhao","Weibo Gong","Xiao Liu","Anran Wang","Xiangtai Li","Xiaojie Jin"],"published":"2026-07-14T14:15:13Z","updated":"2026-07-14T14:15:13Z","abstract_url":"https://arxiv.org/abs/2607.12800v1","html_url":"https://arxiv.org/html/2607.12800v1","pdf_url":"https://arxiv.org/pdf/2607.12800v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":71048,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Learning broad world knowledge directly from raw visual data is a fundamental capability of intelligence. We introduce UniVR, the first investigation into simultaneously learning complex reasoning, fine-grained physical dynamics, and long-term planning from p...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12789v1","title":"AVQ-Attention: Adaptive Vector-Quantized Attention","abstract":"The $\\mathcal{O}(N^2)$ complexity of attention over $N$ tokens remains a computational bottleneck in transformer models. Vector-Quantized (VQ) attention reduces this to $\\mathcal{O}(MN)$ by representing keys with $M$ codewords, but applies uniform codebook capacity regardless of where attention mass concentrates: high-attention regions of key space may be coarsely approximated while low-attention regions waste representational capacity. We propose Adaptive Vector-Quantized (AVQ) Attention, which adaptively allocates codebook capacity based on attention importance. Starting from a small set of codewords, our method identifies the most important codes during the forward pass and refines them with pre-learned child codewords, achieving fine-grained quantization where it matters most while maintaining coarse quantization elsewhere. We develop an implementation using custom Triton kernels that enables the full adaptive refinement process, including importance scoring, child codeword insertion, and parent contribution replacement, to be carried out within the tiled computation paradigm of Flash Attention with minimal overhead. Our approach maintains $\\mathcal{O}(MN)$ complexity while achieving improved accuracy-efficiency trade-offs compared to fixed-codebook VQ-attention.","authors":["Winfried van den dool","Patrick Forré","Amir Habibian","Yuki M. Asano","Max Welling"],"published":"2026-07-14T14:02:22Z","updated":"2026-07-14T14:02:22Z","abstract_url":"https://arxiv.org/abs/2607.12789v1","html_url":"https://arxiv.org/html/2607.12789v1","pdf_url":"https://arxiv.org/pdf/2607.12789v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":69877,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：The $\\mathcal{O}(N^2)$ complexity of attention over $N$ tokens remains a computational bottleneck in transformer models. Vector-Quantized (VQ) attention reduces this to $\\mathcal{O}(MN)$ by representing keys with $M$ codewords, but applies uniform codebook ca...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:57+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12787v1","title":"Do We Really Need Multimodal Emotion Language Models Larger Than 1B Parameters?","abstract":"Recent advances in multimodal large language models (MLLMs) have significantly improved the performance of multimodal emotion recognition (MER) and enabled interpretable description generation by jointly modeling video, audio, and language, etc. However, these performance improvements are often accompanied by an increase in model parameter size (e.g, at least 7B), which simultaneously incurs high computational costs and reduces inference efficiency, thereby hindering real-time deployment on resource-constrained platforms such as robots and mobile devices. This raises a fundamental question: do we really need the multimodal MER model larger than 1B parameters for high-quality MER? In this paper, we challenge the assumption that larger models are inherently necessary and proposes a lightweight MER framework (called Light-MER), which achieves better and faster multimodal sentiment understanding and recognition through knowledge distillation. It can transfer knowledge from a strong, large-scale teacher model to a lightweight sub-billion-parameter student model, aiming to preserve rich multimodal emotion reasoning and recognition while substantially improving deployment efficiency. Specifically, we introduce two new optimization strategies to enhance knowledge transfer: (1) a new optimal transport loss that combines Sliced Wasserstein Distance with hidden-state alignment, and (2) a new multi-reward optimization strategy based on GRPO that balances MER performance and efficiency, aimed at further enhancing the learning capabilities of student models. Extensive experiments on nine benchmark datasets demonstrate that Light-MER achieves state-of-the-art performance while significantly improving inference efficiency. This highlights the strong potential of small multimodal emotion language models for future research. Code is available at https://github.com/GAIR-Lab/Light-MER.","authors":["Kaiwen Zheng","Junchen Fu","Wenhao Deng","Hu Han","Joemon M. Jose","Xuri Ge"],"published":"2026-07-14T14:01:29Z","updated":"2026-07-14T14:01:29Z","abstract_url":"https://arxiv.org/abs/2607.12787v1","html_url":"https://arxiv.org/html/2607.12787v1","pdf_url":"https://arxiv.org/pdf/2607.12787v1.pdf","matched_keywords":["video","multimodal"],"source_used":"html","source_text_chars":64580,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, multimodal 相关；摘要显示其主要贡献为：Recent advances in multimodal large language models (MLLMs) have significantly improved the performance of multimodal emotion recognition (MER) and enabled interpretable description generation by jointly modeling video, audio, and language, etc. However, thes...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:58+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12786v1","title":"CoRe: A Comprehensive Framework for Cross-Image Comparative Reasoning in Vision-Language Models","abstract":"Cross-image comparative reasoning remains challenging for vision-language models (VLMs), especially when correct prediction requires fine-grained attribute grounding and globally consistent reasoning. We present CoRe, a unified framework for this problem. CoRe includes: (i) CoRe-20K, a large-scale triplet-based training set automatically constructed from structured visual metadata through a multi-expert collaborative pipeline, covering counting, depth, distance, and spatial relations; (ii) TriSR, a structured reward framework that jointly supervises attribute grounding, judgment alignment, and triplet consistency under GRPO optimization; and (iii) CoRe-Bench, the first benchmark dedicated to fine-grained cross-image comparative reasoning. Experiments show that CoRe substantially outperforms existing VLMs on CoRe-Bench while remaining competitive on standard multimodal benchmarks, achieving a 28.2-point gain in partial accuracy over the strongest baseline.","authors":["Lin Peng","Cong Wan","Zeyu Guo","SongLin Dong","Yihong Gong"],"published":"2026-07-14T14:01:07Z","updated":"2026-07-14T14:01:07Z","abstract_url":"https://arxiv.org/abs/2607.12786v1","html_url":"https://arxiv.org/html/2607.12786v1","pdf_url":"https://arxiv.org/pdf/2607.12786v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":56190,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Cross-image comparative reasoning remains challenging for vision-language models (VLMs), especially when correct prediction requires fine-grained attribute grounding and globally consistent reasoning. We present CoRe, a unified framework for this problem. CoR...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:58+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12785v1","title":"ExtraGS: Enhancing Endoscopic View Extrapolation via Diffusion-Guided 3D Gaussian Splatting","abstract":"Robot-assisted minimally invasive surgery (MIS) critically depends on reliable endoscopic perception for navigation and safety. However, conventional endoscopes provide only a limited field of view, leaving large portions of surrounding anatomy unobserved. Recent neural rendering approaches, such as Neural Radiance Fields and 3D Gaussian Splatting, enable novel view synthesis from endoscopic videos, but their reliance on sparse observations often leads to severe artifacts when extrapolating beyond the training trajectory.In this work, we propose ExtraGS, a framework for enhancing endoscopic view extrapolation via diffusion-guided 3D Gaussian Splatting. Starting from an initial reconstruction, we introduce an uncertainty-guided virtual camera sampling strategy to actively explore blind spots and maximize information gain. The rendered views from these sampled locations are refined using a diffusion model to recover plausible anatomical structures, producing pseudo observations that guide further optimization. To prevent the generated content from degrading reliable regions, we adopt a confidence-weighted fine-tuning strategy when incorporating these pseudo observations.Extensive experiments on multiple public endoscopic datasets demonstrate that ExtraGS significantly reduces extrapolation artifacts and achieves state-of-the-art performance in endoscopic novel view synthesis.","authors":["Cheng-Tai Hsieh","Jiwei Shan","Han Fang","Jianshu Hu","Tao Ni","Lijun Han","Yutong Ban","Shing Shin Cheng","Hesheng Wang"],"published":"2026-07-14T14:00:50Z","updated":"2026-07-14T14:00:50Z","abstract_url":"https://arxiv.org/abs/2607.12785v1","html_url":"https://arxiv.org/html/2607.12785v1","pdf_url":"https://arxiv.org/pdf/2607.12785v1.pdf","matched_keywords":["video","3d","diffusion"],"source_used":"html","source_text_chars":50605,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, diffusion 相关；摘要显示其主要贡献为：Robot-assisted minimally invasive surgery (MIS) critically depends on reliable endoscopic perception for navigation and safety. However, conventional endoscopes provide only a limited field of view, leaving large portions of surrounding anatomy unobserved. Re...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:58+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12782v1","title":"MBTI: A Multi-Branch Efficient Fine-Tuning Framework for Hyperspectral Image Classification with Foundation Models","abstract":"Hyperspectral foundation models learn transferable spectral-spatial representations from large-scale unlabeled data. They provide an effective paradigm for adapting to downstream hyperspectral image (HSI) classification tasks with limited labeled samples. However, spectral band configurations vary substantially across sensors, which makes direct model transfer difficult. Existing adaptation strategies often compress, select, or reshape the original spectra to match model-specific input requirements. These operations may discard useful spectral information and weaken local spectral continuity. To address this problem, we propose MBTI, a Multi-Branch efficient fine-tuning framework for Hyperspectral Image classification. MBTI adapts hyperspectral foundation models to downstream classification tasks while preserving full-band spectral information. First, we introduce a spectral-continuity-preserving multi-branch preprocessing strategy. The original HSI is divided into multiple continuous spectral subsets, and a band reuse mechanism is used when the remaining bands cannot form a complete branch. This avoids invalid padding and unnecessary spectral loss. Second, independent Low-Rank Adaptation (LoRA) modules are inserted into each branch. They enable different spectral intervals to learn task-specific discriminative features while keeping most pre-trained parameters frozen. Finally, a multi-branch channel attention fusion module adaptively recalibrates and integrates features from all spectral branches. Experiments on three public hyperspectral datasets show that MBTI achieves competitive and superior performance compared with representative classification methods. Under the final rank-8 configuration, only about 2.33\\%--2.36\\% of the parameters are trainable. The code will be available at https://github.com/Azhenmiddleblock/MBTI/tree/main.","authors":["Mingzhen Xu","Haonan Guo","Di Wang","Yinghua Qu","Zhiliang Zhou","Lei Zhang","Huiwen Yao","Rui Zhao","Fengxiang Wang","Gang Wan","Bo Du","Liangpei Zhang"],"published":"2026-07-14T13:58:10Z","updated":"2026-07-14T13:58:10Z","abstract_url":"https://arxiv.org/abs/2607.12782v1","html_url":"https://arxiv.org/html/2607.12782v1","pdf_url":"https://arxiv.org/pdf/2607.12782v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":70688,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Hyperspectral foundation models learn transferable spectral-spatial representations from large-scale unlabeled data. They provide an effective paradigm for adapting to downstream hyperspectral image (HSI) classification tasks with limited labeled samples. How...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:58+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12774v1","title":"HSEmotion Team at the 11th ABAW Challenge: Multi-Task Learning and Ambivalence/Hesitancy Video Recognition","abstract":"This article presents our results for the 11th Affective Behavior Analysis in-the-Wild (ABAW) competition. For multi-task learning with simultaneous prediction of valence, arousal, facial expressions, and action units on s-Aff-Wild2 dataset, we use frozen lightweight facial extractors, MT-EmotiDDAMFN and MT-EmotiEffNet-B0, with separate heads and systematic post-processing: temporal Gaussian smoothing, per-class expression bias, AffectNet blending, per-AU threshold tuning, and weighted backbone fusion. On the official validation set, our ensemble significantly exceeds the performance of the ConvNeXt baseline. For ambivalence/hesitancy video recognition on the expanded BAH dataset, we extend the audiovisual pipeline to video-level Macro F1 by late fusion of face, HuBERT audio, and RoBERTa text classifiers, temporal aggregation, and a global-text gate. Frame-level Weighted F1 on validation set rises from 0.74 in ABAW-8 to 0.79, while the best public-test video-level Macro F1 reaches 0.73. In both tasks, competitive performance is achieved without fine-tuning heavy backbones. These results indicate that systematic prediction calibration and lightweight multimodal fusion can rival substantially heavier end-to-end approaches while offering improved efficiency and deployment flexibility.","authors":["Aleksei Bakin","Andrey V. Savchenko"],"published":"2026-07-14T13:45:48Z","updated":"2026-07-14T13:45:48Z","abstract_url":"https://arxiv.org/abs/2607.12774v1","html_url":"https://arxiv.org/html/2607.12774v1","pdf_url":"https://arxiv.org/pdf/2607.12774v1.pdf","matched_keywords":["video","multimodal"],"source_used":"html","source_text_chars":41611,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, multimodal 相关；摘要显示其主要贡献为：This article presents our results for the 11th Affective Behavior Analysis in-the-Wild (ABAW) competition. For multi-task learning with simultaneous prediction of valence, arousal, facial expressions, and action units on s-Aff-Wild2 dataset, we use frozen lig...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-15T03:54:58+00:00","status":"fallback"},"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12764v1","title":"EvoGraph-R1: Self-Evolving Multimodal Knowledge Hypergraphs for Agentic Retrieval","abstract":"Retrieval-augmented generation (RAG) has emerged as a critical paradigm for grounding Multimodal Large Language Models (MLLMs) in external knowledge. Recent GraphRAG methods introduce structured entity-relation graphs to improve retrieval and reasoning. However, they remain limited by treating knowledge graphs as static data structures built offline and queried in a single pass. This static paradigm misaligns with the interactive, iterative nature of knowledge-intensive reasoning, creating three bottlenecks: (i) text-centric fragmentation that impedes cross-modal reasoning, (ii) frozen structures unable to incorporate new evidence or correct errors, and (iii) rigid single-pass retrieval without adaptive refinement. To overcome these limitations, we introduce EvoGraph-R1, a self-evolving GraphRAG framework that reconceptualizes knowledge graphs as dynamic environments shaped through agent interactions. We formulate retrieval as a Markov Decision Process (MDP) where the agent observes the graph state and executes actions to query (GraphRetrieve), expand (WebSearch), refine (GraphEdit), or terminate (Answer) the reasoning. These actions reshape the hypergraph structure and generate feedback signals that guide subsequent evolution. Through this closed loop, the hypergraph evolves by integrating new evidence, correcting errors, and refining structure to support multi-hop reasoning. Experiments on multimodal VQA and text QA benchmarks demonstrate substantial improvements over existing RAG baselines in accuracy, coverage, and traceability, establishing self-evolving knowledge graphs as a fundamental paradigm across modalities.","authors":["Jiashi Lin","Changhong Jiang","Xiangru Lin","Ruifei Zhang","Xinyi Zhu","Jiyao Liu","Cheng Tang","Ye Du","Shujian Gao","Junzhi Ning","Lihao Liu","Ziyan Huang","Tianbin Li","Jin Ye","Junjun He"],"published":"2026-07-14T13:34:07Z","updated":"2026-07-14T13:34:07Z","abstract_url":"https://arxiv.org/abs/2607.12764v1","html_url":"https://arxiv.org/html/2607.12764v1","pdf_url":"https://arxiv.org/pdf/2607.12764v1.pdf","matched_keywords":["retrieval","agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12756v1","title":"VisCo: Leveraging Large Language Models as Intrinsic Encoders for Visual Token Compression","abstract":"Vision-language models (VLMs) process large numbers of visual tokens, resulting in substantial inference latency and memory overhead. This has motivated extensive research on visual token compression. While training-free strategies rely on heuristic metrics and suffer significant performance degradation under high compression ratios, many training-based methods introduce external compression modules that force the VLM backbone to adapt, incurring substantial retraining cost and compromising VLMs' priors. Effective visual token compression hinges on strong information encoding, a capability already present in pretrained VLMs but underutilized by existing approaches. Motivated by this, we propose VisCo, a training-efficient self-compression framework that reuses the pretrained VLM itself as an intrinsic compressor. VisCo is a parameter-sharing autoencoder that compresses visual information using a small set of memory tokens and transfers hierarchical information from encoding to decoding. Experiments show that VisCo surpasses prior methods across all evaluated compression ratios, with larger gains under more aggressive compression, and remains stable even in the extreme single-token setting. Moreover, when combined with the original visual tokens, the learned memory tokens can even improve the base model, suggesting that VisCo captures complementary representations beyond compression.","authors":["Yupeng Zheng","Kai Zou","Bin Liu","Nenghai Yu"],"published":"2026-07-14T13:21:36Z","updated":"2026-07-14T13:21:36Z","abstract_url":"https://arxiv.org/abs/2607.12756v1","html_url":"https://arxiv.org/html/2607.12756v1","pdf_url":"https://arxiv.org/pdf/2607.12756v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12753v1","title":"RFMSR: Residual Flow Matching for Image Super-Resolution","abstract":"Image super-resolution (ISR) has witnessed remarkable progress with diffusion models and flow matching. The dominant text-to-image (T2I) based approaches leverage large-scale foundation models as generative priors, achieving impressive perceptual quality but at the cost of massive model sizes and prohibitive training expenses. Recent flow-matching-based vision-only approaches have made significant strides; however, they adopt standard flow formulations that transport from a pure Gaussian prior to the data distribution, discarding the rich structural information already present in the low-quality (LQ) input. Furthermore, existing single-step acceleration techniques often forfeit the model's multi-step inference capability. In this paper, we propose Residual Flow Matching for Image Super-Resolution (RFMSR), a vision-only framework that centers the source distribution at the LQ latent, reducing transport distance and preserving structural priors throughout the flow trajectory. We further introduce a two-phase training strategy: Phase I pretrains the velocity field via conditional flow matching, while Phase II applies end-to-end supervision to the single-step prediction while retaining the velocity loss across all timesteps, achieving high-quality single-step generation without sacrificing multi-step refinement. Extensive experiments demonstrate that RFMSR achieves comparable or even superior perceptual quality compared to state-of-the-art (SOTA) methods. The source code is available at https://github.com/Faze-Hsw/RFMSR.","authors":["Shuwei Huang","Tianyao Luo","Jicheng Liu","Daizong Liu","Pan Zhou"],"published":"2026-07-14T13:19:36Z","updated":"2026-07-14T13:19:36Z","abstract_url":"https://arxiv.org/abs/2607.12753v1","html_url":"https://arxiv.org/html/2607.12753v1","pdf_url":"https://arxiv.org/pdf/2607.12753v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12752v1","title":"Hallo4D: Multi-Modal Hallucination Mitigation for Consistent Spatio-Temporal Generation","abstract":"While recent advances in 3D generation have enabled impressive visual synthesis, existing methods often rely on 2D diffusion supervision without explicit mechanisms for geometric consistency, leading to spatial hallucinations such as duplicated structures and misaligned geometry. These issues become more severe in 4D generation, where maintaining consistency across viewpoints and temporal evolution introduces additional challenges, including jitter, identity flicker, and structural drift. We present \\textbf{Hallo4D}, a unified and model-agnostic framework for mitigating spatiotemporal hallucinations in 3D and 4D content generation. Hallo4D introduces a generation-detection-correction paradigm that leverages large multimodal language models (LMMs) to identify and summarize spatial and temporal inconsistencies from multi-view and multi-frame renderings. These insights guide a consensus-driven image-space consistency optimization, where an LMM-based selector evaluates candidate corrections through multi-model voting, without requiring retraining or architectural modifications. To further improve temporal consistency and optimization efficiency, Hallo4D incorporates motion-aware keyframe sampling, LMM-guided initialization, and appearance alignment. We additionally introduce exposure-aware optimization and visibility pruning to enhance robustness under challenging viewpoints. Extensive experiments demonstrate that Hallo4D consistently outperforms strong baselines across diverse 3D and 4D generation settings, providing a scalable and generalizable solution for consistency-aware content generation.","authors":["Hongbo Wang","Huaibo Huang","Jie Cao","Jin Liu","Haoyang Tong","Ran He"],"published":"2026-07-14T13:19:06Z","updated":"2026-07-14T13:19:06Z","abstract_url":"https://arxiv.org/abs/2607.12752v1","html_url":"https://arxiv.org/html/2607.12752v1","pdf_url":"https://arxiv.org/pdf/2607.12752v1.pdf","matched_keywords":["3d","multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12748v1","title":"Weakly Supervised Spatio-Temporal Candidate Discovery of Dairy Farm Sites from Seasonal Satellite Imagery","abstract":"Farm site discovery from satellite imagery is a spatiotemporal candidate ranking problem because farm evidence is distributed across pasture, field boundaries, roads, buildings, and seasonal vegetation patterns. Direct farm labels are often incomplete, which makes fully supervised detection difficult. This paper proposes a weakly supervised pipeline for ranking dairy farm candidate clusters from seasonal Sentinel imagery and open map priors. The method uses aligned spring, summer, and autumn image tiles from County Cork, Ireland, with spectral bands, vegetation indices, built area indices, and a pasture channel. A Barlow Twins encoder learns multi-season tile embeddings without farm labels. In parallel, weak OpenStreetMap farm priors are split into a prior and a held-out set. Prior features support a rule-based tile score that combines farm proximity, seasonal pasture evidence, and summer greenness, while held-out features are reserved only for proxy evaluation. The rule score is smoothed over a spatial representation graph using geographic proximity and embedding similarity, and high-scoring tiles are grouped into ranked candidate clusters. From 26,722 valid tiles, the main run selects 535 high-confidence tiles and forms 71 candidate clusters. The top 5 clusters achieve 0.60 precision within 500 m and 0.80 precision within 1000 m of held-out OpenStreetMap farm features. The top 10 clusters achieve 0.40 precision within 500 m and 0.80 precision within 1000 m. The results show that seasonal representation learning and weak geographic priors can reduce large satellite image collections into compact candidate sets for human review.","authors":["Usman Haider","Fatima Khalid","Karl Mason"],"published":"2026-07-14T13:17:18Z","updated":"2026-07-14T13:17:18Z","abstract_url":"https://arxiv.org/abs/2607.12748v1","html_url":"https://arxiv.org/html/2607.12748v1","pdf_url":"https://arxiv.org/pdf/2607.12748v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12680v1","title":"ReflectVLN: Training Vision-Language Navigation Agents with Reflective Reasoning","abstract":"Existing vision-language navigation methods often couple a VLM with waypoint decoders to produce multi-step action plans, but they typically lack an explicit closed-loop mechanism for tracking semantic progress, diagnosing execution failures, and recovering from error accumulation in long-horizon navigation. To address this gap, we propose ReflectVLN, an agentic VLN framework that organizes decision-making through bidirectionally interactive intention and execution agents. The intention agent performs subtask decomposition and reflection, generating executable subtask descriptions as corrective plans. Conditioned on these descriptions, the execution agent grounds them into short-horizon actions under current observations while monitoring sub-goal progress and detecting off-track behavior. Crucially, ReflectVLN enables closed-loop bidirectional communication: the execution agent emits progress and deviation signals to trigger reflection and subtask updates on demand, and the intention agent returns structured guidance that reconditions subsequent actions for recovery. To encourage temporally coherent decisions with interpretable intermediate rationales, we introduce Action Chain-of-Thought (Action-CoT), a path-conditioned dual-query training scheme for action generation. Experiments on standard VLN benchmarks show that ReflectVLN improves success rates and path efficiency under a constrained data budget, with favorable training cost and fewer high-level intention calls at inference time, while providing interpretable intermediate decisions for analysis and collaboration. Code is available at: https://github.com/AIprogrammer/ReflectVLN","authors":["Jiahang Wang","Yirong Yang","Yanqing Zhu","Minghua Luo","Shichao Xie","Fei Liu","Mu Xu"],"published":"2026-07-14T12:09:33Z","updated":"2026-07-14T12:09:33Z","abstract_url":"https://arxiv.org/abs/2607.12680v1","html_url":"https://arxiv.org/html/2607.12680v1","pdf_url":"https://arxiv.org/pdf/2607.12680v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12678v1","title":"Text-Aided Multi-Modal Panoptic Symbol Spotting for CAD Floor Plan Drawings","abstract":"Computer-Aided Design (CAD) floor plan drawings contain both graphical primitives and textual annotations, which provide complementary geometric and semantic cues for intelligent design understanding. Among CAD analysis tasks, panoptic symbol spotting has become increasingly important with the growing demand for industrial digitalization and deep learning-based automation. However, most existing methods remain primarily primitive-centric and underexploit textual annotations, despite their critical semantic value. Even the few text-aware approaches often treat annotations only superficially, without properly modeling complex syntax and hierarchical semantics of CAD annotations, which leads to semantic loss and suboptimal spotting performance. To address these limitations, we propose TextCAD, a multimodal framework that jointly models graphical primitives and textual annotations for panoptic symbol spotting. Specifically, we design a Type-Attribute Correlation Encoder (TACE) to explicitly encode the compositional semantics within annotations by jointly modeling their types and attributes. We further introduce a Semantic Hierarchy Alignment framework with Multi-level Semantic Filtering (MSF) and primitive downsampling, which adaptively aligns annotation semantics with graphical primitives at different semantic levels and enables accurate cross-modal semantic injection and fusion. Experiments on real-world building-design datasets show that TextCAD effectively improves symbol spotting performance and achieves state-of-the-art results.","authors":["Yan Gong","Bohao Li","Bowen Du","Junchen Ye"],"published":"2026-07-14T12:07:44Z","updated":"2026-07-14T12:07:44Z","abstract_url":"https://arxiv.org/abs/2607.12678v1","html_url":"https://arxiv.org/html/2607.12678v1","pdf_url":"https://arxiv.org/pdf/2607.12678v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12630v1","title":"Instance-Enriched Semantic Maps for Visual Language Navigation","abstract":"Visual Language Navigation (VLN) aims to enable an embodied agent to navigate complex environments by following natural language instructions. Recent approaches build semantic spatial maps and leverage Large Language Models (LLMs) for reasoning and decision making. Despite these advances, existing systems lack instance-level object detail and robustness to diverse user queries, limiting reliable navigation in complex indoor environments. To address these limitations, we propose Instance-Enriched Semantic Maps, a unified framework with three key contributions: (1) Instance-level two-and-a-half-dimensional (2.5D) rich information mapping that constructs maps from color and depth observations via open-vocabulary panoptic segmentation, preserving vertical distinctions and capturing small objects, while storing diverse semantic attributes and natural language captions enriched with room-level context. (2) Robust query processing via LLM-based target selection, which dynamically routes queries across type-specialized experts and integrates their outputs through score-level fusion, enabling consistent goal selection across diverse query formulations. (3) Storage-efficient semantic representation that achieves approximately 96% reduction compared to three-dimensional (3D) scene-graph approaches while preserving sufficient spatial information for navigation. The proposed 2.5D representation outperforms the 3D baseline by over 27% in prediction-normalized Area Under the Curve (AUC). In navigation experiments, our method achieves over 17% improvement in object retrieval and over 23% in navigation success compared to the baseline across diverse query types. The project page is available at https://rcilab.github.io/iesm_vln.","authors":["Jiho Hong","Eunae Kang","Sanghyun Kim","Young-Sik Shin"],"published":"2026-07-14T11:09:48Z","updated":"2026-07-14T11:09:48Z","abstract_url":"https://arxiv.org/abs/2607.12630v1","html_url":"https://arxiv.org/html/2607.12630v1","pdf_url":"https://arxiv.org/pdf/2607.12630v1.pdf","matched_keywords":["retrieval","3d","agent","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12625v1","title":"KnowAct-GUIClaw: Know Deeply, Act Perfectly, Personal GUI Assistant with Self-Evolving Memory and Skill","abstract":"OpenClaw has emerged as a leading agent framework for complex task automation, yet it faces insufficient cross-platform GUI interaction support and a well-built self-evolution mechanism. These flaws limit its adaptation to diverse device ecosystems and prevent performance improvements through continuous learning from execution experience. To resolve these issues, we propose the Know Deeply, Act Perfectly paradigm for personal assistants, which holds that accumulated user interaction and task-running experience directly improve execution accuracy and efficiency, unifying cognitive comprehension and operational execution. Based on this paradigm, we introduce KnowAct-GUIClaw, a novel Know-Route-Act-Reflect framework designed to address OpenClaw's GUI manipulation deficits and break through its cross-platform and recursive self-improvement constraints. First, the host agent leverages accumulated interaction experience and task-relevant knowledge for long-horizon task decomposition and allocation (Know). Second, a pluggable GUI subagent with an experience-attributable memory system (Know) and self-evolving skill library (Act), enabling seamless cross-platform migration and fast-path integration. Especially, this framework continuously stores user profiles and feedback to improve the accuracy of task decomposition and tool calls. Extensive experiments across Android, iOS, HarmonyOS and Windows show that KnowAct-GUIClaw achieves superior efficiency, accuracy and cross-platform adaptability. Especially, the GUIClaw with open-source Kimi-2.6 models achieves the best performance (64.1%) on the long-horizon MobileWorld benchmark, beating all agentical frameworks and closed-source agentical models, e.g., Seed-2.0-Pro and GPT-5.5. Additionally, the knowledgeable memory and execution skills supported by our framework are transferable across diverse base models, improving by 8.5% with Kimi-2.6.","authors":["Yunxin Li","Jinchao Li","Shibo Su","Zhenran Xu","Chenrui Zhao","Tongshu Bian","Xiaoman Liang","Meishan Zhang","Baotian Hu","Min Zhang"],"published":"2026-07-14T11:04:01Z","updated":"2026-07-14T11:04:01Z","abstract_url":"https://arxiv.org/abs/2607.12625v1","html_url":"https://arxiv.org/html/2607.12625v1","pdf_url":"https://arxiv.org/pdf/2607.12625v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12621v1","title":"Towards Vision-Free CIR: Attribute-Augmented Scoring and LLM-Based Reranking for Zero-Shot Composed Image Retrieval","abstract":"Recent work has shown that \"Vision-Free'' approaches (representing images as text) can be effective for standard image retrieval tasks. However, it remains unclear whether this paradigm can effectively handle a more complex, multimodal task, Composed Image Retrieval (CIR), due to the inherent information loss in textual descriptions. In this paper, we introduce a Vision-Free CIR framework that addresses this challenge through two key techniques: (1) Attribute-Augmented Hybrid Scoring, which compensates for lost visual details via explicit attribute matching, and (2) LLM-Based Reranking, which verifies semantic consistency of top candidates. Experiments on the open-domain CIRR dataset show that our approach outperforms existing Zero-shot CIR methods (44.04% R@1, +8.79%). On FashionIQ, our results highlight the trade-off between semantic reasoning and fine-grained visual matching. Ablation studies reveal that both attribute-augmented scoring and LLM-Based Reranking consistently improve performance.","authors":["Ryotaro Shimada","Yu-Chieh Lin","Yuji Nozawa","Youyang Ng","Osamu Torii","Yusuke Matsui"],"published":"2026-07-14T10:58:12Z","updated":"2026-07-14T10:58:12Z","abstract_url":"https://arxiv.org/abs/2607.12621v1","html_url":"https://arxiv.org/html/2607.12621v1","pdf_url":"https://arxiv.org/pdf/2607.12621v1.pdf","matched_keywords":["retrieval","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12602v1","title":"Decouple and Reason: Anatomically Guided Two-Stage Voxel-Level Grounding of Free-Text Findings in 3D Chest CT","abstract":"Automatic voxel-level grounding of free-text findings in 3D chest Computed Tomography (CT) is critical for clinical interpretability. However, this task remains highly challenging due to the intricate spatial complexity of large 3D volumes and the heterogeneity of free-text findings. Existing end-to-end approaches often struggle to simultaneously learn the localized feature representations required for accurate 3D segmentation and the complex semantic understanding needed for text alignment, leading to suboptimal grounding performance. To overcome this fundamental limitation, we propose a novel decoupled framework that disentangles the problem into two specialized stages: (1) class-agnostic lesion segmentation and (2) text-volume reasoning. This structural separation allows the model to first extract candidate sub-volumes by localizing potential abnormalities. Subsequently, intensive cross-modal reasoning is performed to align these localized sub-volumes with free-text medical findings. To resolve the spatial ambiguities inherent in local regions, the reasoning module is augmented with explicit anatomical guidance, utilizing relative spatial coordinates and lung lobe priors. Evaluated on the ReXGroundingCT benchmark, our method achieves state-of-the-art performance in overall grounding quality on the official leaderboard. These results demonstrate that decoupling detection from reasoning is a highly effective paradigm for handling the complexity of 3D medical visual grounding. Our code is publicly available at https://github.com/khuhm/DAGG.","authors":["Kwang-Hyun Uhm","Inhwa Son","Sung-Jea Ko"],"published":"2026-07-14T10:26:14Z","updated":"2026-07-14T10:26:14Z","abstract_url":"https://arxiv.org/abs/2607.12602v1","html_url":"https://arxiv.org/html/2607.12602v1","pdf_url":"https://arxiv.org/pdf/2607.12602v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12592v1","title":"WanToFight: Real-Time Generative Game Engine for Multi-Player Combat Interaction","abstract":"We present WanToFight, a generative game engine that simulates real-time, two-player The King of Fighters '97 (KOF~'97) gameplay from keyboard input. Prior generative game engines target either single-player first-person settings or non-real-time cooperative scenarios; multi-player control, real-time inference, complex physical interaction, and adversarial gameplay have not been jointly addressed. WanToFight closes this gap with three components built on the Wan-1.3B video diffusion transformer: a streaming autoregressive generator with block-causal attention and a rolling KV cache; a visually grounded Player Association module that binds each player's keyboard signal to a character identity; and a gated, locally causal keyboard injection module trained with a single-player-to-full-gameplay curriculum. A four-step DMD-distilled student paired with a pruned VAE decoder sustains 30FPS at 512x384 on a single NVIDIA RTX 5090 over the duration of a complete match. To our knowledge, WanToFight is the first generative game engine to combine multi-player control, real-time inference, complex physical interaction, and adversarial gameplay in one system.","authors":["Li Hu","Guangyuan Wang","Peng Zhang","Bang Zhang"],"published":"2026-07-14T10:10:03Z","updated":"2026-07-14T10:10:03Z","abstract_url":"https://arxiv.org/abs/2607.12592v1","html_url":"https://arxiv.org/html/2607.12592v1","pdf_url":"https://arxiv.org/pdf/2607.12592v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12557v1","title":"Gaussian Mixture Modeling for Event-Aware Visual Allocation in Long Video Understanding","abstract":"Large Vision-Language Models (LVLMs) face significant challenges in long video understanding due to the excessive computational cost and information loss associated with uniform sampling. Existing keyframe selection methods often treat video frames as atomic entities and allocate visual budgets equally, thereby overlooking high-level semantic structures and introducing substantial redundancy. To address these limitations, we propose GMM-EVA (Gaussian Mixture Modeling for Event-Aware Visual Allocation), which leverages Gaussian Mixture Models to model event-level structure from discrete frame-wise observations. A differentiated allocation strategy is then applied to preserve one primary high-resolution keyframe per event for high-fidelity detail, while utilizing lower-resolution secondary keyframes to maintain temporal context and optimize token budgets. GMM-EVA is a training-free, plug-and-play framework that generalizes robustly across various relevance measures and downstream LVLMs. Extensive experiments on multiple long video benchmarks demonstrate that our method significantly outperforms uniform sampling. Notably, GMM-EVA achieves comparable performance to baseline selection methods while utilizing only approximately half of the visual token budget, highlighting its superior efficiency and effectiveness.","authors":["Yifan Lu","Ziqi Zhang","Chunfeng Yuan","Jun Gao","Bing Li","Weiming Hu"],"published":"2026-07-14T09:27:25Z","updated":"2026-07-14T09:27:25Z","abstract_url":"https://arxiv.org/abs/2607.12557v1","html_url":"https://arxiv.org/html/2607.12557v1","pdf_url":"https://arxiv.org/pdf/2607.12557v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12556v1","title":"CGRL: Concept-Guided Pruning and Representation Learning for Whole-Slide Image Classification","abstract":"Weakly supervised whole-slide image (WSI) classification is widely used in computational pathology because slide-level labels are easier to obtain than dense region annotations. Existing multiple instance learning (MIL) methods often aggregate large bags of patch embeddings using mainly visual cues, which can retain many non-informative patches and provide weak alignment between instance features and class-level disease semantics. We propose Concept-Guided Pruning and Representation Learning (CGRL), a simple framework that introduces class-level concept prototypes derived from disease prompts into the MIL pipeline. First, concept-relevance pruning ranks patch instances by their similarity to class concepts and retains the top-K concept-relevant patches for downstream MIL aggregation. Second, concept-guided contrastive representation learning constructs class-wise positive and negative patch sets from the same similarity matrix and optimizes target-class, symmetric auxiliary, and cross-class separation objectives, thereby regularizing the projected concept space. We evaluate CGRL on TCGA-BRCA and TCGA-NSCLC using multiple representative MIL methods. Experimental results show that CGRL improves several model-dataset combinations, with gains depending on the downstream MIL model and dataset. It achieves particularly clear improvements in accuracy and macro-F1 while reducing computational cost through concept-relevance pruning. These findings demonstrate that class-level semantic concepts provide an effective and practical prior for patch selection and representation learning in weakly supervised computational pathology.","authors":["Thuc Huynh","Tuan Le","Doanh C. Bui"],"published":"2026-07-14T09:25:52Z","updated":"2026-07-14T09:25:52Z","abstract_url":"https://arxiv.org/abs/2607.12556v1","html_url":"https://arxiv.org/html/2607.12556v1","pdf_url":"https://arxiv.org/pdf/2607.12556v1.pdf","matched_keywords":["representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12539v1","title":"DiTailed: Ensuring Visual Object Consistency in Text-Image-to-Image Flow Matching Models","abstract":"Despite remarkable progress in text-guided image editing, generative models frequently fail to preserve visual object consistency, defined as the preservation of a subject's key attributes throughout the editing process. We address this limitation through three contributions. First, we introduce ABO-Edit, a dataset specifically designed to study object consistency, comprising over 12,000 triplets of source images, editing prompts, and high-quality target images rendered from artist-designed 3D assets, with multi-view coverage and human-verified quality control. Second, we uncover an overlooked property of image-editing rectified flow models: the conditioning embedding space, not directly supervised during training, encodes a prediction of the final generated image even at high noise levels. Third, exploiting this finding, we propose FlowMirror, a parameter-free auxiliary loss that supervises this conditioning embedding space. Without architectural changes, our method improves generation quality across several metrics over baselines.","authors":["Francesco Taioli","Daniel Coelho","Iaroslav Melekhov","Roberto Alcover-Couso","Jose Miguel Grande Saiz","Virginia Fernandez Arguedas","Artur Bekasov"],"published":"2026-07-14T09:09:52Z","updated":"2026-07-14T09:09:52Z","abstract_url":"https://arxiv.org/abs/2607.12539v1","html_url":"https://arxiv.org/html/2607.12539v1","pdf_url":"https://arxiv.org/pdf/2607.12539v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12503v1","title":"DynTrace: Tracking Dynamic Object Evidence for 4D Spatio-Temporal Reasoning in MLLMs","abstract":"4D spatio-temporal reasoning, jointly modeling 3D spatial structure and temporal evolution, is essential for understanding dynamic worlds and enabling embodied interaction. While current Multimodal Large Language Models (MLLMs) show strong capabilities in static scene understanding and coarse-grained 4D tasks, they still have notable limitations in continuous dynamic scene perception, especially in tracking dynamic object evidence for coherent 4D spatio-temporal reasoning. This shortcoming stems mainly from relying on sparse frame-level observations, fragmenting continuous dynamic cues and leaving models unable to disentangle genuine object dynamics from camera-induced apparent motion. Inspired by humans tracking dynamic cues while compensating for viewpoint changes, we propose DynTrace, a training-free framework for 4D spatio-temporal reasoning with two complementary components. Dynamic Trajectory Visualization (DTV) reprojects world-coordinate trajectories onto the image plane, providing geometry-informed visual priors that disentangle genuine object dynamics from camera-induced apparent motion. Meanwhile, the Dynamic Trace Token (DT-Token), organized into a Dynamic Trace Graph (DTG), tracks object-level dynamic cues, trace evolution, and key moments, maintaining continuous dynamic object evidence for coherent 4D reasoning. Together, these two components equip MLLMs with continuously tracked dynamic object evidence, grounded in geometry-informed visual priors and structured spatio-temporal traces. DynTrace consistently improves open-source MLLMs, achieving state-of-the-art results on Dyn-Bench, VLM4D, and DSI-Bench, validating the importance of tracking dynamic object evidence for robust 4D spatio-temporal reasoning.","authors":["Rongxin Gao","Yuzhi Huang","Dongxuan Liu","Chu Li","Zhenye Wang","Jie Wu","Shuzhao Xie","Jingyan Jiang","Xinghao Ding","Xiaotong Tu","Yue Huang"],"published":"2026-07-14T08:35:07Z","updated":"2026-07-14T08:35:07Z","abstract_url":"https://arxiv.org/abs/2607.12503v1","html_url":"https://arxiv.org/html/2607.12503v1","pdf_url":"https://arxiv.org/pdf/2607.12503v1.pdf","matched_keywords":["3d","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12497v1","title":"TerraLogic: A Benchmark for Hierarchical Geospatial Reasoning in Earth Observation","abstract":"Beyond perception, reasoning is essential in remote sensing for advanced interpretation, inference, and decision-making. Recent advances in large language models (LLMs) have enabled tool-augmented agents that leverage external tools to perform complex analytical tasks. However, existing studies in remote sensing primarily focus on perception-oriented tasks, leaving cognitive geospatial reasoning largely underexplored. To address this gap, we introduce TerraLogic, a benchmark for geospatial reasoning. TerraLogic comprises 545 scenario-driven, hierarchy-aware tasks, such as hazard vulnerability assessment, urban heat island analysis, and forest fragmentation dynamics, spanning optical, Synthetic Aperture Radar (SAR), and infrared (IR) imagery. It advances evaluation beyond recognition and monitoring toward cognitive-level geospatial analysis. To facilitate evaluation on TerraLogic, we further propose HieraPlan, a tool-augmented agent that organizes toolkits into functional hierarchies and performs fault-tolerant reasoning. HieraPlan enables structured abstraction, robust recovery from tool failures, and stable long-horizon planning. Extensive experiments demonstrate that current approaches struggle with hierarchical geospatial reasoning, while HieraPlan provides a strong baseline with improved reasoning, cross-modal generalization, and error handling. The dataset and agent code are publicly available at https://github.com/Ireliya/TerraLogic.","authors":["Yuhang Yan","Linchao Mou","Bokang Yang","Qingyu Li"],"published":"2026-07-14T08:30:45Z","updated":"2026-07-14T08:30:45Z","abstract_url":"https://arxiv.org/abs/2607.12497v1","html_url":"https://arxiv.org/html/2607.12497v1","pdf_url":"https://arxiv.org/pdf/2607.12497v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12495v1","title":"RealSkin: Spatio-Spectral Partial Neural Adjoint Maps for Image-to-3D Attribute Transfer","abstract":"Creating photorealistic 3D assets requires bridging the appearance gap between real-world observations and synthetic models. A promising approach is to transfer visual attributes from real images onto synthetic 3D surfaces. Traditional methods struggle with resolution mismatch and the inherent discreteness of point correspondences. In contrast, resolution-robust functional maps enable smooth attribute propagation but rely on near-isometry assumptions and topological consistency. To address these limitations, we propose RealSkin, a self-supervised framework that performs correspondence optimization in a learned spectral domain, guided by spatial correspondences. We first introduce a spatial-guided registration algorithm to establish coarse correspondences under severe topological discrepancies. To relax strict isometric assumptions and handle partial correspondences, we further design a spectral-aware neural adjoint network that incorporates partial correspondences into a neural function space and models non-isometric residuals for correspondence refinement. Experimental results demonstrate that our method achieves state-of-the-art performance on challenging real-to-synthetic scenarios. The code will be publicly released.","authors":["Jing Li","Yawei Luo","Xiangze Meng","Ying Li","Tieru Wu","Rui Ma"],"published":"2026-07-14T08:27:28Z","updated":"2026-07-14T08:27:28Z","abstract_url":"https://arxiv.org/abs/2607.12495v1","html_url":"https://arxiv.org/html/2607.12495v1","pdf_url":"https://arxiv.org/pdf/2607.12495v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12477v1","title":"Self in Space: Benchmarking Self-Awareness and Spatial Cognition in UAV Embodied Intelligence","abstract":"Autonomous UAV systems increasingly rely on multimodal large language models (MLLMs) to operate in complex real-world environments. Such embodied scenarios require not only understanding the surrounding space but also maintaining a coherent representation of the agent itself. However, existing UAV-oriented approaches and benchmarks remain largely environment-centric, primarily focusing on spatial understanding tasks, with the agent's self-awareness remaining implicit. To address this gap, we introduce SIS-Bench, a benchmark for evaluating embodied spatial intelligence in UAV scenarios under a unified self-in-space formulation. SIS-Bench organizes evaluation along two complementary dimensions, space and self, and a three-level hierarchy of perception, memory, and reasoning. It contains 4,856 question--answer pairs across 13 tasks derived from 1,646 real-world UAV videos through a task-conditioned construction pipeline with expert verification.Extensive evaluations reveal that current MLLMs exhibit fundamental limitations in modeling dynamic and agent-centered processes. In particular, we observe a clear imbalance between spatial cognition and self-awareness, as well as a progressive performance degradation across cognitive levels.Motivated by these findings, we further explore a motion-aware representation that incorporates self-related dynamics through optical flow and visual feature fusion. Experimental results show that modeling agent motion consistently improves perception and memory performance, not only in spatial cognition but also in self-awareness, and generalizes to downstream UAV decision-making tasks.Our results highlight the importance of self-awareness for advancing embodied spatial intelligence, and provide both a new benchmark and empirical evidence for motion-aware self-in-space modeling.","authors":["Zhishan Zou","Guoyan Sun","Zhiwei Wei","Jiancheng Pan","Yujie Li","Mugen Peng","Wenjia Xu"],"published":"2026-07-14T08:04:31Z","updated":"2026-07-14T08:04:31Z","abstract_url":"https://arxiv.org/abs/2607.12477v1","html_url":"https://arxiv.org/html/2607.12477v1","pdf_url":"https://arxiv.org/pdf/2607.12477v1.pdf","matched_keywords":["video","agent","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12464v1","title":"Steering Diffusion Models via Class-Contrastive Influence for Few-Shot Medical Classification","abstract":"When labeled data are scarce, off-the-shelf diffusion models can augment training sets for few-shot medical image classification, but not all generated samples are equally useful for the downstream task. Existing approaches largely improve synthetic data by increasing realism, diversity, or domain adaptation, while overlooking a more fundamental question: how should sample usefulness for classification be measured and optimized? We address this with Class-Contrastive Influence (C2I), a criterion that quantifies a sample's usefulness through its gradient-based influence on the classifier. We find that effective samples exhibit a strong C2I gap: their loss gradients align with validation gradients from the same class and oppose those from other classes. Our analysis further suggests that such high-C2I samples are hard, boundary-proximal examples that help refine the decision boundary and improve robustness. Building on this insight, we fine-tune diffusion models with reinforcement learning using a C2I-based reward to steer generation toward class-informative samples. Across several few-shot medical imaging benchmarks, C2I-guided generation improves downstream accuracy and robustness over diffusion-based augmentation baselines, showing that synthetic augmentation is most effective when guided by task usefulness rather than image quality alone.","authors":["Jeeyung Kim","Erfan Esmaeili","Qiang Qiu"],"published":"2026-07-14T07:45:46Z","updated":"2026-07-14T07:45:46Z","abstract_url":"https://arxiv.org/abs/2607.12464v1","html_url":"https://arxiv.org/html/2607.12464v1","pdf_url":"https://arxiv.org/pdf/2607.12464v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12433v1","title":"ARDepth: Auto-regressive Monocular Depth Estimation with Progressive Visual Conditioning","abstract":"Diffusion models have recently become the dominant paradigm for monocular depth estimation (MDE). However, they implicitly assume that depth can be recovered as a globally smooth field through iterative denoising, which does not explicitly reflect the piecewise and scale-dependent organization of scene geometry. In practice, geometric structure emerges progressively across spatial scales, where coarse layout, surfaces, and boundaries are constructed in a hierarchical manner. Motivated by this observation, we introduce ARDepth, which formulates depth estimation as structured auto-regressive generation. Instead of recovering depth through global refinement, ARDepth progressively constructs depth representations as spatial resolution increases. To support this generative process, we introduce Scale-Progressive Conditioning (SPC) to inject multi-scale visual features at each generation stage, and Semantic-Aware Guidance (SAG) to provide scene-level semantic priors that enhance global structural consistency. Together, these designs enable the model to capture fine-grained local details while maintaining coherent global geometry. Empirical results demonstrate that our approach achieves strong performance and produces structurally consistent depth predictions across scales, validating auto-regressive generation as a promising alternative paradigm for geometric modeling.","authors":["Zijie Wang","Wei Zhang","Weiming Zhang","Xiao Tan","Weikai Chen","Xiaoxu Li","Guanbin Li"],"published":"2026-07-14T07:06:46Z","updated":"2026-07-14T07:06:46Z","abstract_url":"https://arxiv.org/abs/2607.12433v1","html_url":"https://arxiv.org/html/2607.12433v1","pdf_url":"https://arxiv.org/pdf/2607.12433v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12429v1","title":"More Than Where You Are: Learning Semantics, Structure, and Geometry from Cross-View Localization","abstract":"Consistent cross-view understanding under extreme viewpoint changes is essential for spatial intelligence, as it enables models to recognize the same scene across extreme viewpoint gaps. Cross-view localization naturally provides a promising pathway toward this ability, as it requires a model to align ground-view imagery with geo-referenced satellite-view imagery despite drastic appearance changes to estimate camera poses. Recent visual foundation models have made this long-standing localization problem increasingly feasible by providing rich 2D representations for cross-view matching. However, we argue that cross-view localization should not be viewed merely as 2D matching or pose estimation. In this work, we revisit cross-view localization as more than pose estimation and investigate how it can help the model develop consistent cross-view understanding under extreme viewpoint changes, including stable semantics, reliable structure, and transferable geometry. We identify three key limitations of existing methods that prevent them from achieving this. They usually lack explicit 3D grounding, rely on strict point-wise matching that can weaken semantic consistency, and learn from an absolute objective that provides limited guidance for geometric reasoning. To address these limitations, we propose CROSS, a unified cross-view localization framework built upon 3D-grounded alignment, structure-aware matching, and hypothesis ranking. This formulation makes structure learning an intrinsic requirement, encourages semantic representations to remain stable, and enables the model to acquire transferable geometry. Extensive experiments on the KITTI and VIGOR datasets show that CROSS achieves state-of-the-art performance in cross-view localization. More importantly, CROSS effectively learns stable semantics, reliable structure, and transferable geometry across extremely different viewpoints.","authors":["Mao Chen","Xiangkai Zhang","Zhiyong Liu","Chuankai Liu","Xu Yang"],"published":"2026-07-14T07:00:34Z","updated":"2026-07-14T07:00:34Z","abstract_url":"https://arxiv.org/abs/2607.12429v1","html_url":"https://arxiv.org/html/2607.12429v1","pdf_url":"https://arxiv.org/pdf/2607.12429v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12419v1","title":"DeGuNet: Depth-Guided Ultra-Compact Backbones for Efficient LiDAR-Camera 3D Detection","abstract":"In autonomous driving perception, the fusion of LiDAR and camera modalities has become the dominant paradigm for 3D object detection. However, current multi-modal frameworks heavily rely on massive visual backbones pretrained on 2D semantic tasks. This reliance introduces substantial parameter redundancy and a structural misalignment, as 2D priors are ill-equipped to handle the extreme sparsity of LiDAR projections required for Bird's-Eye-View geometry. To address this, we present DeGuNet, an ultra-compact and plug-and-play image backbone explicitly designed for depth-guided representation learning. By incorporating sparsity-aware feature extraction mechanisms, DeGuNet effectively aligns multi-view images with unstructured LiDAR depth while strictly preventing invalid-region contamination. Extensive experiments on the nuScenes dataset demonstrate DeGuNet's broad plug-and-play applicability and superior efficiency. When integrated into established baselines, it fundamentally eliminates architectural redundancy, reducing GPU memory consumption by up to 66.5% and achieving a 1.16x inference speedup. Concurrently, DeGuNet delivers up to a 6.20 absolute mAP gain, establishing a new paradigm for parameter-efficient multi-modal 3D perception.","authors":["Haifa Zhang","Yijing Wang","Peixi Peng","Zhiqiang Zuo"],"published":"2026-07-14T06:46:30Z","updated":"2026-07-14T06:46:30Z","abstract_url":"https://arxiv.org/abs/2607.12419v1","html_url":"https://arxiv.org/html/2607.12419v1","pdf_url":"https://arxiv.org/pdf/2607.12419v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12418v1","title":"MQAdapter: Multi-Modal Quantum Adapter for Coarse-to-Fine VLM Fine-tuning","abstract":"Large-scale Vision-Language Models have demonstrated impressive transfer learning capabilities across a wide range of tasks. For few-shot classification, we observe that VLMs exhibit a notable ability to filter candidate categories and thus achieve high Top-K accuracy. However, they often struggle with fine-grained discrimination among visually similar categories, resulting in unsatisfactory Top-1 performance, as shown in Figure 1. Existing studies on VLM adapters generally focus on global alignment between visual and textual representations in the feature space, but fail to exploit semantically similar categories to refine fine-grained visual representations. Based on these observations, we propose a novel coarse-to-fine VLM fine-tuning approach for few-shot learning that leverages quantum computation, termed the Multi-Modal Quantum Adapter (MQAdapter). Specifically, MQAdapter first retrieves the Top-K category candidates most similar to the input image and uses them as semantic anchors. It then employs a cross-modal quantum learning mechanism to refine visual features under the guidance of these anchors. The core of this mechanism is the encoding of visual and textual features into quantum states. By leveraging quantum entanglement and superposition in a high-dimensional Hilbert space, MQAdapter effectively models higher-order cross-modal interactions, producing more discriminative representations than traditional Euclidean adapters. MQAdapter is parameter-efficient and can be integrated with various existing fine-tuning algorithms to achieve further performance gains. Evaluations on 15 datasets demonstrate the effectiveness of MQAdapter while requiring fewer trainable parameters.","authors":["Yumiao Zhao","Bo Jiang","Min Lu","Xiao Wang","Jin Tang"],"published":"2026-07-14T06:46:24Z","updated":"2026-07-14T06:46:24Z","abstract_url":"https://arxiv.org/abs/2607.12418v1","html_url":"https://arxiv.org/html/2607.12418v1","pdf_url":"https://arxiv.org/pdf/2607.12418v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12404v1","title":"Contrastive-Augmented Flow Matching for Style-Content Disentanglement","abstract":"Learning representations that separate content and style is crucial for controllable generation and compositional generalization. However, diffusion and flow-based models trained primarily with generative objectives often produce entangled or misaligned factors. To address this gap, we introduce Contrastive Augmented Flow Matching (CAtFM), a framework that integrates contrastive regularization into an invertible flow matching formulation to promote structured content-style representations. Rather than constraining intermediate latents or velocity fields, we apply contrastive supervision to predicted endpoints during training, enforcing semantic consistency across transported distributions while allowing disentanglement to emerge implicitly, without assuming strictly pure or fully factorized content and style representations. Our main experiments operate in the CLIP embedding space, with additional validation using frozen DINO and ALIGN encoders. Across synthetic data, in-domain styles, and real-world benchmarks (ImageNet, WikiArt, DomainNet, and DTD), CAtFM improves content and style retrieval, enhances embedding cluster separation, and achieves stronger open-set robustness compared to generative and discriminative baselines. Overall, CAtFM provides a simple way to couple discriminative constraints with deterministic transport, improving disentanglement and robustness under distribution shift.","authors":["Yusong Li","Pingchuan Ma","Ming Gui","Vincent Tao Hu","Björn Ommer"],"published":"2026-07-14T06:23:52Z","updated":"2026-07-14T06:23:52Z","abstract_url":"https://arxiv.org/abs/2607.12404v1","html_url":"https://arxiv.org/html/2607.12404v1","pdf_url":"https://arxiv.org/pdf/2607.12404v1.pdf","matched_keywords":["retrieval","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12379v1","title":"SeamGen: Artist-Aligned UV Seam Generation via Graph Flow Matching","abstract":"UV seam placement is a critical yet labor-intensive step in 3D content creation, requiring artists to balance chart shape, seam concealment, and alignment with semantic and geometric features. Existing automatic methods are primarily based on per-object optimization, relying on handcrafted objectives to avoid distortion or on proxies from pretrained models to inject semantic information. However, these strategies are not always well aligned with seams used in industrial production pipelines, often resulting in layouts that deviate from artist-preferred seam patterns and practical production requirements. To address these limitations, we propose SeamGen, a generative model for UV seam generation that aligns with artist preferences and production requirements. Instead of depending on manually designed objectives and constraints, SeamGen learns the distribution of per-edge seam labels from a large corpus of existing seam layouts using a flow-matching generative model. A key challenge is that typical Transformer architectures used in flow matching models are designed for sequential representations, such as point clouds, and cannot naturally account for mesh topology. To enable mesh-native learning, we design a Mesh Transformer backbone that interleaves local graph attention over mesh edges with global self-attention across vertices, capturing both fine-grained geometric cues and long-range topological coherence. To further improve inference-time controllability and quality, we exploit the training-free inpainting capability of flow models for both localized seam refinement and constraint-guided seam generation. Extensive experiments show that by learning priors from professional seam layout data, SeamGen produces UV layouts that better align with artist-authored preferences and achieve superior perceptual quality compared with distortion-based and semantic-proxy baselines.","authors":["Hao Xu","Yuqing Zhang","Yiqian Wu","Xueqi Ma","Ding Liang","Yan-Pei Cao","Ying-Tian Liu","Xiaogang Jin"],"published":"2026-07-14T05:52:52Z","updated":"2026-07-14T05:52:52Z","abstract_url":"https://arxiv.org/abs/2607.12379v1","html_url":"https://arxiv.org/html/2607.12379v1","pdf_url":"https://arxiv.org/pdf/2607.12379v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12376v1","title":"Demonstration of the common dual-channel feature decoupling characteristic of front-door mediation causal inference methods in whole-slice image classification","abstract":"Causal inference using front door intervention and multi-instance learning (MIL) has advanced the analysis of Whole Slide Images (WSI) in digital pathology. These methods adjust feature distributions of subtle evidence sub-images to correctly associate them with WSI-level diagnoses. We propose and prove 2 hypotheses for evaluating such methods: 1) Causal inference MIL introduces an independent classification channel that effectively completes WSI classification; 2) Greater difference between features extracted by the new and baseline channels increases effectiveness in eliminating false correlations. This hypothesis describes the core of causal inference MILs: overlaying parallel, independent channels to eliminate false associations between WSI-level diagnostic and non-diagnostic evidence sub-images by increasing deep feature diversity. Based on these hypotheses, we evaluated several causal inference MILs on breast cancer and non-small cell lung cancer datasets. This hypothesis provides a new theoretical perspective for applying causal inference to WSI analysis.","authors":["Zhirui Zhang","Tianhang Nan","Yong Ding","Zhuolun Song","Dayu Hu","Xiaoyu Cui"],"published":"2026-07-14T05:49:34Z","updated":"2026-07-14T05:49:34Z","abstract_url":"https://arxiv.org/abs/2607.12376v1","html_url":"https://arxiv.org/html/2607.12376v1","pdf_url":"https://arxiv.org/pdf/2607.12376v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12375v1","title":"IQA-T1: Tool-based Visual Evidence Reasoning for Image Quality Assessment","abstract":"Image Quality Assessment (IQA) in open-world environments remains challenging due to limited generalization and interpretability. Recent approaches based on multimodal large language models (MLLMs) introduce textual reasoning for quality prediction, yet their judgments rely heavily on semantically biased internal representations, making them insensitive to low-level perceptual degradations. We propose IQA-T1, a tool-based visual evidence reasoning framework that augments MLLM reasoning with explicit perceptual observations. During inference, the model autonomously invokes specialized analysis tools to generate structured visual evidence, such as noise residual maps, gradient statistics, and frequency spectra, which are progressively integrated into the reasoning process. To support this paradigm, we construct Q-Tool, a dataset containing 11k multimodal reasoning chains grounded in tool-generated evidence. Extensive experiments on seven IQA benchmarks show that IQA-T1 achieves the best overall performance across datasets while producing interpretable and evidence-grounded quality assessments. Code and dataset are available at https://github.com/zibuyu-02/IQA-T1.","authors":["Jinjian Wu","Jiaqi Tang","Wei Wei","Yingying Yan","Jianmin Chen","Botong Geng","Lei Zhang","Qifeng Chen"],"published":"2026-07-14T05:47:32Z","updated":"2026-07-14T05:47:32Z","abstract_url":"https://arxiv.org/abs/2607.12375v1","html_url":"https://arxiv.org/html/2607.12375v1","pdf_url":"https://arxiv.org/pdf/2607.12375v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12372v1","title":"UMSS: Towards Unsupervised Multi-modal Semantic Segmentation","abstract":"Multimodal semantic segmentation (MSS) is essential for robust perception in complex environments, yet its potential remains largely untapped because of the prohibitive cost of human annotations. While unsupervised semantic segmentation (USS) has achieved strong results on a single RGB modality, its naive extension to multimodal data is often hindered by fusion degradation. This occurs because, without explicit supervision, existing frameworks struggle to reconcile the heterogeneous structural patterns captured by different sensors and therefore fail to effectively exploit their complementary information. In this paper, we make the first attempt to address the novel problem of Unsupervised Multimodal Semantic Segmentation (UMSS), aiming to effectively exploit complementary sensor information in a fully label free setting. To this end, we propose UniM2 (Unified Multimodal), a novel framework built on DINOv3 that transforms conventional fusion methods into consistent performance gains. Our key idea is to learn a unified latent space driven by Cross Modal Correspondence Synergy (CMCS) to extract intrinsic shared semantic cues, bypassing the need for label guided adaptive fusion. To mitigate inherent intermodal conflicts, we introduce a Cross Modal Harmonizer (CMH) that designates RGB as a stable reference, effectively suppressing inconsistent relational supervision while guiding the model to exploit complementary structural features. Extensive experimental results on NYU Depth v2 and MFNet show that UniM2 improves mIoU by 6.4% and 9.8%, respectively, demonstrating clear advantages over existing frameworks for UMSS.","authors":["Haitian Zhang","Thai Duy Nguyen","Xiangyuan Wang","Mohan Liu","Lin Wang"],"published":"2026-07-14T05:44:29Z","updated":"2026-07-14T05:44:29Z","abstract_url":"https://arxiv.org/abs/2607.12372v1","html_url":"https://arxiv.org/html/2607.12372v1","pdf_url":"https://arxiv.org/pdf/2607.12372v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12364v1","title":"Lost in Visual Translation: A VLM-Assisted Perceptual-Semantic Coherence Framework for EEG-to-Image Reconstruction","abstract":"EEG-to-image evaluation should distinguish visual fidelity from recoverable meaning. Yet EEG-derived reconstructions are blurry, distorted, and low-detail, causing SSIM, LPIPS, and CLIP to penalize semantically recoverable outputs or reward plausible but incorrect ones. We analyze 6,855 ground-truth/reconstruction pairs from ATM, ENIGMA, BrainVis, and DreamDiffusion using semantic probes, caption harshness and blind-spot rates, and controlled degradations. Pixel metrics show near-zero correlation with semantic consistency, while representation metrics conflate perceptual and semantic errors. We therefore introduce a BCI-aware framework in which four VLMs assess image pairs through structured questions, producing Tolerant Perceptual Alignment Scores (T-PAS) and Tolerant Semantic Alignment Scores (T-SAS). Their consensus is distilled into the BCI-Coherence Score (BCS), a compact evaluator achieving a T-PAS MAE of 0.079 (r = 0.700) and a T-SAS MAE of 0.082 (r = 0.850) on our data. Human validation shows highly reliable joint coherence judgments, with Cohen's kappa = 0.882 +/- 0.174 and Krippendorff's alpha = 0.882, supporting perceptual-semantic recoverability over generic visual similarity. Code and resources are available at https://sukt03.github.io/BCS/.","authors":["Sukriti Tiwari","BHVSP Subrahmanyam","Nidhi Goyal","Sai Amrit Patnaik"],"published":"2026-07-14T05:40:23Z","updated":"2026-07-14T05:40:23Z","abstract_url":"https://arxiv.org/abs/2607.12364v1","html_url":"https://arxiv.org/html/2607.12364v1","pdf_url":"https://arxiv.org/pdf/2607.12364v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12362v1","title":"Implicit 4D Gaussian Splatting for Fast Motion with Large Inter-Frame Displacements","abstract":"Recent 4D Gaussian Splatting (4DGS) methods often fail under fast motion with large inter-frame displacements, where Gaussian attributes are poorly learned during training, and fast-moving objects are often lost from the reconstruction. In this work, we introduce Spatiotemporal Position Implicit Network for 4DGS, coined SPIN-4DGS, which learns Gaussian attributes from explicitly collected spatiotemporal positions rather than modeling temporal displacements, thereby enabling more faithful splatting under fast motions with large inter-frame displacements. To avoid the heavy memory overhead of explicitly optimizing attributes across all spatiotemporal positions, we instead predict them with a lightweight feed-forward network trained under a rasterization-based reconstruction loss. Consequently, SPIN-4DGS learns shared representations across Gaussians, effectively capturing spatiotemporal consistency and enabling stable high-quality Gaussian splatting even under challenging motions. Across extensive experiments, SPIN-4DGS consistently achieves higher fidelity under large displacements, with clear improvements in PSNR and SSIM on challenging sports scenes from the CMU Panoptic dataset. For example, SPIN-4DGS notably outperforms the strongest baseline, D3DGS, by achieving +1.83 higher PSNR on the Basketball scene.","authors":["Seung-gyeom Kim","Areum Kim","Yongjae Yoo","Sukmin Yun"],"published":"2026-07-14T05:33:05Z","updated":"2026-07-14T05:33:05Z","abstract_url":"https://arxiv.org/abs/2607.12362v1","html_url":"https://arxiv.org/html/2607.12362v1","pdf_url":"https://arxiv.org/pdf/2607.12362v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12358v1","title":"ACID: Adaptive Caching for vIDeo generation","abstract":"Video diffusion models produce high-quality generations but remain slow at inference due to their sequential denoising procedure. Caching-based acceleration methods address this by reusing intermediate model outputs: leading dynamic approaches such as TeaCache, EasyCache, and DiCache accumulate a drift signal and skip expensive model evaluations when accumulated drift stays below a fixed threshold τ. This threshold controls an apparent tradeoff - raising it yields faster generation at the cost of visual quality, while lowering it preserves quality but sacrifices speed. We show this tradeoff is not fundamental; it is an artifact of holding τ constant throughout denoising. We identify the existence of critical steps - timesteps where the drift signal changes rapidly - and show that applying a low threshold selectively at these steps while caching aggressively elsewhere recovers most of the quality of conservative caching at substantially higher inference speeds. Building on this insight, we propose ACID, a lightweight, training-free wrapper that monitors the rate of change of each method's existing drift signal to dynamically switch between a low and a high threshold. ACID is signal-agnostic and modular: it requires no retraining and plugs directly into existing dynamic caching methods without modifying their core mechanisms. Evaluated across three caching methods (TeaCache, EasyCache, DiCache) and three open-source video diffusion models (HunyuanVideo, Wan 2.1, CogVideoX), ACID consistently expands the Pareto frontier of visual quality versus inference speed beyond what any fixed threshold achieves. In particular, on TeaCache and HunyuanVideo, ACID achieves up to 2.16x speedup over the no-caching baseline, and up to 38% additional speedup over the conservative fixed-threshold baseline with negligible (<0.3 dB PSNR, <0.01 SSIM, <0.01 LPIPS) quality degradation.","authors":["Om Agrawal","Saurabh Agarwal","Aditya Akella"],"published":"2026-07-14T05:17:24Z","updated":"2026-07-14T05:17:24Z","abstract_url":"https://arxiv.org/abs/2607.12358v1","html_url":"https://arxiv.org/html/2607.12358v1","pdf_url":"https://arxiv.org/pdf/2607.12358v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12335v1","title":"ProtoPointNet: Prototype-Based Interpretable Classification of 3D Dental Point Clouds with Verifiable Spatial Activations","abstract":"Prototype-based networks provide inherently interpretable classification by linking predictions to learned exemplars, but their use in 3D point clouds and clinical surface-pair reasoning remains limited. We introduce ProtoPointNet, a prototype-based model for dental occlusion classification from registered upper--lower intraoral arch pairs. Each point is encoded by a 14-dimensional descriptor combining local surface geometry, curvature, and explicit inter-arch displacement and clearance, exposing occlusal relationships to prototype matching. A shared multi-task point-cloud backbone learns axis-specific prototype heads for sagittal-left, sagittal-right, vertical, transverse, and midline classification. To support limited clinical data, we train prototypes from scratch using auxiliary supervision and encoder-freeze hand-off. On Bits2Bites, ProtoPointNet achieves mean test macro-F1 of 0.724 and AUROC of 0.825, with strongest performance on vertical (F1 0.828) and sagittal-left classification (F1 0.807). Projected prototype activations localise to anatomically plausible regions, including posterior molars and premolars for cross-bite evidence and anterior incisors for bite-depth evidence. These results support prototype-based reasoning as a transparent, spatially grounded alternative to black-box 3D classifiers for dental surface-pair analysis.","authors":["George V. Jose","Thao Liang Chiam","Toby Hughes","Dilan Patel","Alan Brook","Lyle J. Palmer","Nikhil Cherian Kurian"],"published":"2026-07-14T04:30:09Z","updated":"2026-07-14T04:30:09Z","abstract_url":"https://arxiv.org/abs/2607.12335v1","html_url":"https://arxiv.org/html/2607.12335v1","pdf_url":"https://arxiv.org/pdf/2607.12335v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12319v1","title":"DM-KG: A Novel Method for Boosting Spatial Cognition of Vision-Language Models in Street View Imagery","abstract":"As vision-language models (VLMs) are increasingly deployed in geospatial question answering and visual scene understanding, improving their spatial cognition capability on street view imagery for complex logical reasoning has emerged as a key research priority. However, existing VLMs frequently suffer from \"spatial semantic hallucinations\" when perceiving object locations, distances, and directions in real-world street view scenes. Furthermore, such errors are often recalcitrant to tracing and calibration, posing a critical bottleneck for their practical deployment in geospatial tasks. To address this pressing challenge, this study proposes DM-KG (Direction-Metric Knowledge Graph), a structurally grounded spatial representation framework for street view imagery. By explicitly extracting directional and metric relationships between entities from a single 2D image, this framework enhances the spatial reasoning accuracy of VLMs through a structured knowledge graph. Specifically, we integrate panoptic segmentation with metric depth estimation to robustly compute entity-level 3D spatial coordinates. Subsequently, we encode the clock azimuths and Euclidean distances of entity pairs into a JSON-formatted knowledge graph, which is injected into the VLM as an explicit geometric prior to guide spatial reasoning. Experimental results on public spatial question-answering (QA) benchmarks demonstrate that DM-KG reduces the mean absolute error (MAE) in distance estimation by 31.1% and the mean angular error in direction judgment by 65.8%, while simultaneously maintaining a high QA success rate. By establishing a complete, augmented reasoning pipeline, this research significantly improves the spatial cognitive capabilities of VLMs in street view scenarios, thereby providing a flexible, generalized, and interpretable framework for geographic visual question answering (GeoVQA) in open environments.","authors":["Xinyue Xu","Zheng Zhang","Kunyang Ma","Ge Zhu","Lianshuai Cao","Lei Wang","Zixuan Li","Yi Cheng"],"published":"2026-07-14T03:52:37Z","updated":"2026-07-14T03:52:37Z","abstract_url":"https://arxiv.org/abs/2607.12319v1","html_url":"https://arxiv.org/html/2607.12319v1","pdf_url":"https://arxiv.org/pdf/2607.12319v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12304v1","title":"What Does a Temporal Benchmark Score Measure? Decomposing Channel Use in Video VLM Evaluation","abstract":"A score on a temporal video question answering benchmark is meant to measure that a model has temporal understanding, but it conflates two questions. 1. The task question: is the question even temporal, does it need several frames and their order? and 2. The channel question, when it does, does the model recover the order from the pixels, or read it off the positional encoding (RoPE)? Most of a temporal score answers neither, a single frame and answer priors often carry it. The field's validity checks, frame-shuffle sensitivity and the accuracy gained from the full video, speak only to the task question. We contribute a label-free screen for the channel question, the reversal-drop: the accuracy lost when the visual sequence is reversed while RoPE remains forward. It can be applied to compatible temporal benchmarks without new annotations. Paired reverse labels, or tasks whose labels transform deterministically under reversal, distinguish models that follow reversed content from those merely disrupted by the conflict. Molmo2 answers the forward event reading order off positions, while Qwen3-VL answers the reversed event it actually sees, reading visual order (comparatively). We call them position-dominant and visual-sequence-dominant. The split holds across two benchmarks and several temporal tasks at two scales, and activation patching shows it is a real internal property, not an artifact of the conflict. The distinction matters, the two channels fail on opposite inputs so two models with similar score are not interchangable, i.e. an aggregate score does not reflect potential failure modes.","authors":["Farrukh Rahman"],"published":"2026-07-14T03:26:33Z","updated":"2026-07-14T03:26:33Z","abstract_url":"https://arxiv.org/abs/2607.12304v1","html_url":"https://arxiv.org/html/2607.12304v1","pdf_url":"https://arxiv.org/pdf/2607.12304v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12297v1","title":"MobileSAM2: Lightweight Segment Anything for Spatial Intelligence","abstract":"The recent large video foundation model, SAM2, enables segment anything in both images and videos, serving as a powerful base model for various applications. However, many of such use cases require to operate on resource-constrained devices like mobile phones and laptops. In this work, we aim to make SAM2 more mobile-friendly by distilling the heavyweight SAM2 into a lightweight model, facilitating segment anything in both images and videos on mobile devices. To this end, we propose Hypergraphical Knowledge Distill (HyperKD), which introduces the idea of hypergraph into knowledge distillation, aiming to effectively model and transfer SAM2's generalizable and comprehensive knowledge. HyperKD consists of Temporal HyperKD and Granularity HyperKD that construct hypergraphs to explicitly model and extract the generalizable temporal knowledge and the comprehensive multi-granularity knowledge from SAM2 respectively, which are then distilled into the lightweight student model by aligning it with the constructed hypergraphs. Besides, we present MobileSAM2, a new family of lightweight SAM2 that balances efficiency and effectiveness via searching the best model architectures with HyperKD during model size reduction. Extensive experiments validate MobileSAM2 across multiple benchmarks and show promising generalization performance on embodied AI tasks.","authors":["Kai Jiang","Jiaxing Huang","Jingyi Zhang","Weiying Xie","Yunsong Li","Yufei Wang","Aoran Xiao","Dacheng Tao"],"published":"2026-07-14T03:10:11Z","updated":"2026-07-14T03:10:11Z","abstract_url":"https://arxiv.org/abs/2607.12297v1","html_url":"https://arxiv.org/html/2607.12297v1","pdf_url":"https://arxiv.org/pdf/2607.12297v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12293v1","title":"Adaptive Cross-Modal Fusion with Sparse Attention for Pedestrian Crossing Intention Prediction","abstract":"Predicting pedestrian crossing intention is a safety-critical task for autonomous driving, yet existing approaches often rely on single-modal inputs or dense multimodal fusion strategies that inadequately capture complementary visual and kinematic information while introducing redundant inter-modal interactions. We propose ADAPT (Adaptive Domain-Aware Pedestrian Crossing Transformer), a multimodal framework that jointly models local and global visual context together with temporal motion dynamics for accurate pedestrian crossing intention prediction. ADAPT processes four spatially aligned visual modalities, including RGB images, local depth maps, global semantic maps, and global depth maps, together with ego-vehicle speed, pedestrian bounding boxes, and skeleton pose information through five specialized modules: a weight-shared Swin Transformer V2 backbone for visual feature extraction, a Cross-Modality Guided Attention module for hierarchical visual fusion, a Mamba-based Motion Feature Encoding module for efficient temporal modeling, a Sparse Cross-Modal Attention module that selectively preserves the most informative inter-modal interactions, and a Vision Transformer-based Temporal Feature Fusion module for sequence-level prediction. Extensive experiments on the JAAD and PIE benchmark datasets demonstrate that ADAPT consistently outperforms existing state-of-the-art methods while maintaining low computational complexity. On JAAD, the proposed method achieves an AUC of 0.73 on JAADbeh and 0.85 on JAADall, while on PIE it achieves an accuracy of 0.92 and an AUC of 0.90. Furthermore, ADAPT performs inference in only 17.23 ms per sample, offering an effective balance between predictive accuracy and real-time deployment efficiency for intelligent transportation and autonomous driving applications.","authors":["Md Mahfuzur Rahman","Pengzhan Zhou","A F M Abdun Noor","Md Imam Ahasan","Kah Ong Michael Goh","S. M. Hasan Mahmud","Md Mustafizur Rahman","Kaixin Gao"],"published":"2026-07-14T03:05:09Z","updated":"2026-07-14T03:05:09Z","abstract_url":"https://arxiv.org/abs/2607.12293v1","html_url":"https://arxiv.org/html/2607.12293v1","pdf_url":"https://arxiv.org/pdf/2607.12293v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12278v1","title":"Auditing Data Leakage in Whole-Slide Image Multimodal Benchmarks","abstract":"Recent vision-language models (VLMs) for computational pathology report striking zero-shot performance on whole-slide image (WSI) visual question answering (VQA) benchmarks. We audit these claims and find them fundamentally compromised by data leakage at two hierarchical levels: patient-level leakage, where slides from the same case appear in both training and test folds, and institutional-level leakage, where different cases nonetheless share staining-batch and scanner signatures through a common Tissue Source Site (TSS). By tracing canonical slide, case, and TSS identifiers across major public resources, we document case level train test overlaps of 92.3~100% on TCGA-derived benchmarks, together with near-complete TSS overlap. We further demonstrate that both leakage levels are linearly decodable from foundation-model feature space, that they induce a measurable accuracy gap between leaked and audit-clean cases on a published checkpoint, and that across multiple published WSI VLMs, peak reported accuracies concentrate on the most heavily contaminated benchmarks. Therefore, the current WSI VQA evaluation cannot distinguish genuine multimodal reasoning from nearest-neighbor retrieval over memorized institutional and patient-specific artifacts. Finally, we outline concrete recommendations for contamination-free evaluation. By addressing benchmark construction, provenance disclosure, and automated overlap auditing, we aim to guide future research toward verifiable claims of progress.","authors":["Wenhao Zhang","Zhongliang Zhou","John Kang","Sheng Li"],"published":"2026-07-14T02:28:29Z","updated":"2026-07-14T02:28:29Z","abstract_url":"https://arxiv.org/abs/2607.12278v1","html_url":"https://arxiv.org/html/2607.12278v1","pdf_url":"https://arxiv.org/pdf/2607.12278v1.pdf","matched_keywords":["retrieval","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12254v1","title":"How to Realize Recursively Self-Improving Agents and Personal Singularity: A Goal-, Scope-, Tool-, and Benchmark-Driven Multi-Agent Architecture","abstract":"Large language model (LLM) agents can increasingly plan, use tools, maintain memory, and execute long-horizon tasks. These advances motivate two linked questions: how can an agent improve the mechanisms by which it learns and acts, and how can that improvement increase the durable capabilities of its user rather than only the software itself? This paper proposes a governed multi-agent architecture for recursively self-improving agents and introduces personal singularity as a bounded human-AI co-development objective: helping a user approach an expanding, user-defined capability frontier across selected domains. Each agent is defined by a goal contract, bounded scope, validated tool registry, tool-level tests, end-to-end benchmarks, an owner-controlled autonomy policy, a routing policy, memory, and an improvement policy. Out-of-scope tasks are transferred to another accountable agent or to a newly created niche agent. A user-facing Auto-Index selects interactive, hybrid, autonomous, or scheduled operation without overriding external permissions. The architecture combines a fast planner-executor-verifier loop, a slower evidence-gated improvement loop, an external governance plane, decentralized agent lineages, an owner-directed agent foundry, and a Personal Singularity OS coordinating working, computational-imaging, process-learning, and personal-learning agents. We formalize scope, routing, improvement acceptance, bounded goal evolution, tool-first execution, and human capability transfer, and provide safety invariants, benchmark design, and an implementation roadmap. This is a position and systems-design paper, not evidence that unrestricted recursive self-improvement or personal singularity has already been achieved.","authors":["Chengshuai Yang"],"published":"2026-07-14T01:44:53Z","updated":"2026-07-14T01:44:53Z","abstract_url":"https://arxiv.org/abs/2607.12254v1","html_url":"https://arxiv.org/html/2607.12254v1","pdf_url":"https://arxiv.org/pdf/2607.12254v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12231v1","title":"The GEST-Engine: From Event Graphs to Synthetic Video. A Full Technical Report","abstract":"We present the GEST-Engine, a complete system that goes from natural-language text to fully-annotated multi-actor video. At its core is an explicit world model: rather than encoding state as a learned latent, the engine maintains a complete, inspectable representation of the world (which actors exist, where they are, what they are doing, which objects they hold, and how events relate in time and space), expressed as a formal Graph of Events in Space and Time (GEST) and realized deterministically inside the open world of a commercial game engine driven through an open-source multiplayer scripting framework. GESTs are produced either procedurally or by an agentic text-to-GEST system in which an LLM Director plans a story through tool calls validated by a programmatic state backend, so every generated specification is executable by construction. A GEST then enters a four-stage execution pipeline: graph parsing and validation, entity and action grounding, temporal orchestration (Allen-style constraints resolved by Floyd-Warshall transitive closure), and execution and capture. In a single simulation pass the engine emits frame-aligned RGB video, dense per-pixel depth, instance segmentation, per-actor skeletal pose, per-frame pairwise spatial-relation graphs, 2D bounding boxes, event-to-frame temporal mappings, and natural-language descriptions, all at zero marginal annotation cost. We further describe an in-game world editor, runtime capability extraction, a text-generation pipeline, and a production system that renders corpora at scale across parallel virtual machines. Because every frame traces back to a semantic specification, the engine guarantees object permanence, multi-actor coordination, and temporal consistency by construction, making its output valuable as training data, evaluation benchmarks, and diagnostic tools for video understanding.","authors":["Nicolae Cudlenco","Mihai Masala","Marius Leordeanu"],"published":"2026-07-14T00:25:00Z","updated":"2026-07-14T00:25:00Z","abstract_url":"https://arxiv.org/abs/2607.12231v1","html_url":"https://arxiv.org/html/2607.12231v1","pdf_url":"https://arxiv.org/pdf/2607.12231v1.pdf","matched_keywords":["video","agent","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12206v1","title":"RegHead: Non-Humanoid Head Blendshapes via Feed-Forward Registration","abstract":"We present RegHead, a framework for constructing semantic blendshape sets for animatable non-humanoid head avatars. With a fixed expression vocabulary, semantic blendshapes provide a low-dimensional and interpretable animation interface and support cross-identity retargeting. Building such blendshape sets remains expensive because (i) expression-consistent supervision is scarce, (ii) generated 4D assets typically lack correspondence, and (iii) facial motion is highly localized. We propose (1) a large-scale dataset of non-humanoid identities paired with a shared expression vocabulary, obtained by expanding a small artist-rigged library via fine-tuned image editing; (2) a dense stochastic anchor motion representation tailored to localized facial deformations; and (3) a fast feed-forward registration model that converts unregistered expression meshes into a corresponded blendshape basis by predicting anchor-based deformations from the neutral shape. Experiments show that our approach produces higher-fidelity expression meshes than baselines, while running orders of magnitude faster than optimization. We further demonstrate real-time retargeting from human face tracking signals to non-humanoid characters, capturing both head pose and localized facial motions. Our project page is available at https://snap-research.github.io/RegHead/.","authors":["Jiahao Luo","Hao Zhang","Jianqi Chen","Yijie He","Jiaxu Zou","Michael Vasilkovsky","Sergei Korolev","Sergey Tulyakov","Chaoyang Wang","Peter Wonka","James Davis","Jian Wang"],"published":"2026-07-13T23:16:29Z","updated":"2026-07-13T23:16:29Z","abstract_url":"https://arxiv.org/abs/2607.12206v1","html_url":"https://arxiv.org/html/2607.12206v1","pdf_url":"https://arxiv.org/pdf/2607.12206v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12193v1","title":"Compos3D: Interactive Part-Based Composition for Creative Control in Generative 3D Models","abstract":"While generative AI has unlocked new opportunities for 3D content creation, current workflows often rely on multiple regenerations, which provides limited control and unpredictable outcomes. We present Compos3D, a system that introduces a compositional workflow for generative 3D modeling through remixing. Instead of repeatedly regenerating models, users generate multiple candidates from text or image prompts, select parts of interest via 2D image regions or 3D mesh segments, and assemble them into a coherent design. The system synthesizes these compositions into a refined 3D model, preserving high-level intent while resolving low-level geometry. To evaluate this approach, we conducted a controlled user study comparing remixing and regeneration workflows across both 2D and 3D modalities. Results show that the remixing workflow provides participants with greater creative control, stronger alignment with their intent, and higher satisfaction. We conclude with design recommendations for future AI-assisted 3D modeling workflows.","authors":["Faraz Faruqi","Sean J. Liu","George Fitzmaurice","Justin Matejka"],"published":"2026-07-13T22:24:26Z","updated":"2026-07-13T22:24:26Z","abstract_url":"https://arxiv.org/abs/2607.12193v1","html_url":"https://arxiv.org/html/2607.12193v1","pdf_url":"https://arxiv.org/pdf/2607.12193v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"},{"id":"2607.12186v1","title":"Overview of Cross-Component In-loop Filters in Video Coding Standards","abstract":"In-loop filters have been comprehensively explored during the development of video coding standards due to their remarkable noise-reduction capability. In the early stage of video coding, in-loop filters, such as Deblocking Filter, Sample Adaptive Offset, and Adaptive Loop Filter, were performed separately for each component. Recently, cross-component filters were studied to improve the chroma fidelity by exploiting correlations between the luma and chroma channels. This paper summarizes the cross-component filters used in the state-of-the-art video coding standard. Specifically, it includes the Cross-Component Adaptive Loop Filter and Cross-Component Sample Adaptive Offset. Cross-component filters aim to reduce compression artifacts based on the correlation between different components and provide more accurate pixel reconstruction values. In this paper, we introduce the origin, development, and status of cross-component filters in the current video coding standards. Finally, we had some discussions on the further evolutions of cross-component filters.","authors":["Zhaoyu Li","Xuewei Meng","Jiaqi Zhang","Cheng Huang","Chuanmin Jia","Siwei Ma","Yun Jiang"],"published":"2026-07-13T22:07:16Z","updated":"2026-07-13T22:07:16Z","abstract_url":"https://arxiv.org/abs/2607.12186v1","html_url":"https://arxiv.org/html/2607.12186v1","pdf_url":"https://arxiv.org/pdf/2607.12186v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-15T03:54:56+00:00","last_seen_at":"2026-07-15T03:54:56+00:00"}],"tracked_paper_count":63,"storage_mode":"latest_overwrite"}};
